"""
Parameterized generator for GH329_testify_1792.

Source PR:    https://github.com/stretchr/testify/pull/1792
Source Issue: N/A

Seed varies: renames 'actual' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH329_testify_1792'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH329_testify_1792'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('actual', 'actual' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH329_testify_1792',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'stretchr/testify',
                "pr_number": 1792,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/stretchr/testify/pull/1792",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'assert/assertions.go': 'package assert\n\nimport (\n\t"bufio"\n\t"bytes"\n\t"encoding/json"\n\t"errors"\n\t"fmt"\n\t"math"\n\t"os"\n\t"reflect"\n\t"regexp"\n\t"runtime"\n\t"runtime/debug"\n\t"strings"\n\t"time"\n\t"unicode"\n\t"unicode/utf8"\n\n\t"github.com/davecgh/go-spew/spew"\n\t"github.com/stretchr/testify/internal/difflib"\n\n\t// Wrapper around gopkg.in/yaml.v3\n\t"github.com/stretchr/testify/assert/yaml"\n)\n\n//go:generate sh -c "cd ../_codegen && go build && cd - && ../_codegen/_codegen -output-package=assert -template=assertion_format.go.tmpl"\n\n// TestingT is an interface wrapper around *testing.T\ntype TestingT interface {\n\tErrorf(format string, args ...interface{})\n}\n\n// ComparisonAssertionFunc is a common function prototype when comparing two values.  Can be useful\n// for table driven tests.\ntype ComparisonAssertionFunc func(TestingT, interface{}, interface{}, ...interface{}) bool\n\n// ValueAssertionFunc is a common function prototype when validating a single value.  Can be useful\n// for table driven tests.\ntype ValueAssertionFunc func(TestingT, interface{}, ...interface{}) bool\n\n// BoolAssertionFunc is a common function prototype when validating a bool value.  Can be useful\n// for table driven tests.\ntype BoolAssertionFunc func(TestingT, bool, ...interface{}) bool\n\n// ErrorAssertionFunc is a common function prototype when validating an error value.  Can be useful\n// for table driven tests.\ntype ErrorAssertionFunc func(TestingT, error, ...interface{}) bool\n\n// PanicAssertionFunc is a common function prototype when validating a panic value.  Can be useful\n// for table driven tests.\ntype PanicAssertionFunc = func(t TestingT, f PanicTestFunc, msgAndArgs ...interface{}) bool\n\n// Comparison is a custom function that returns true on success and false on failure\ntype Comparison func() (success bool)\n\n/*\n\tHelper functions\n*/\n\n// ObjectsAreEqual determines if two objects are considered equal.\n//\n// This function does no assertion of any kind.\nfunc ObjectsAreEqual(expected, actual interface{}) bool {\n\tif expected == nil || actual == nil {\n\t\treturn expected == actual\n\t}\n\n\texp, ok := expected.([]byte)\n\tif !ok {\n\t\treturn reflect.DeepEqual(expected, actual)\n\t}\n\n\tact, ok := actual.([]byte)\n\tif !ok {\n\t\treturn false\n\t}\n\tif exp == nil || act == nil {\n\t\treturn exp == nil && act == nil\n\t}\n\treturn bytes.Equal(exp, act)\n}\n\n// copyExportedFields iterates downward through nested data structures and creates a copy\n// that only contains the exported struct fields.\nfunc copyExportedFields(expected interface{}) interface{} {\n\tif isNil(expected) {\n\t\treturn expected\n\t}\n\n\texpectedType := reflect.TypeOf(expected)\n\texpectedKind := expectedType.Kind()\n\texpectedValue := reflect.ValueOf(expected)\n\n\tswitch expectedKind {\n\tcase reflect.Struct:\n\t\tresult := reflect.New(expectedType).Elem()\n\t\tfor i := 0; i < expectedType.NumField(); i++ {\n\t\t\tfield := expectedType.Field(i)\n\t\t\tisExported := field.IsExported()\n\t\t\tif isExported {\n\t\t\t\tfieldValue := expectedValue.Field(i)\n\t\t\t\tif isNil(fieldValue) || isNil(fieldValue.Interface()) {\n\t\t\t\t\tcontinue\n\t\t\t\t}\n\t\t\t\tnewValue := copyExportedFields(fieldValue.Interface())\n\t\t\t\tresult.Field(i).Set(reflect.ValueOf(newValue))\n\t\t\t}\n\t\t}\n\t\treturn result.Interface()\n\n\tcase reflect.Ptr:\n\t\tresult := reflect.New(expectedType.Elem())\n\t\tunexportedRemoved := copyExportedFields(expectedValue.Elem().Interface())\n\t\tresult.Elem().Set(reflect.ValueOf(unexportedRemoved))\n\t\treturn result.Interface()\n\n\tcase reflect.Array, reflect.Slice:\n\t\tvar result reflect.Value\n\t\tif expectedKind == reflect.Array {\n\t\t\tresult = reflect.New(reflect.ArrayOf(expectedValue.Len(), expectedType.Elem())).Elem()\n\t\t} else {\n\t\t\tresult = reflect.MakeSlice(expectedType, expectedValue.Len(), expectedValue.Len())\n\t\t}\n\t\tfor i := 0; i < expectedValue.Len(); i++ {\n\t\t\tindex := expectedValue.Index(i)\n\t\t\tif isNil(index) {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tunexportedRemoved := copyExportedFields(index.Interface())\n\t\t\tresult.Index(i).Set(reflect.ValueOf(unexportedRemoved))\n\t\t}\n\t\treturn result.Interface()\n\n\tcase reflect.Map:\n\t\tresult := reflect.MakeMap(expectedType)\n\t\tfor _, k := range expectedValue.MapKeys() {\n\t\t\tindex := expectedValue.MapIndex(k)\n\t\t\tunexportedRemoved := copyExportedFields(index.Interface())\n\t\t\tresult.SetMapIndex(k, reflect.ValueOf(unexportedRemoved))\n\t\t}\n\t\treturn result.Interface()\n\n\tdefault:\n\t\treturn expected\n\t}\n}\n\n// ObjectsExportedFieldsAreEqual determines if the exported (public) fields of two objects are\n// considered equal. This comparison of only exported fields is applied recursively to nested data\n// structures.\n//\n// This function does no assertion of any kind.\n//\n// Deprecated: Use [EqualExportedValues] instead.\nfunc ObjectsExportedFieldsAreEqual(expected, actual interface{}) bool {\n\texpectedCleaned := copyExportedFields(expected)\n\tactualCleaned := copyExportedFields(actual)\n\treturn ObjectsAreEqualValues(expectedCleaned, actualCleaned)\n}\n\n// ObjectsAreEqualValues gets whether two objects are equal, or if their\n// values are equal.\nfunc ObjectsAreEqualValues(expected, actual interface{}) bool {\n\tif ObjectsAreEqual(expected, actual) {\n\t\treturn true\n\t}\n\n\texpectedValue := reflect.ValueOf(expected)\n\tactualValue := reflect.ValueOf(actual)\n\tif !expectedValue.IsValid() || !actualValue.IsValid() {\n\t\treturn false\n\t}\n\n\texpectedType := expectedValue.Type()\n\tactualType := actualValue.Type()\n\tif !expectedType.ConvertibleTo(actualType) {\n\t\treturn false\n\t}\n\n\tif !isNumericType(expectedType) || !isNumericType(actualType) {\n\t\t// Attempt comparison after type conversion\n\t\treturn reflect.DeepEqual(\n\t\t\texpectedValue.Convert(actualType).Interface(), actual,\n\t\t)\n\t}\n\n\t// If BOTH values are numeric, there are chances of false positives due\n\t// to overflow or underflow. So, we need to make sure to always convert\n\t// the smaller type to a larger type before comparing.\n\tif expectedType.Size() >= actualType.Size() {\n\t\treturn actualValue.Convert(expectedType).Interface() == expected\n\t}\n\n\treturn expectedValue.Convert(actualType).Interface() == actual\n}\n\n// isNumericType returns true if the type is one of:\n// int, int8, int16, int32, int64, uint, uint8, uint16, uint32, uint64,\n// float32, float64, complex64, complex128\nfunc isNumericType(t reflect.Type) bool {\n\treturn t.Kind() >= reflect.Int && t.Kind() <= reflect.Complex128\n}\n\n/* CallerInfo is necessary because the assert functions use the testing object\ninternally, causing it to print the file:line of the assert method, rather than where\nthe problem actually occurred in calling code.*/\n\n// CallerInfo returns an array of strings containing the file and line number\n// of each stack frame leading from the current test to the assert call that\n// failed.\nfunc CallerInfo() []string {\n\tvar pc uintptr\n\tvar file string\n\tvar line int\n\tvar name string\n\n\tconst stackFrameBufferSize = 10\n\tpcs := make([]uintptr, stackFrameBufferSize)\n\n\tcallers := []string{}\n\toffset := 1\n\n\tfor {\n\t\tn := runtime.Callers(offset, pcs)\n\n\t\tif n == 0 {\n\t\t\tbreak\n\t\t}\n\n\t\tframes := runtime.CallersFrames(pcs[:n])\n\n\t\tfor {\n\t\t\tframe, more := frames.Next()\n\t\t\tpc = frame.PC\n\t\t\tfile = frame.File\n\t\t\tline = frame.Line\n\n\t\t\t// This is a huge edge case, but it will panic if this is the case, see #180\n\t\t\tif file == "<autogenerated>" {\n\t\t\t\tbreak\n\t\t\t}\n\n\t\t\tf := runtime.FuncForPC(pc)\n\t\t\tif f == nil {\n\t\t\t\tbreak\n\t\t\t}\n\t\t\tname = f.Name()\n\n\t\t\t// testing.tRunner is the standard library function that calls\n\t\t\t// tests. Subtests are called directly by tRunner, without going through\n\t\t\t// the Test/Benchmark/Example function that contains the t.Run calls, so\n\t\t\t// with subtests we should break when we hit tRunner, without adding it\n\t\t\t// to the list of callers.\n\t\t\tif name == "testing.tRunner" {\n\t\t\t\tbreak\n\t\t\t}\n\n\t\t\tparts := strings.Split(file, "/")\n\t\t\tif len(parts) > 1 {\n\t\t\t\tfilename := parts[len(parts)-1]\n\t\t\t\tdir := parts[len(parts)-2]\n\t\t\t\tif (dir != "assert" && dir != "mock" && dir != "require") || filename == "mock_test.go" {\n\t\t\t\t\tcallers = append(callers, fmt.Sprintf("%s:%d", file, line))\n\t\t\t\t}\n\t\t\t}\n\n\t\t\t// Drop the package\n\t\t\tdotPos := strings.LastIndexByte(name, \'.\')\n\t\t\tname = name[dotPos+1:]\n\t\t\tif isTest(name, "Test") ||\n\t\t\t\tisTest(name, "Benchmark") ||\n\t\t\t\tisTest(name, "Example") {\n\t\t\t\tbreak\n\t\t\t}\n\n\t\t\tif !more {\n\t\t\t\tbreak\n\t\t\t}\n\t\t}\n\n\t\t// Next batch\n\t\toffset += cap(pcs)\n\t}\n\n\treturn callers\n}\n\n// Stolen from the `go test` tool.\n// isTest tells whether name looks like a test (or benchmark, according to prefix).\n// It is a Test (say) if there is a character after Test that is not a lower-case letter.\n// We don\'t want TesticularCancer.\nfunc isTest(name, prefix string) bool {\n\tif !strings.HasPrefix(name, prefix) {\n\t\treturn false\n\t}\n\tif len(name) == len(prefix) { // "Test" is ok\n\t\treturn true\n\t}\n\tr, _ := utf8.DecodeRuneInString(name[len(prefix):])\n\treturn !unicode.IsLower(r)\n}\n\nfunc messageFromMsgAndArgs(msgAndArgs ...interface{}) string {\n\tif len(msgAndArgs) == 0 || msgAndArgs == nil {\n\t\treturn ""\n\t}\n\tif len(msgAndArgs) == 1 {\n\t\tmsg := msgAndArgs[0]\n\t\tif msgAsStr, ok := msg.(string); ok {\n\t\t\treturn msgAsStr\n\t\t}\n\t\treturn fmt.Sprintf("%+v", msg)\n\t}\n\tif len(msgAndArgs) > 1 {\n\t\treturn fmt.Sprintf(msgAndArgs[0].(string), msgAndArgs[1:]...)\n\t}\n\treturn ""\n}\n\n// Aligns the provided message so that all lines after the first line start at the same location as the first line.\n// Assumes that the first line starts at the correct location (after carriage return, tab, label, spacer and tab).\n// The longestLabelLen parameter specifies the length of the longest label in the output (required because this is the\n// basis on which the alignment occurs).\nfunc indentMessageLines(message string, longestLabelLen int) string {\n\toutBuf := new(bytes.Buffer)\n\n\tfor i, scanner := 0, bufio.NewScanner(strings.NewReader(message)); scanner.Scan(); i++ {\n\t\t// no need to align first line because it starts at the correct location (after the label)\n\t\tif i != 0 {\n\t\t\t// append alignLen+1 spaces to align with "{{longestLabel}}:" before adding tab\n\t\t\toutBuf.WriteString("\\n\\t" + strings.Repeat(" ", longestLabelLen+1) + "\\t")\n\t\t}\n\t\toutBuf.WriteString(scanner.Text())\n\t}\n\n\treturn outBuf.String()\n}\n\ntype failNower interface {\n\tFailNow()\n}\n\n// FailNow fails test\nfunc FailNow(t TestingT, failureMessage string, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tFail(t, failureMessage, msgAndArgs...)\n\n\t// We cannot extend TestingT with FailNow() and\n\t// maintain backwards compatibility, so we fallback\n\t// to panicking when FailNow is not available in\n\t// TestingT.\n\t// See issue #263\n\n\tif t, ok := t.(failNower); ok {\n\t\tt.FailNow()\n\t} else {\n\t\tpanic("test failed and t is missing `FailNow()`")\n\t}\n\treturn false\n}\n\n// Fail reports a failure through\nfunc Fail(t TestingT, failureMessage string, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tcontent := []labeledContent{\n\t\t{"Error Trace", strings.Join(CallerInfo(), "\\n\\t\\t\\t")},\n\t\t{"Error", failureMessage},\n\t}\n\n\t// Add test name if the Go version supports it\n\tif n, ok := t.(interface {\n\t\tName() string\n\t}); ok {\n\t\tcontent = append(content, labeledContent{"Test", n.Name()})\n\t}\n\n\tmessage := messageFromMsgAndArgs(msgAndArgs...)\n\tif len(message) > 0 {\n\t\tcontent = append(content, labeledContent{"Messages", message})\n\t}\n\n\tt.Errorf("\\n%s", ""+labeledOutput(content...))\n\n\treturn false\n}\n\ntype labeledContent struct {\n\tlabel   string\n\tcontent string\n}\n\n// labeledOutput returns a string consisting of the provided labeledContent. Each labeled output is appended in the following manner:\n//\n//\t\\t{{label}}:{{align_spaces}}\\t{{content}}\\n\n//\n// The initial carriage return is required to undo/erase any padding added by testing.T.Errorf. The "\\t{{label}}:" is for the label.\n// If a label is shorter than the longest label provided, padding spaces are added to make all the labels match in length. Once this\n// alignment is achieved, "\\t{{content}}\\n" is added for the output.\n//\n// If the content of the labeledOutput contains line breaks, the subsequent lines are aligned so that they start at the same location as the first line.\nfunc labeledOutput(content ...labeledContent) string {\n\tlongestLabel := 0\n\tfor _, v := range content {\n\t\tif len(v.label) > longestLabel {\n\t\t\tlongestLabel = len(v.label)\n\t\t}\n\t}\n\tvar output string\n\tfor _, v := range content {\n\t\toutput += "\\t" + v.label + ":" + strings.Repeat(" ", longestLabel-len(v.label)) + "\\t" + indentMessageLines(v.content, longestLabel) + "\\n"\n\t}\n\treturn output\n}\n\n// Implements asserts that an object is implemented by the specified interface.\n//\n//\tassert.Implements(t, (*MyInterface)(nil), new(MyObject))\nfunc Implements(t TestingT, interfaceObject interface{}, object interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tinterfaceType := reflect.TypeOf(interfaceObject).Elem()\n\n\tif object == nil {\n\t\treturn Fail(t, fmt.Sprintf("Cannot check if nil implements %v", interfaceType), msgAndArgs...)\n\t}\n\tif !reflect.TypeOf(object).Implements(interfaceType) {\n\t\treturn Fail(t, fmt.Sprintf("%T must implement %v", object, interfaceType), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// NotImplements asserts that an object does not implement the specified interface.\n//\n//\tassert.NotImplements(t, (*MyInterface)(nil), new(MyObject))\nfunc NotImplements(t TestingT, interfaceObject interface{}, object interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tinterfaceType := reflect.TypeOf(interfaceObject).Elem()\n\n\tif object == nil {\n\t\treturn Fail(t, fmt.Sprintf("Cannot check if nil does not implement %v", interfaceType), msgAndArgs...)\n\t}\n\tif reflect.TypeOf(object).Implements(interfaceType) {\n\t\treturn Fail(t, fmt.Sprintf("%T implements %v", object, interfaceType), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\nfunc isType(expectedType, object interface{}) bool {\n\treturn ObjectsAreEqual(reflect.TypeOf(object), reflect.TypeOf(expectedType))\n}\n\n// IsType asserts that the specified objects are of the same type.\n//\n//\tassert.IsType(t, &MyStruct{}, &MyStruct{})\nfunc IsType(t TestingT, expectedType, object interface{}, msgAndArgs ...interface{}) bool {\n\tif isType(expectedType, object) {\n\t\treturn true\n\t}\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\treturn Fail(t, fmt.Sprintf("Object expected to be of type %T, but was %T", expectedType, object), msgAndArgs...)\n}\n\n// IsNotType asserts that the specified objects are not of the same type.\n//\n//\tassert.IsNotType(t, &NotMyStruct{}, &MyStruct{})\nfunc IsNotType(t TestingT, theType, object interface{}, msgAndArgs ...interface{}) bool {\n\tif !isType(theType, object) {\n\t\treturn true\n\t}\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\treturn Fail(t, fmt.Sprintf("Object type expected to be different than %T", theType), msgAndArgs...)\n}\n\n// Equal asserts that two objects are equal.\n//\n//\tassert.Equal(t, 123, 123)\n//\n// Pointer variable equality is determined based on the equality of the\n// referenced values (as opposed to the memory addresses). Function equality\n// cannot be determined and will always fail.\nfunc Equal(t TestingT, expected, actual interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif err := validateEqualArgs(expected, actual); err != nil {\n\t\treturn Fail(t, fmt.Sprintf("Invalid operation: %#v == %#v (%s)",\n\t\t\texpected, actual, err), msgAndArgs...)\n\t}\n\n\tif !ObjectsAreEqual(expected, actual) {\n\t\tdiff := diff(expected, actual)\n\t\texpected, actual = formatUnequalValues(expected, actual)\n\t\treturn Fail(t, fmt.Sprintf("Not equal: \\n"+\n\t\t\t"expected: %s\\n"+\n\t\t\t"actual  : %s%s", expected, actual, diff), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// validateEqualArgs checks whether provided arguments can be safely used in the\n// Equal/NotEqual functions.\nfunc validateEqualArgs(expected, actual interface{}) error {\n\tif expected == nil && actual == nil {\n\t\treturn nil\n\t}\n\n\tif isFunction(expected) || isFunction(actual) {\n\t\treturn errors.New("cannot take func type as argument")\n\t}\n\treturn nil\n}\n\n// Same asserts that two pointers reference the same object.\n//\n//\tassert.Same(t, ptr1, ptr2)\n//\n// Both arguments must be pointer variables. Pointer variable sameness is\n// determined based on the equality of both type and value.\nfunc Same(t TestingT, expected, actual interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tsame, ok := samePointers(expected, actual)\n\tif !ok {\n\t\treturn Fail(t, "Both arguments must be pointers", msgAndArgs...)\n\t}\n\n\tif !same {\n\t\t// both are pointers but not the same type & pointing to the same address\n\t\treturn Fail(t, fmt.Sprintf("Not same: \\n"+\n\t\t\t"expected: %p %#[1]v\\n"+\n\t\t\t"actual  : %p %#[2]v",\n\t\t\texpected, actual), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// NotSame asserts that two pointers do not reference the same object.\n//\n//\tassert.NotSame(t, ptr1, ptr2)\n//\n// Both arguments must be pointer variables. Pointer variable sameness is\n// determined based on the equality of both type and value.\nfunc NotSame(t TestingT, expected, actual interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tsame, ok := samePointers(expected, actual)\n\tif !ok {\n\t\t// fails when the arguments are not pointers\n\t\treturn !(Fail(t, "Both arguments must be pointers", msgAndArgs...))\n\t}\n\n\tif same {\n\t\treturn Fail(t, fmt.Sprintf(\n\t\t\t"Expected and actual point to the same object: %p %#[1]v",\n\t\t\texpected), msgAndArgs...)\n\t}\n\treturn true\n}\n\n// samePointers checks if two generic interface objects are pointers of the same\n// type pointing to the same object. It returns two values: same indicating if\n// they are the same type and point to the same object, and ok indicating that\n// both inputs are pointers.\nfunc samePointers(first, second interface{}) (same bool, ok bool) {\n\tfirstPtr, secondPtr := reflect.ValueOf(first), reflect.ValueOf(second)\n\tif firstPtr.Kind() != reflect.Ptr || secondPtr.Kind() != reflect.Ptr {\n\t\treturn false, false // not both are pointers\n\t}\n\n\tfirstType, secondType := reflect.TypeOf(first), reflect.TypeOf(second)\n\tif firstType != secondType {\n\t\treturn false, true // both are pointers, but of different types\n\t}\n\n\t// compare pointer addresses\n\treturn first == second, true\n}\n\n// formatUnequalValues takes two values of arbitrary types and returns string\n// representations appropriate to be presented to the user.\n//\n// If the values are not of like type, the returned strings will be prefixed\n// with the type name, and the value will be enclosed in parentheses similar\n// to a type conversion in the Go grammar.\nfunc formatUnequalValues(expected, actual interface{}) (e string, a string) {\n\tif reflect.TypeOf(expected) != reflect.TypeOf(actual) {\n\t\treturn fmt.Sprintf("%T(%s)", expected, truncatingFormat(expected)),\n\t\t\tfmt.Sprintf("%T(%s)", actual, truncatingFormat(actual))\n\t}\n\tswitch expected.(type) {\n\tcase time.Duration:\n\t\treturn fmt.Sprintf("%v", expected), fmt.Sprintf("%v", actual)\n\t}\n\treturn truncatingFormat(expected), truncatingFormat(actual)\n}\n\n// truncatingFormat formats the data and truncates it if it\'s too long.\n//\n// This helps keep formatted error messages lines from exceeding the\n// bufio.MaxScanTokenSize max line length that the go testing framework imposes.\nfunc truncatingFormat(data interface{}) string {\n\tvalue := fmt.Sprintf("%#v", data)\n\tmax := bufio.MaxScanTokenSize - 100 // Give us some space the type info too if needed.\n\tif len(value) > max {\n\t\tvalue = value[0:max] + "<... truncated>"\n\t}\n\treturn value\n}\n\n// EqualValues asserts that two objects are equal or convertible to the larger\n// type and equal.\n//\n//\tassert.EqualValues(t, uint32(123), int32(123))\nfunc EqualValues(t TestingT, expected, actual interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tif !ObjectsAreEqualValues(expected, actual) {\n\t\tdiff := diff(expected, actual)\n\t\texpected, actual = formatUnequalValues(expected, actual)\n\t\treturn Fail(t, fmt.Sprintf("Not equal: \\n"+\n\t\t\t"expected: %s\\n"+\n\t\t\t"actual  : %s%s", expected, actual, diff), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// EqualExportedValues asserts that the types of two objects are equal and their public\n// fields are also equal. This is useful for comparing structs that have private fields\n// that could potentially differ.\n//\n//\t type S struct {\n//\t\tExported     \tint\n//\t\tnotExported   \tint\n//\t }\n//\t assert.EqualExportedValues(t, S{1, 2}, S{1, 3}) => true\n//\t assert.EqualExportedValues(t, S{1, 2}, S{2, 3}) => false\nfunc EqualExportedValues(t TestingT, expected, actual interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\taType := reflect.TypeOf(expected)\n\tbType := reflect.TypeOf(actual)\n\n\tif aType != bType {\n\t\treturn Fail(t, fmt.Sprintf("Types expected to match exactly\\n\\t%v != %v", aType, bType), msgAndArgs...)\n\t}\n\n\texpected = copyExportedFields(expected)\n\tactual = copyExportedFields(actual)\n\n\tif !ObjectsAreEqualValues(expected, actual) {\n\t\tdiff := diff(expected, actual)\n\t\texpected, actual = formatUnequalValues(expected, actual)\n\t\treturn Fail(t, fmt.Sprintf("Not equal (comparing only exported fields): \\n"+\n\t\t\t"expected: %s\\n"+\n\t\t\t"actual  : %s%s", expected, actual, diff), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// Exactly asserts that two objects are equal in value and type.\n//\n//\tassert.Exactly(t, int32(123), int64(123))\nfunc Exactly(t TestingT, expected, actual interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\taType := reflect.TypeOf(expected)\n\tbType := reflect.TypeOf(actual)\n\n\tif aType != bType {\n\t\treturn Fail(t, fmt.Sprintf("Types expected to match exactly\\n\\t%v != %v", aType, bType), msgAndArgs...)\n\t}\n\n\treturn Equal(t, expected, actual, msgAndArgs...)\n}\n\n// NotNil asserts that the specified object is not nil.\n//\n//\tassert.NotNil(t, err)\nfunc NotNil(t TestingT, object interface{}, msgAndArgs ...interface{}) bool {\n\tif !isNil(object) {\n\t\treturn true\n\t}\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\treturn Fail(t, "Expected value not to be nil.", msgAndArgs...)\n}\n\n// isNil checks if a specified object is nil or not, without Failing.\nfunc isNil(object interface{}) bool {\n\tif object == nil {\n\t\treturn true\n\t}\n\n\tvalue := reflect.ValueOf(object)\n\tswitch value.Kind() {\n\tcase\n\t\treflect.Chan, reflect.Func,\n\t\treflect.Interface, reflect.Map,\n\t\treflect.Ptr, reflect.Slice, reflect.UnsafePointer:\n\n\t\treturn value.IsNil()\n\t}\n\n\treturn false\n}\n\n// Nil asserts that the specified object is nil.\n//\n//\tassert.Nil(t, err)\nfunc Nil(t TestingT, object interface{}, msgAndArgs ...interface{}) bool {\n\tif isNil(object) {\n\t\treturn true\n\t}\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\treturn Fail(t, fmt.Sprintf("Expected nil, but got: %#v", object), msgAndArgs...)\n}\n\n// isEmpty gets whether the specified object is considered empty or not.\nfunc isEmpty(object interface{}) bool {\n\t// get nil case out of the way\n\tif object == nil {\n\t\treturn true\n\t}\n\n\treturn isEmptyValue(reflect.ValueOf(object))\n}\n\n// isEmptyValue gets whether the specified reflect.Value is considered empty or not.\nfunc isEmptyValue(objValue reflect.Value) bool {\n\tif objValue.IsZero() {\n\t\treturn true\n\t}\n\t// Special cases of non-zero values that we consider empty\n\tswitch objValue.Kind() {\n\t// collection types are empty when they have no element\n\t// Note: array types are empty when they match their zero-initialized state.\n\tcase reflect.Chan, reflect.Map, reflect.Slice:\n\t\treturn objValue.Len() == 0\n\t// non-nil pointers are empty if the value they point to is empty\n\tcase reflect.Ptr:\n\t\treturn isEmptyValue(objValue.Elem())\n\t}\n\treturn false\n}\n\n// Empty asserts that the given value is "empty".\n//\n// [Zero values] are "empty".\n//\n// Arrays are "empty" if every element is the zero value of the type (stricter than "empty").\n//\n// Slices, maps and channels with zero length are "empty".\n//\n// Pointer values are "empty" if the pointer is nil or if the pointed value is "empty".\n//\n//\tassert.Empty(t, obj)\n//\n// [Zero values]: https://go.dev/ref/spec#The_zero_value\nfunc Empty(t TestingT, object interface{}, msgAndArgs ...interface{}) bool {\n\tpass := isEmpty(object)\n\tif !pass {\n\t\tif h, ok := t.(tHelper); ok {\n\t\t\th.Helper()\n\t\t}\n\t\tFail(t, fmt.Sprintf("Should be empty, but was %v", object), msgAndArgs...)\n\t}\n\n\treturn pass\n}\n\n// NotEmpty asserts that the specified object is NOT [Empty].\n//\n//\tif assert.NotEmpty(t, obj) {\n//\t  assert.Equal(t, "two", obj[1])\n//\t}\nfunc NotEmpty(t TestingT, object interface{}, msgAndArgs ...interface{}) bool {\n\tpass := !isEmpty(object)\n\tif !pass {\n\t\tif h, ok := t.(tHelper); ok {\n\t\t\th.Helper()\n\t\t}\n\t\tFail(t, fmt.Sprintf("Should NOT be empty, but was %v", object), msgAndArgs...)\n\t}\n\n\treturn pass\n}\n\n// getLen tries to get the length of an object.\n// It returns (0, false) if impossible.\nfunc getLen(x interface{}) (length int, ok bool) {\n\tv := reflect.ValueOf(x)\n\tdefer func() {\n\t\tok = recover() == nil\n\t}()\n\treturn v.Len(), true\n}\n\n// Len asserts that the specified object has specific length.\n// Len also fails if the object has a type that len() not accept.\n//\n//\tassert.Len(t, mySlice, 3)\nfunc Len(t TestingT, object interface{}, length int, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tl, ok := getLen(object)\n\tif !ok {\n\t\treturn Fail(t, fmt.Sprintf("\\"%v\\" could not be applied builtin len()", object), msgAndArgs...)\n\t}\n\n\tif l != length {\n\t\treturn Fail(t, fmt.Sprintf("\\"%v\\" should have %d item(s), but has %d", object, length, l), msgAndArgs...)\n\t}\n\treturn true\n}\n\n// True asserts that the specified value is true.\n//\n//\tassert.True(t, myBool)\nfunc True(t TestingT, value bool, msgAndArgs ...interface{}) bool {\n\tif !value {\n\t\tif h, ok := t.(tHelper); ok {\n\t\t\th.Helper()\n\t\t}\n\t\treturn Fail(t, "Should be true", msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// False asserts that the specified value is false.\n//\n//\tassert.False(t, myBool)\nfunc False(t TestingT, value bool, msgAndArgs ...interface{}) bool {\n\tif value {\n\t\tif h, ok := t.(tHelper); ok {\n\t\t\th.Helper()\n\t\t}\n\t\treturn Fail(t, "Should be false", msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// NotEqual asserts that the specified values are NOT equal.\n//\n//\tassert.NotEqual(t, obj1, obj2)\n//\n// Pointer variable equality is determined based on the equality of the\n// referenced values (as opposed to the memory addresses).\nfunc NotEqual(t TestingT, expected, actual interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif err := validateEqualArgs(expected, actual); err != nil {\n\t\treturn Fail(t, fmt.Sprintf("Invalid operation: %#v != %#v (%s)",\n\t\t\texpected, actual, err), msgAndArgs...)\n\t}\n\n\tif ObjectsAreEqual(expected, actual) {\n\t\treturn Fail(t, fmt.Sprintf("Should not be: %#v\\n", actual), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// NotEqualValues asserts that two objects are not equal even when converted to the same type\n//\n//\tassert.NotEqualValues(t, obj1, obj2)\nfunc NotEqualValues(t TestingT, expected, actual interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tif ObjectsAreEqualValues(expected, actual) {\n\t\treturn Fail(t, fmt.Sprintf("Should not be: %#v\\n", actual), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// containsElement try loop over the list check if the list includes the element.\n// return (false, false) if impossible.\n// return (true, false) if element was not found.\n// return (true, true) if element was found.\nfunc containsElement(list interface{}, element interface{}) (ok, found bool) {\n\tlistValue := reflect.ValueOf(list)\n\tlistType := reflect.TypeOf(list)\n\tif listType == nil {\n\t\treturn false, false\n\t}\n\tlistKind := listType.Kind()\n\tdefer func() {\n\t\tif e := recover(); e != nil {\n\t\t\tok = false\n\t\t\tfound = false\n\t\t}\n\t}()\n\n\tif listKind == reflect.String {\n\t\telementValue := reflect.ValueOf(element)\n\t\treturn true, strings.Contains(listValue.String(), elementValue.String())\n\t}\n\n\tif listKind == reflect.Map {\n\t\tmapKeys := listValue.MapKeys()\n\t\tfor i := 0; i < len(mapKeys); i++ {\n\t\t\tif ObjectsAreEqual(mapKeys[i].Interface(), element) {\n\t\t\t\treturn true, true\n\t\t\t}\n\t\t}\n\t\treturn true, false\n\t}\n\n\tfor i := 0; i < listValue.Len(); i++ {\n\t\tif ObjectsAreEqual(listValue.Index(i).Interface(), element) {\n\t\t\treturn true, true\n\t\t}\n\t}\n\treturn true, false\n}\n\n// Contains asserts that the specified string, list(array, slice...) or map contains the\n// specified substring or element.\n//\n//\tassert.Contains(t, "Hello World", "World")\n//\tassert.Contains(t, ["Hello", "World"], "World")\n//\tassert.Contains(t, {"Hello": "World"}, "Hello")\nfunc Contains(t TestingT, s, contains interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tok, found := containsElement(s, contains)\n\tif !ok {\n\t\treturn Fail(t, fmt.Sprintf("%#v could not be applied builtin len()", s), msgAndArgs...)\n\t}\n\tif !found {\n\t\treturn Fail(t, fmt.Sprintf("%#v does not contain %#v", s, contains), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// NotContains asserts that the specified string, list(array, slice...) or map does NOT contain the\n// specified substring or element.\n//\n//\tassert.NotContains(t, "Hello World", "Earth")\n//\tassert.NotContains(t, ["Hello", "World"], "Earth")\n//\tassert.NotContains(t, {"Hello": "World"}, "Earth")\nfunc NotContains(t TestingT, s, contains interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tok, found := containsElement(s, contains)\n\tif !ok {\n\t\treturn Fail(t, fmt.Sprintf("%#v could not be applied builtin len()", s), msgAndArgs...)\n\t}\n\tif found {\n\t\treturn Fail(t, fmt.Sprintf("%#v should not contain %#v", s, contains), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// Subset asserts that the list (array, slice, or map) contains all elements\n// given in the subset (array, slice, or map).\n// Map elements are key-value pairs unless compared with an array or slice where\n// only the map key is evaluated.\n//\n//\tassert.Subset(t, [1, 2, 3], [1, 2])\n//\tassert.Subset(t, {"x": 1, "y": 2}, {"x": 1})\n//\tassert.Subset(t, [1, 2, 3], {1: "one", 2: "two"})\n//\tassert.Subset(t, {"x": 1, "y": 2}, ["x"])\nfunc Subset(t TestingT, list, subset interface{}, msgAndArgs ...interface{}) (ok bool) {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif subset == nil {\n\t\treturn true // we consider nil to be equal to the nil set\n\t}\n\n\tlistKind := reflect.TypeOf(list).Kind()\n\tif listKind != reflect.Array && listKind != reflect.Slice && listKind != reflect.Map {\n\t\treturn Fail(t, fmt.Sprintf("%q has an unsupported type %s", list, listKind), msgAndArgs...)\n\t}\n\n\tsubsetKind := reflect.TypeOf(subset).Kind()\n\tif subsetKind != reflect.Array && subsetKind != reflect.Slice && subsetKind != reflect.Map {\n\t\treturn Fail(t, fmt.Sprintf("%q has an unsupported type %s", subset, subsetKind), msgAndArgs...)\n\t}\n\n\tif subsetKind == reflect.Map && listKind == reflect.Map {\n\t\tsubsetMap := reflect.ValueOf(subset)\n\t\tactualMap := reflect.ValueOf(list)\n\n\t\tfor _, k := range subsetMap.MapKeys() {\n\t\t\tev := subsetMap.MapIndex(k)\n\t\t\tav := actualMap.MapIndex(k)\n\n\t\t\tif !av.IsValid() {\n\t\t\t\treturn Fail(t, fmt.Sprintf("%#v does not contain %#v", list, subset), msgAndArgs...)\n\t\t\t}\n\t\t\tif !ObjectsAreEqual(ev.Interface(), av.Interface()) {\n\t\t\t\treturn Fail(t, fmt.Sprintf("%#v does not contain %#v", list, subset), msgAndArgs...)\n\t\t\t}\n\t\t}\n\n\t\treturn true\n\t}\n\n\tsubsetList := reflect.ValueOf(subset)\n\tif subsetKind == reflect.Map {\n\t\tkeys := make([]interface{}, subsetList.Len())\n\t\tfor idx, key := range subsetList.MapKeys() {\n\t\t\tkeys[idx] = key.Interface()\n\t\t}\n\t\tsubsetList = reflect.ValueOf(keys)\n\t}\n\tfor i := 0; i < subsetList.Len(); i++ {\n\t\telement := subsetList.Index(i).Interface()\n\t\tok, found := containsElement(list, element)\n\t\tif !ok {\n\t\t\treturn Fail(t, fmt.Sprintf("%#v could not be applied builtin len()", list), msgAndArgs...)\n\t\t}\n\t\tif !found {\n\t\t\treturn Fail(t, fmt.Sprintf("%#v does not contain %#v", list, element), msgAndArgs...)\n\t\t}\n\t}\n\n\treturn true\n}\n\n// NotSubset asserts that the list (array, slice, or map) does NOT contain all\n// elements given in the subset (array, slice, or map).\n// Map elements are key-value pairs unless compared with an array or slice where\n// only the map key is evaluated.\n//\n//\tassert.NotSubset(t, [1, 3, 4], [1, 2])\n//\tassert.NotSubset(t, {"x": 1, "y": 2}, {"z": 3})\n//\tassert.NotSubset(t, [1, 3, 4], {1: "one", 2: "two"})\n//\tassert.NotSubset(t, {"x": 1, "y": 2}, ["z"])\nfunc NotSubset(t TestingT, list, subset interface{}, msgAndArgs ...interface{}) (ok bool) {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif subset == nil {\n\t\treturn Fail(t, "nil is the empty set which is a subset of every set", msgAndArgs...)\n\t}\n\n\tlistKind := reflect.TypeOf(list).Kind()\n\tif listKind != reflect.Array && listKind != reflect.Slice && listKind != reflect.Map {\n\t\treturn Fail(t, fmt.Sprintf("%q has an unsupported type %s", list, listKind), msgAndArgs...)\n\t}\n\n\tsubsetKind := reflect.TypeOf(subset).Kind()\n\tif subsetKind != reflect.Array && subsetKind != reflect.Slice && subsetKind != reflect.Map {\n\t\treturn Fail(t, fmt.Sprintf("%q has an unsupported type %s", subset, subsetKind), msgAndArgs...)\n\t}\n\n\tif subsetKind == reflect.Map && listKind == reflect.Map {\n\t\tsubsetMap := reflect.ValueOf(subset)\n\t\tactualMap := reflect.ValueOf(list)\n\n\t\tfor _, k := range subsetMap.MapKeys() {\n\t\t\tev := subsetMap.MapIndex(k)\n\t\t\tav := actualMap.MapIndex(k)\n\n\t\t\tif !av.IsValid() {\n\t\t\t\treturn true\n\t\t\t}\n\t\t\tif !ObjectsAreEqual(ev.Interface(), av.Interface()) {\n\t\t\t\treturn true\n\t\t\t}\n\t\t}\n\n\t\treturn Fail(t, fmt.Sprintf("%q is a subset of %q", subset, list), msgAndArgs...)\n\t}\n\n\tsubsetList := reflect.ValueOf(subset)\n\tif subsetKind == reflect.Map {\n\t\tkeys := make([]interface{}, subsetList.Len())\n\t\tfor idx, key := range subsetList.MapKeys() {\n\t\t\tkeys[idx] = key.Interface()\n\t\t}\n\t\tsubsetList = reflect.ValueOf(keys)\n\t}\n\tfor i := 0; i < subsetList.Len(); i++ {\n\t\telement := subsetList.Index(i).Interface()\n\t\tok, found := containsElement(list, element)\n\t\tif !ok {\n\t\t\treturn Fail(t, fmt.Sprintf("%q could not be applied builtin len()", list), msgAndArgs...)\n\t\t}\n\t\tif !found {\n\t\t\treturn true\n\t\t}\n\t}\n\n\treturn Fail(t, fmt.Sprintf("%q is a subset of %q", subset, list), msgAndArgs...)\n}\n\n// ElementsMatch asserts that the specified listA(array, slice...) is equal to specified\n// listB(array, slice...) ignoring the order of the elements. If there are duplicate elements,\n// the number of appearances of each of them in both lists should match.\n//\n// assert.ElementsMatch(t, [1, 3, 2, 3], [1, 3, 3, 2])\nfunc ElementsMatch(t TestingT, listA, listB interface{}, msgAndArgs ...interface{}) (ok bool) {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif isEmpty(listA) && isEmpty(listB) {\n\t\treturn true\n\t}\n\n\tif !isList(t, listA, msgAndArgs...) || !isList(t, listB, msgAndArgs...) {\n\t\treturn false\n\t}\n\n\textraA, extraB := diffLists(listA, listB)\n\n\tif len(extraA) == 0 && len(extraB) == 0 {\n\t\treturn true\n\t}\n\n\treturn Fail(t, formatListDiff(listA, listB, extraA, extraB), msgAndArgs...)\n}\n\n// isList checks that the provided value is array or slice.\nfunc isList(t TestingT, list interface{}, msgAndArgs ...interface{}) (ok bool) {\n\tkind := reflect.TypeOf(list).Kind()\n\tif kind != reflect.Array && kind != reflect.Slice {\n\t\treturn Fail(t, fmt.Sprintf("%q has an unsupported type %s, expecting array or slice", list, kind),\n\t\t\tmsgAndArgs...)\n\t}\n\treturn true\n}\n\n// diffLists diffs two arrays/slices and returns slices of elements that are only in A and only in B.\n// If some element is present multiple times, each instance is counted separately (e.g. if something is 2x in A and\n// 5x in B, it will be 0x in extraA and 3x in extraB). The order of items in both lists is ignored.\nfunc diffLists(listA, listB interface{}) (extraA, extraB []interface{}) {\n\taValue := reflect.ValueOf(listA)\n\tbValue := reflect.ValueOf(listB)\n\n\taLen := aValue.Len()\n\tbLen := bValue.Len()\n\n\t// Mark indexes in bValue that we already used\n\tvisited := make([]bool, bLen)\n\tfor i := 0; i < aLen; i++ {\n\t\telement := aValue.Index(i).Interface()\n\t\tfound := false\n\t\tfor j := 0; j < bLen; j++ {\n\t\t\tif visited[j] {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tif ObjectsAreEqual(bValue.Index(j).Interface(), element) {\n\t\t\t\tvisited[j] = true\n\t\t\t\tfound = true\n\t\t\t\tbreak\n\t\t\t}\n\t\t}\n\t\tif !found {\n\t\t\textraA = append(extraA, element)\n\t\t}\n\t}\n\n\tfor j := 0; j < bLen; j++ {\n\t\tif visited[j] {\n\t\t\tcontinue\n\t\t}\n\t\textraB = append(extraB, bValue.Index(j).Interface())\n\t}\n\n\treturn\n}\n\nfunc formatListDiff(listA, listB interface{}, extraA, extraB []interface{}) string {\n\tvar msg bytes.Buffer\n\n\tmsg.WriteString("elements differ")\n\tif len(extraA) > 0 {\n\t\tmsg.WriteString("\\n\\nextra elements in list A:\\n")\n\t\tmsg.WriteString(spewConfig.Sdump(extraA))\n\t}\n\tif len(extraB) > 0 {\n\t\tmsg.WriteString("\\n\\nextra elements in list B:\\n")\n\t\tmsg.WriteString(spewConfig.Sdump(extraB))\n\t}\n\tmsg.WriteString("\\n\\nlistA:\\n")\n\tmsg.WriteString(spewConfig.Sdump(listA))\n\tmsg.WriteString("\\n\\nlistB:\\n")\n\tmsg.WriteString(spewConfig.Sdump(listB))\n\n\treturn msg.String()\n}\n\n// NotElementsMatch asserts that the specified listA(array, slice...) is NOT equal to specified\n// listB(array, slice...) ignoring the order of the elements. If there are duplicate elements,\n// the number of appearances of each of them in both lists should not match.\n// This is an inverse of ElementsMatch.\n//\n// assert.NotElementsMatch(t, [1, 1, 2, 3], [1, 1, 2, 3]) -> false\n//\n// assert.NotElementsMatch(t, [1, 1, 2, 3], [1, 2, 3]) -> true\n//\n// assert.NotElementsMatch(t, [1, 2, 3], [1, 2, 4]) -> true\nfunc NotElementsMatch(t TestingT, listA, listB interface{}, msgAndArgs ...interface{}) (ok bool) {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif isEmpty(listA) && isEmpty(listB) {\n\t\treturn Fail(t, "listA and listB contain the same elements", msgAndArgs)\n\t}\n\n\tif !isList(t, listA, msgAndArgs...) {\n\t\treturn Fail(t, "listA is not a list type", msgAndArgs...)\n\t}\n\tif !isList(t, listB, msgAndArgs...) {\n\t\treturn Fail(t, "listB is not a list type", msgAndArgs...)\n\t}\n\n\textraA, extraB := diffLists(listA, listB)\n\tif len(extraA) == 0 && len(extraB) == 0 {\n\t\treturn Fail(t, "listA and listB contain the same elements", msgAndArgs)\n\t}\n\n\treturn true\n}\n\n// Condition uses a Comparison to assert a complex condition.\nfunc Condition(t TestingT, comp Comparison, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tresult := comp()\n\tif !result {\n\t\tFail(t, "Condition failed!", msgAndArgs...)\n\t}\n\treturn result\n}\n\n// PanicTestFunc defines a func that should be passed to the assert.Panics and assert.NotPanics\n// methods, and represents a simple func that takes no arguments, and returns nothing.\ntype PanicTestFunc func()\n\n// didPanic returns true if the function passed to it panics. Otherwise, it returns false.\nfunc didPanic(f PanicTestFunc) (didPanic bool, message interface{}, stack string) {\n\tdidPanic = true\n\n\tdefer func() {\n\t\tmessage = recover()\n\t\tif didPanic {\n\t\t\tstack = string(debug.Stack())\n\t\t}\n\t}()\n\n\t// call the target function\n\tf()\n\tdidPanic = false\n\n\treturn\n}\n\n// Panics asserts that the code inside the specified PanicTestFunc panics.\n//\n//\tassert.Panics(t, func(){ GoCrazy() })\nfunc Panics(t TestingT, f PanicTestFunc, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tif funcDidPanic, panicValue, _ := didPanic(f); !funcDidPanic {\n\t\treturn Fail(t, fmt.Sprintf("func %#v should panic\\n\\tPanic value:\\t%#v", f, panicValue), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// PanicsWithValue asserts that the code inside the specified PanicTestFunc panics, and that\n// the recovered panic value equals the expected panic value.\n//\n//\tassert.PanicsWithValue(t, "crazy error", func(){ GoCrazy() })\nfunc PanicsWithValue(t TestingT, expected interface{}, f PanicTestFunc, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tfuncDidPanic, panicValue, panickedStack := didPanic(f)\n\tif !funcDidPanic {\n\t\treturn Fail(t, fmt.Sprintf("func %#v should panic\\n\\tPanic value:\\t%#v", f, panicValue), msgAndArgs...)\n\t}\n\tif panicValue != expected {\n\t\treturn Fail(t, fmt.Sprintf("func %#v should panic with value:\\t%#v\\n\\tPanic value:\\t%#v\\n\\tPanic stack:\\t%s", f, expected, panicValue, panickedStack), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// PanicsWithError asserts that the code inside the specified PanicTestFunc\n// panics, and that the recovered panic value is an error that satisfies the\n// EqualError comparison.\n//\n//\tassert.PanicsWithError(t, "crazy error", func(){ GoCrazy() })\nfunc PanicsWithError(t TestingT, errString string, f PanicTestFunc, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tfuncDidPanic, panicValue, panickedStack := didPanic(f)\n\tif !funcDidPanic {\n\t\treturn Fail(t, fmt.Sprintf("func %#v should panic\\n\\tPanic value:\\t%#v", f, panicValue), msgAndArgs...)\n\t}\n\tpanicErr, isError := panicValue.(error)\n\tif !isError || panicErr.Error() != errString {\n\t\tmsg := fmt.Sprintf("func %#v should panic with error message:\\t%#v\\n", f, errString)\n\t\tif isError {\n\t\t\tmsg += fmt.Sprintf("\\tError message:\\t%#v\\n", panicErr.Error())\n\t\t}\n\t\tmsg += fmt.Sprintf("\\tPanic value:\\t%#v\\n", panicValue)\n\t\tmsg += fmt.Sprintf("\\tPanic stack:\\t%s\\n", panickedStack)\n\t\treturn Fail(t, msg, msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// NotPanics asserts that the code inside the specified PanicTestFunc does NOT panic.\n//\n//\tassert.NotPanics(t, func(){ RemainCalm() })\nfunc NotPanics(t TestingT, f PanicTestFunc, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tif funcDidPanic, panicValue, panickedStack := didPanic(f); funcDidPanic {\n\t\treturn Fail(t, fmt.Sprintf("func %#v should not panic\\n\\tPanic value:\\t%v\\n\\tPanic stack:\\t%s", f, panicValue, panickedStack), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// WithinDuration asserts that the two times are within duration delta of each other.\n//\n//\tassert.WithinDuration(t, time.Now(), time.Now(), 10*time.Second)\nfunc WithinDuration(t TestingT, expected, actual time.Time, delta time.Duration, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tdt := expected.Sub(actual)\n\tif dt < -delta || dt > delta {\n\t\treturn Fail(t, fmt.Sprintf("Max difference between %v and %v allowed is %v, but difference was %v", expected, actual, delta, dt), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// WithinRange asserts that a time is within a time range (inclusive).\n//\n//\tassert.WithinRange(t, time.Now(), time.Now().Add(-time.Second), time.Now().Add(time.Second))\nfunc WithinRange(t TestingT, actual, start, end time.Time, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tif end.Before(start) {\n\t\treturn Fail(t, "Start should be before end", msgAndArgs...)\n\t}\n\n\tif actual.Before(start) {\n\t\treturn Fail(t, fmt.Sprintf("Time %v expected to be in time range %v to %v, but is before the range", actual, start, end), msgAndArgs...)\n\t} else if actual.After(end) {\n\t\treturn Fail(t, fmt.Sprintf("Time %v expected to be in time range %v to %v, but is after the range", actual, start, end), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\nfunc toFloat(x interface{}) (float64, bool) {\n\tvar xf float64\n\txok := true\n\n\tswitch xn := x.(type) {\n\tcase uint:\n\t\txf = float64(xn)\n\tcase uint8:\n\t\txf = float64(xn)\n\tcase uint16:\n\t\txf = float64(xn)\n\tcase uint32:\n\t\txf = float64(xn)\n\tcase uint64:\n\t\txf = float64(xn)\n\tcase int:\n\t\txf = float64(xn)\n\tcase int8:\n\t\txf = float64(xn)\n\tcase int16:\n\t\txf = float64(xn)\n\tcase int32:\n\t\txf = float64(xn)\n\tcase int64:\n\t\txf = float64(xn)\n\tcase float32:\n\t\txf = float64(xn)\n\tcase float64:\n\t\txf = xn\n\tcase time.Duration:\n\t\txf = float64(xn)\n\tdefault:\n\t\txok = false\n\t}\n\n\treturn xf, xok\n}\n\n// InDelta asserts that the two numerals are within delta of each other.\n//\n//\tassert.InDelta(t, math.Pi, 22/7.0, 0.01)\nfunc InDelta(t TestingT, expected, actual interface{}, delta float64, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\taf, aok := toFloat(expected)\n\tbf, bok := toFloat(actual)\n\n\tif !aok || !bok {\n\t\treturn Fail(t, "Parameters must be numerical", msgAndArgs...)\n\t}\n\n\tif math.IsNaN(af) && math.IsNaN(bf) {\n\t\treturn true\n\t}\n\n\tif math.IsNaN(af) {\n\t\treturn Fail(t, "Expected must not be NaN", msgAndArgs...)\n\t}\n\n\tif math.IsNaN(bf) {\n\t\treturn Fail(t, fmt.Sprintf("Expected %v with delta %v, but was NaN", expected, delta), msgAndArgs...)\n\t}\n\n\tdt := af - bf\n\tif dt < -delta || dt > delta {\n\t\treturn Fail(t, fmt.Sprintf("Max difference between %v and %v allowed is %v, but difference was %v", expected, actual, delta, dt), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// InDeltaSlice is the same as InDelta, except it compares two slices.\nfunc InDeltaSlice(t TestingT, expected, actual interface{}, delta float64, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif expected == nil || actual == nil ||\n\t\treflect.TypeOf(actual).Kind() != reflect.Slice ||\n\t\treflect.TypeOf(expected).Kind() != reflect.Slice {\n\t\treturn Fail(t, "Parameters must be slice", msgAndArgs...)\n\t}\n\n\tactualSlice := reflect.ValueOf(actual)\n\texpectedSlice := reflect.ValueOf(expected)\n\n\tfor i := 0; i < actualSlice.Len(); i++ {\n\t\tresult := InDelta(t, actualSlice.Index(i).Interface(), expectedSlice.Index(i).Interface(), delta, msgAndArgs...)\n\t\tif !result {\n\t\t\treturn result\n\t\t}\n\t}\n\n\treturn true\n}\n\n// InDeltaMapValues is the same as InDelta, but it compares all values between two maps. Both maps must have exactly the same keys.\nfunc InDeltaMapValues(t TestingT, expected, actual interface{}, delta float64, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif expected == nil || actual == nil ||\n\t\treflect.TypeOf(actual).Kind() != reflect.Map ||\n\t\treflect.TypeOf(expected).Kind() != reflect.Map {\n\t\treturn Fail(t, "Arguments must be maps", msgAndArgs...)\n\t}\n\n\texpectedMap := reflect.ValueOf(expected)\n\tactualMap := reflect.ValueOf(actual)\n\n\tif expectedMap.Len() != actualMap.Len() {\n\t\treturn Fail(t, "Arguments must have the same number of keys", msgAndArgs...)\n\t}\n\n\tfor _, k := range expectedMap.MapKeys() {\n\t\tev := expectedMap.MapIndex(k)\n\t\tav := actualMap.MapIndex(k)\n\n\t\tif !ev.IsValid() {\n\t\t\treturn Fail(t, fmt.Sprintf("missing key %q in expected map", k), msgAndArgs...)\n\t\t}\n\n\t\tif !av.IsValid() {\n\t\t\treturn Fail(t, fmt.Sprintf("missing key %q in actual map", k), msgAndArgs...)\n\t\t}\n\n\t\tif !InDelta(\n\t\t\tt,\n\t\t\tev.Interface(),\n\t\t\tav.Interface(),\n\t\t\tdelta,\n\t\t\tmsgAndArgs...,\n\t\t) {\n\t\t\treturn false\n\t\t}\n\t}\n\n\treturn true\n}\n\nfunc calcRelativeError(expected, actual interface{}) (float64, error) {\n\taf, aok := toFloat(expected)\n\tbf, bok := toFloat(actual)\n\tif !aok || !bok {\n\t\treturn 0, fmt.Errorf("Parameters must be numerical")\n\t}\n\tif math.IsNaN(af) && math.IsNaN(bf) {\n\t\treturn 0, nil\n\t}\n\tif math.IsNaN(af) {\n\t\treturn 0, errors.New("expected value must not be NaN")\n\t}\n\tif af == 0 {\n\t\treturn 0, fmt.Errorf("expected value must have a value other than zero to calculate the relative error")\n\t}\n\tif math.IsNaN(bf) {\n\t\treturn 0, errors.New("actual value must not be NaN")\n\t}\n\n\treturn math.Abs(af-bf) / math.Abs(af), nil\n}\n\n// InEpsilon asserts that expected and actual have a relative error less than epsilon\nfunc InEpsilon(t TestingT, expected, actual interface{}, epsilon float64, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif math.IsNaN(epsilon) {\n\t\treturn Fail(t, "epsilon must not be NaN", msgAndArgs...)\n\t}\n\tactualEpsilon, err := calcRelativeError(expected, actual)\n\tif err != nil {\n\t\treturn Fail(t, err.Error(), msgAndArgs...)\n\t}\n\tif math.IsNaN(actualEpsilon) {\n\t\treturn Fail(t, "relative error is NaN", msgAndArgs...)\n\t}\n\tif actualEpsilon > epsilon {\n\t\treturn Fail(t, fmt.Sprintf("Relative error is too high: %#v (expected)\\n"+\n\t\t\t"        < %#v (actual)", epsilon, actualEpsilon), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// InEpsilonSlice is the same as InEpsilon, except it compares each value from two slices.\nfunc InEpsilonSlice(t TestingT, expected, actual interface{}, epsilon float64, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tif expected == nil || actual == nil {\n\t\treturn Fail(t, "Parameters must be slice", msgAndArgs...)\n\t}\n\n\texpectedSlice := reflect.ValueOf(expected)\n\tactualSlice := reflect.ValueOf(actual)\n\n\tif expectedSlice.Type().Kind() != reflect.Slice {\n\t\treturn Fail(t, "Expected value must be slice", msgAndArgs...)\n\t}\n\n\texpectedLen := expectedSlice.Len()\n\tif !IsType(t, expected, actual) || !Len(t, actual, expectedLen) {\n\t\treturn false\n\t}\n\n\tfor i := 0; i < expectedLen; i++ {\n\t\tif !InEpsilon(t, expectedSlice.Index(i).Interface(), actualSlice.Index(i).Interface(), epsilon, "at index %d", i) {\n\t\t\treturn false\n\t\t}\n\t}\n\n\treturn true\n}\n\n/*\n\tErrors\n*/\n\n// NoError asserts that a function returned no error (i.e. `nil`).\n//\n//\t  actualObj, err := SomeFunction()\n//\t  if assert.NoError(t, err) {\n//\t\t   assert.Equal(t, expectedObj, actualObj)\n//\t  }\nfunc NoError(t TestingT, err error, msgAndArgs ...interface{}) bool {\n\tif err != nil {\n\t\tif h, ok := t.(tHelper); ok {\n\t\t\th.Helper()\n\t\t}\n\t\treturn Fail(t, fmt.Sprintf("Received unexpected error:\\n%+v", err), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// Error asserts that a function returned an error (i.e. not `nil`).\n//\n//\tactualObj, err := SomeFunction()\n//\tassert.Error(t, err)\nfunc Error(t TestingT, err error, msgAndArgs ...interface{}) bool {\n\tif err == nil {\n\t\tif h, ok := t.(tHelper); ok {\n\t\t\th.Helper()\n\t\t}\n\t\treturn Fail(t, "An error is expected but got nil.", msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// EqualError asserts that a function returned an error (i.e. not `nil`)\n// and that it is equal to the provided error.\n//\n//\tactualObj, err := SomeFunction()\n//\tassert.EqualError(t, err,  expectedErrorString)\nfunc EqualError(t TestingT, theError error, errString string, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif !Error(t, theError, msgAndArgs...) {\n\t\treturn false\n\t}\n\texpected := errString\n\tactual := theError.Error()\n\t// don\'t need to use deep equals here, we know they are both strings\n\tif expected != actual {\n\t\treturn Fail(t, fmt.Sprintf("Error message not equal:\\n"+\n\t\t\t"expected: %q\\n"+\n\t\t\t"actual  : %q", expected, actual), msgAndArgs...)\n\t}\n\treturn true\n}\n\n// ErrorContains asserts that a function returned an error (i.e. not `nil`)\n// and that the error contains the specified substring.\n//\n//\tactualObj, err := SomeFunction()\n//\tassert.ErrorContains(t, err,  expectedErrorSubString)\nfunc ErrorContains(t TestingT, theError error, contains string, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif !Error(t, theError, msgAndArgs...) {\n\t\treturn false\n\t}\n\n\tactual := theError.Error()\n\tif !strings.Contains(actual, contains) {\n\t\treturn Fail(t, fmt.Sprintf("Error %#v does not contain %#v", actual, contains), msgAndArgs...)\n\t}\n\n\treturn true\n}\n\n// matchRegexp return true if a specified regexp matches a string.\nfunc matchRegexp(rx interface{}, str interface{}) bool {\n\tvar r *regexp.Regexp\n\tif rr, ok := rx.(*regexp.Regexp); ok {\n\t\tr = rr\n\t} else {\n\t\tr = regexp.MustCompile(fmt.Sprint(rx))\n\t}\n\n\tswitch v := str.(type) {\n\tcase []byte:\n\t\treturn r.Match(v)\n\tcase string:\n\t\treturn r.MatchString(v)\n\tdefault:\n\t\treturn r.MatchString(fmt.Sprint(v))\n\t}\n}\n\n// Regexp asserts that a specified regexp matches a string.\n//\n//\tassert.Regexp(t, regexp.MustCompile("start"), "it\'s starting")\n//\tassert.Regexp(t, "start...$", "it\'s not starting")\nfunc Regexp(t TestingT, rx interface{}, str interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tmatch := matchRegexp(rx, str)\n\n\tif !match {\n\t\tFail(t, fmt.Sprintf("Expect \\"%v\\" to match \\"%v\\"", str, rx), msgAndArgs...)\n\t}\n\n\treturn match\n}\n\n// NotRegexp asserts that a specified regexp does not match a string.\n//\n//\tassert.NotRegexp(t, regexp.MustCompile("starts"), "it\'s starting")\n//\tassert.NotRegexp(t, "^start", "it\'s not starting")\nfunc NotRegexp(t TestingT, rx interface{}, str interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tmatch := matchRegexp(rx, str)\n\n\tif match {\n\t\tFail(t, fmt.Sprintf("Expect \\"%v\\" to NOT match \\"%v\\"", str, rx), msgAndArgs...)\n\t}\n\n\treturn !match\n}\n\n// Zero asserts that i is the zero value for its type.\nfunc Zero(t TestingT, i interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif i != nil && !reflect.DeepEqual(i, reflect.Zero(reflect.TypeOf(i)).Interface()) {\n\t\treturn Fail(t, fmt.Sprintf("Should be zero, but was %v", i), msgAndArgs...)\n\t}\n\treturn true\n}\n\n// NotZero asserts that i is not the zero value for its type.\nfunc NotZero(t TestingT, i interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif i == nil || reflect.DeepEqual(i, reflect.Zero(reflect.TypeOf(i)).Interface()) {\n\t\treturn Fail(t, fmt.Sprintf("Should not be zero, but was %v", i), msgAndArgs...)\n\t}\n\treturn true\n}\n\n// FileExists checks whether a file exists in the given path. It also fails if\n// the path points to a directory or there is an error when trying to check the file.\nfunc FileExists(t TestingT, path string, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tinfo, err := os.Lstat(path)\n\tif err != nil {\n\t\tif os.IsNotExist(err) {\n\t\t\treturn Fail(t, fmt.Sprintf("unable to find file %q", path), msgAndArgs...)\n\t\t}\n\t\treturn Fail(t, fmt.Sprintf("error when running os.Lstat(%q): %s", path, err), msgAndArgs...)\n\t}\n\tif info.IsDir() {\n\t\treturn Fail(t, fmt.Sprintf("%q is a directory", path), msgAndArgs...)\n\t}\n\treturn true\n}\n\n// NoFileExists checks whether a file does not exist in a given path. It fails\n// if the path points to an existing _file_ only.\nfunc NoFileExists(t TestingT, path string, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tinfo, err := os.Lstat(path)\n\tif err != nil {\n\t\treturn true\n\t}\n\tif info.IsDir() {\n\t\treturn true\n\t}\n\treturn Fail(t, fmt.Sprintf("file %q exists", path), msgAndArgs...)\n}\n\n// DirExists checks whether a directory exists in the given path. It also fails\n// if the path is a file rather a directory or there is an error checking whether it exists.\nfunc DirExists(t TestingT, path string, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tinfo, err := os.Lstat(path)\n\tif err != nil {\n\t\tif os.IsNotExist(err) {\n\t\t\treturn Fail(t, fmt.Sprintf("unable to find file %q", path), msgAndArgs...)\n\t\t}\n\t\treturn Fail(t, fmt.Sprintf("error when running os.Lstat(%q): %s", path, err), msgAndArgs...)\n\t}\n\tif !info.IsDir() {\n\t\treturn Fail(t, fmt.Sprintf("%q is a file", path), msgAndArgs...)\n\t}\n\treturn true\n}\n\n// NoDirExists checks whether a directory does not exist in the given path.\n// It fails if the path points to an existing _directory_ only.\nfunc NoDirExists(t TestingT, path string, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tinfo, err := os.Lstat(path)\n\tif err != nil {\n\t\tif os.IsNotExist(err) {\n\t\t\treturn true\n\t\t}\n\t\treturn true\n\t}\n\tif !info.IsDir() {\n\t\treturn true\n\t}\n\treturn Fail(t, fmt.Sprintf("directory %q exists", path), msgAndArgs...)\n}\n\n// JSONEq asserts that two JSON strings are equivalent.\n//\n//\tassert.JSONEq(t, `{"hello": "world", "foo": "bar"}`, `{"foo": "bar", "hello": "world"}`)\nfunc JSONEq(t TestingT, expected string, actual string, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tvar expectedJSONAsInterface, actualJSONAsInterface interface{}\n\n\tif err := json.Unmarshal([]byte(expected), &expectedJSONAsInterface); err != nil {\n\t\treturn Fail(t, fmt.Sprintf("Expected value (\'%s\') is not valid json.\\nJSON parsing error: \'%s\'", expected, err.Error()), msgAndArgs...)\n\t}\n\n\t// Shortcut if same bytes\n\tif actual == expected {\n\t\treturn true\n\t}\n\n\tif err := json.Unmarshal([]byte(actual), &actualJSONAsInterface); err != nil {\n\t\treturn Fail(t, fmt.Sprintf("Input (\'%s\') needs to be valid json.\\nJSON parsing error: \'%s\'", actual, err.Error()), msgAndArgs...)\n\t}\n\n\treturn Equal(t, expectedJSONAsInterface, actualJSONAsInterface, msgAndArgs...)\n}\n\n// YAMLEq asserts that two YAML strings are equivalent.\nfunc YAMLEq(t TestingT, expected string, actual string, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tvar expectedYAMLAsInterface, actualYAMLAsInterface interface{}\n\n\tif err := yaml.Unmarshal([]byte(expected), &expectedYAMLAsInterface); err != nil {\n\t\treturn Fail(t, fmt.Sprintf("Expected value (\'%s\') is not valid yaml.\\nYAML parsing error: \'%s\'", expected, err.Error()), msgAndArgs...)\n\t}\n\n\t// Shortcut if same bytes\n\tif actual == expected {\n\t\treturn true\n\t}\n\n\tif err := yaml.Unmarshal([]byte(actual), &actualYAMLAsInterface); err != nil {\n\t\treturn Fail(t, fmt.Sprintf("Input (\'%s\') needs to be valid yaml.\\nYAML error: \'%s\'", actual, err.Error()), msgAndArgs...)\n\t}\n\n\treturn Equal(t, expectedYAMLAsInterface, actualYAMLAsInterface, msgAndArgs...)\n}\n\nfunc typeAndKind(v interface{}) (reflect.Type, reflect.Kind) {\n\tt := reflect.TypeOf(v)\n\tk := t.Kind()\n\n\tif k == reflect.Ptr {\n\t\tt = t.Elem()\n\t\tk = t.Kind()\n\t}\n\treturn t, k\n}\n\n// diff returns a diff of both values as long as both are of the same type and\n// are a struct, map, slice, array or string. Otherwise it returns an empty string.\nfunc diff(expected interface{}, actual interface{}) string {\n\tif expected == nil || actual == nil {\n\t\treturn ""\n\t}\n\n\tet, ek := typeAndKind(expected)\n\tat, _ := typeAndKind(actual)\n\n\tif et != at {\n\t\treturn ""\n\t}\n\n\tif ek != reflect.Struct && ek != reflect.Map && ek != reflect.Slice && ek != reflect.Array && ek != reflect.String {\n\t\treturn ""\n\t}\n\n\tvar e, a string\n\n\tswitch et {\n\tcase reflect.TypeOf(""):\n\t\te = reflect.ValueOf(expected).String()\n\t\ta = reflect.ValueOf(actual).String()\n\tcase reflect.TypeOf(time.Time{}):\n\t\te = spewConfigStringerEnabled.Sdump(expected)\n\t\ta = spewConfigStringerEnabled.Sdump(actual)\n\tdefault:\n\t\te = spewConfig.Sdump(expected)\n\t\ta = spewConfig.Sdump(actual)\n\t}\n\n\tdiff, _ := difflib.GetUnifiedDiffString(difflib.UnifiedDiff{\n\t\tA:        difflib.SplitLines(e),\n\t\tB:        difflib.SplitLines(a),\n\t\tFromFile: "Expected",\n\t\tFromDate: "",\n\t\tToFile:   "Actual",\n\t\tToDate:   "",\n\t\tContext:  1,\n\t})\n\n\treturn "\\n\\nDiff:\\n" + diff\n}\n\nfunc isFunction(arg interface{}) bool {\n\tif arg == nil {\n\t\treturn false\n\t}\n\treturn reflect.TypeOf(arg).Kind() == reflect.Func\n}\n\nvar spewConfig = spew.ConfigState{\n\tIndent:                  " ",\n\tDisablePointerAddresses: true,\n\tDisableCapacities:       true,\n\tSortKeys:                true,\n\tDisableMethods:          true,\n\tMaxDepth:                10,\n}\n\nvar spewConfigStringerEnabled = spew.ConfigState{\n\tIndent:                  " ",\n\tDisablePointerAddresses: true,\n\tDisableCapacities:       true,\n\tSortKeys:                true,\n\tMaxDepth:                10,\n}\n\ntype tHelper = interface {\n\tHelper()\n}\n\n// Eventually asserts that given condition will be met in waitFor time,\n// periodically checking target function each tick.\n//\n//\tassert.Eventually(t, func() bool { return true; }, time.Second, 10*time.Millisecond)\nfunc Eventually(t TestingT, condition func() bool, waitFor time.Duration, tick time.Duration, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tch := make(chan bool, 1)\n\tcheckCond := func() { ch <- condition() }\n\n\ttimer := time.NewTimer(waitFor)\n\tdefer timer.Stop()\n\n\tticker := time.NewTicker(tick)\n\tdefer ticker.Stop()\n\n\tvar tickC <-chan time.Time\n\n\t// Check the condition once first on the initial call.\n\tgo checkCond()\n\n\tfor {\n\t\tselect {\n\t\tcase <-timer.C:\n\t\t\treturn Fail(t, "Condition never satisfied", msgAndArgs...)\n\t\tcase <-tickC:\n\t\t\ttickC = nil\n\t\t\tgo checkCond()\n\t\tcase v := <-ch:\n\t\t\tif v {\n\t\t\t\treturn true\n\t\t\t}\n\t\t\ttickC = ticker.C\n\t\t}\n\t}\n}\n\n// CollectT implements the TestingT interface and collects all errors.\ntype CollectT struct {\n\t// A slice of errors. Non-nil slice denotes a failure.\n\t// If it\'s non-nil but len(c.errors) == 0, this is also a failure\n\t// obtained by direct c.FailNow() call.\n\terrors []error\n}\n\n// Helper is like [testing.T.Helper] but does nothing.\nfunc (CollectT) Helper() {}\n\n// Errorf collects the error.\nfunc (c *CollectT) Errorf(format string, args ...interface{}) {\n\tc.errors = append(c.errors, fmt.Errorf(format, args...))\n}\n\n// FailNow stops execution by calling runtime.Goexit.\nfunc (c *CollectT) FailNow() {\n\tc.fail()\n\truntime.Goexit()\n}\n\n// Deprecated: That was a method for internal usage that should not have been published. Now just panics.\nfunc (*CollectT) Reset() {\n\tpanic("Reset() is deprecated")\n}\n\n// Deprecated: That was a method for internal usage that should not have been published. Now just panics.\nfunc (*CollectT) Copy(TestingT) {\n\tpanic("Copy() is deprecated")\n}\n\nfunc (c *CollectT) fail() {\n\tif !c.failed() {\n\t\tc.errors = []error{} // Make it non-nil to mark a failure.\n\t}\n}\n\nfunc (c *CollectT) failed() bool {\n\treturn c.errors != nil\n}\n\n// EventuallyWithT asserts that given condition will be met in waitFor time,\n// periodically checking target function each tick. In contrast to Eventually,\n// it supplies a CollectT to the condition function, so that the condition\n// function can use the CollectT to call other assertions.\n// The condition is considered "met" if no errors are raised in a tick.\n// The supplied CollectT collects all errors from one tick (if there are any).\n// If the condition is not met before waitFor, the collected errors of\n// the last tick are copied to t.\n//\n//\texternalValue := false\n//\tgo func() {\n//\t\ttime.Sleep(8*time.Second)\n//\t\texternalValue = true\n//\t}()\n//\tassert.EventuallyWithT(t, func(c *assert.CollectT) {\n//\t\t// add assertions as needed; any assertion failure will fail the current tick\n//\t\tassert.True(c, externalValue, "expected \'externalValue\' to be true")\n//\t}, 10*time.Second, 1*time.Second, "external state has not changed to \'true\'; still false")\nfunc EventuallyWithT(t TestingT, condition func(collect *CollectT), waitFor time.Duration, tick time.Duration, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tvar lastFinishedTickErrs []error\n\tch := make(chan *CollectT, 1)\n\n\tcheckCond := func() {\n\t\tcollect := new(CollectT)\n\t\tdefer func() {\n\t\t\tch <- collect\n\t\t}()\n\t\tcondition(collect)\n\t}\n\n\ttimer := time.NewTimer(waitFor)\n\tdefer timer.Stop()\n\n\tticker := time.NewTicker(tick)\n\tdefer ticker.Stop()\n\n\tvar tickC <-chan time.Time\n\n\t// Check the condition once first on the initial call.\n\tgo checkCond()\n\n\tfor {\n\t\tselect {\n\t\tcase <-timer.C:\n\t\t\tfor _, err := range lastFinishedTickErrs {\n\t\t\t\tt.Errorf("%v", err)\n\t\t\t}\n\t\t\treturn Fail(t, "Condition never satisfied", msgAndArgs...)\n\t\tcase <-tickC:\n\t\t\ttickC = nil\n\t\t\tgo checkCond()\n\t\tcase collect := <-ch:\n\t\t\tif !collect.failed() {\n\t\t\t\treturn true\n\t\t\t}\n\t\t\t// Keep the errors from the last ended condition, so that they can be copied to t if timeout is reached.\n\t\t\tlastFinishedTickErrs = collect.errors\n\t\t\ttickC = ticker.C\n\t\t}\n\t}\n}\n\n// Never asserts that the given condition doesn\'t satisfy in waitFor time,\n// periodically checking the target function each tick.\n//\n//\tassert.Never(t, func() bool { return false; }, time.Second, 10*time.Millisecond)\nfunc Never(t TestingT, condition func() bool, waitFor time.Duration, tick time.Duration, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\n\tch := make(chan bool, 1)\n\tcheckCond := func() { ch <- condition() }\n\n\ttimer := time.NewTimer(waitFor)\n\tdefer timer.Stop()\n\n\tticker := time.NewTicker(tick)\n\tdefer ticker.Stop()\n\n\tvar tickC <-chan time.Time\n\n\t// Check the condition once first on the initial call.\n\tgo checkCond()\n\n\tfor {\n\t\tselect {\n\t\tcase <-timer.C:\n\t\t\treturn true\n\t\tcase <-tickC:\n\t\t\ttickC = nil\n\t\t\tgo checkCond()\n\t\tcase v := <-ch:\n\t\t\tif v {\n\t\t\t\treturn Fail(t, "Condition satisfied", msgAndArgs...)\n\t\t\t}\n\t\t\ttickC = ticker.C\n\t\t}\n\t}\n}\n\n// ErrorIs asserts that at least one of the errors in err\'s chain matches target.\n// This is a wrapper for errors.Is.\nfunc ErrorIs(t TestingT, err, target error, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif errors.Is(err, target) {\n\t\treturn true\n\t}\n\n\tvar expectedText string\n\tif target != nil {\n\t\texpectedText = target.Error()\n\t\tif err == nil {\n\t\t\treturn Fail(t, fmt.Sprintf("Expected error with %q in chain but got nil.", expectedText), msgAndArgs...)\n\t\t}\n\t}\n\n\tchain := buildErrorChainString(err, false)\n\n\treturn Fail(t, fmt.Sprintf("Target error should be in err chain:\\n"+\n\t\t"expected: %q\\n"+\n\t\t"in chain: %s", expectedText, chain,\n\t), msgAndArgs...)\n}\n\n// NotErrorIs asserts that none of the errors in err\'s chain matches target.\n// This is a wrapper for errors.Is.\nfunc NotErrorIs(t TestingT, err, target error, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif !errors.Is(err, target) {\n\t\treturn true\n\t}\n\n\tvar expectedText string\n\tif target != nil {\n\t\texpectedText = target.Error()\n\t}\n\n\tchain := buildErrorChainString(err, false)\n\n\treturn Fail(t, fmt.Sprintf("Target error should not be in err chain:\\n"+\n\t\t"found: %q\\n"+\n\t\t"in chain: %s", expectedText, chain,\n\t), msgAndArgs...)\n}\n\n// ErrorAs asserts that at least one of the errors in err\'s chain matches target, and if so, sets target to that error value.\n// This is a wrapper for errors.As.\nfunc ErrorAs(t TestingT, err error, target interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif errors.As(err, target) {\n\t\treturn true\n\t}\n\n\texpectedType := reflect.TypeOf(target).Elem().String()\n\tif err == nil {\n\t\treturn Fail(t, fmt.Sprintf("An error is expected but got nil.\\n"+\n\t\t\t"expected: %s", expectedType), msgAndArgs...)\n\t}\n\n\tchain := buildErrorChainString(err, true)\n\n\treturn Fail(t, fmt.Sprintf("Should be in error chain:\\n"+\n\t\t"expected: %s\\n"+\n\t\t"in chain: %s", expectedType, chain,\n\t), msgAndArgs...)\n}\n\n// NotErrorAs asserts that none of the errors in err\'s chain matches target,\n// but if so, sets target to that error value.\nfunc NotErrorAs(t TestingT, err error, target interface{}, msgAndArgs ...interface{}) bool {\n\tif h, ok := t.(tHelper); ok {\n\t\th.Helper()\n\t}\n\tif !errors.As(err, target) {\n\t\treturn true\n\t}\n\n\tchain := buildErrorChainString(err, true)\n\n\treturn Fail(t, fmt.Sprintf("Target error should not be in err chain:\\n"+\n\t\t"found: %s\\n"+\n\t\t"in chain: %s", reflect.TypeOf(target).Elem().String(), chain,\n\t), msgAndArgs...)\n}\n\nfunc unwrapAll(err error) (errs []error) {\n\terrs = append(errs, err)\n\tswitch x := err.(type) {\n\tcase interface{ Unwrap() error }:\n\t\terr = x.Unwrap()\n\t\tif err == nil {\n\t\t\treturn\n\t\t}\n\t\terrs = append(errs, unwrapAll(err)...)\n\tcase interface{ Unwrap() []error }:\n\t\tfor _, err := range x.Unwrap() {\n\t\t\terrs = append(errs, unwrapAll(err)...)\n\t\t}\n\t}\n\treturn\n}\n\nfunc buildErrorChainString(err error, withType bool) string {\n\tif err == nil {\n\t\treturn ""\n\t}\n\n\tvar chain string\n\terrs := unwrapAll(err)\n\tfor i := range errs {\n\t\tif i != 0 {\n\t\t\tchain += "\\n\\t"\n\t\t}\n\t\tchain += fmt.Sprintf("%q", errs[i].Error())\n\t\tif withType {\n\t\t\tchain += fmt.Sprintf(" (%T)", errs[i])\n\t\t}\n\t}\n\treturn chain\n}\n',
            'assert/assertions_test.go': 'package assert\n\nimport (\n\t"bufio"\n\t"bytes"\n\t"encoding/json"\n\t"errors"\n\t"fmt"\n\t"io"\n\t"math"\n\t"os"\n\t"path/filepath"\n\t"reflect"\n\t"regexp"\n\t"runtime"\n\t"strings"\n\t"testing"\n\t"time"\n)\n\nvar (\n\ti     interface{}\n\tzeros = []interface{}{\n\t\tfalse,\n\t\tbyte(0),\n\t\tcomplex64(0),\n\t\tcomplex128(0),\n\t\tfloat32(0),\n\t\tfloat64(0),\n\t\tint(0),\n\t\tint8(0),\n\t\tint16(0),\n\t\tint32(0),\n\t\tint64(0),\n\t\trune(0),\n\t\tuint(0),\n\t\tuint8(0),\n\t\tuint16(0),\n\t\tuint32(0),\n\t\tuint64(0),\n\t\tuintptr(0),\n\t\t"",\n\t\t[0]interface{}{},\n\t\t[]interface{}(nil),\n\t\tstruct{ x int }{},\n\t\t(*interface{})(nil),\n\t\t(func())(nil),\n\t\tnil,\n\t\tinterface{}(nil),\n\t\tmap[interface{}]interface{}(nil),\n\t\t(chan interface{})(nil),\n\t\t(<-chan interface{})(nil),\n\t\t(chan<- interface{})(nil),\n\t}\n\tnonZeros = []interface{}{\n\t\ttrue,\n\t\tbyte(1),\n\t\tcomplex64(1),\n\t\tcomplex128(1),\n\t\tfloat32(1),\n\t\tfloat64(1),\n\t\tint(1),\n\t\tint8(1),\n\t\tint16(1),\n\t\tint32(1),\n\t\tint64(1),\n\t\trune(1),\n\t\tuint(1),\n\t\tuint8(1),\n\t\tuint16(1),\n\t\tuint32(1),\n\t\tuint64(1),\n\t\tuintptr(1),\n\t\t"s",\n\t\t[1]interface{}{1},\n\t\t[]interface{}{},\n\t\tstruct{ x int }{1},\n\t\t(&i),\n\t\t(func() {}),\n\t\tinterface{}(1),\n\t\tmap[interface{}]interface{}{},\n\t\t(make(chan interface{})),\n\t\t(<-chan interface{})(make(chan interface{})),\n\t\t(chan<- interface{})(make(chan interface{})),\n\t}\n)\n\n// AssertionTesterInterface defines an interface to be used for testing assertion methods\ntype AssertionTesterInterface interface {\n\tTestMethod()\n}\n\n// AssertionTesterConformingObject is an object that conforms to the AssertionTesterInterface interface\ntype AssertionTesterConformingObject struct{}\n\nfunc (a *AssertionTesterConformingObject) TestMethod() {\n}\n\n// AssertionTesterNonConformingObject is an object that does not conform to the AssertionTesterInterface interface\ntype AssertionTesterNonConformingObject struct{}\n\nfunc TestObjectsAreEqual(t *testing.T) {\n\tt.Parallel()\n\n\tcases := []struct {\n\t\texpected interface{}\n\t\tactual   interface{}\n\t\tresult   bool\n\t}{\n\t\t// cases that are expected to be equal\n\t\t{"Hello World", "Hello World", true},\n\t\t{123, 123, true},\n\t\t{123.5, 123.5, true},\n\t\t{[]byte("Hello World"), []byte("Hello World"), true},\n\t\t{nil, nil, true},\n\n\t\t// cases that are expected not to be equal\n\t\t{map[int]int{5: 10}, map[int]int{10: 20}, false},\n\t\t{\'x\', "x", false},\n\t\t{"x", \'x\', false},\n\t\t{0, 0.1, false},\n\t\t{0.1, 0, false},\n\t\t{time.Now, time.Now, false},\n\t\t{func() {}, func() {}, false},\n\t\t{uint32(10), int32(10), false},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run(fmt.Sprintf("ObjectsAreEqual(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tres := ObjectsAreEqual(c.expected, c.actual)\n\n\t\t\tif res != c.result {\n\t\t\t\tt.Errorf("ObjectsAreEqual(%#v, %#v) should return %#v", c.expected, c.actual, c.result)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestObjectsAreEqualValues(t *testing.T) {\n\tt.Parallel()\n\n\tnow := time.Now()\n\n\tcases := []struct {\n\t\texpected interface{}\n\t\tactual   interface{}\n\t\tresult   bool\n\t}{\n\t\t{uint32(10), int32(10), true},\n\t\t{0, nil, false},\n\t\t{nil, 0, false},\n\t\t{now, now.In(time.Local), false}, // should not be time zone independent\n\t\t{int(270), int8(14), false},      // should handle overflow/underflow\n\t\t{int8(14), int(270), false},\n\t\t{[]int{270, 270}, []int8{14, 14}, false},\n\t\t{complex128(1e+100 + 1e+100i), complex64(complex(math.Inf(0), math.Inf(0))), false},\n\t\t{complex64(complex(math.Inf(0), math.Inf(0))), complex128(1e+100 + 1e+100i), false},\n\t\t{complex128(1e+100 + 1e+100i), 270, false},\n\t\t{270, complex128(1e+100 + 1e+100i), false},\n\t\t{complex128(1e+100 + 1e+100i), 3.14, false},\n\t\t{3.14, complex128(1e+100 + 1e+100i), false},\n\t\t{complex128(1e+10 + 1e+10i), complex64(1e+10 + 1e+10i), true},\n\t\t{complex64(1e+10 + 1e+10i), complex128(1e+10 + 1e+10i), true},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run(fmt.Sprintf("ObjectsAreEqualValues(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tres := ObjectsAreEqualValues(c.expected, c.actual)\n\n\t\t\tif res != c.result {\n\t\t\t\tt.Errorf("ObjectsAreEqualValues(%#v, %#v) should return %#v", c.expected, c.actual, c.result)\n\t\t\t}\n\t\t})\n\t}\n}\n\ntype Nested struct {\n\tExported    interface{}\n\tnotExported interface{}\n}\n\ntype S struct {\n\tExported1    interface{}\n\tExported2    Nested\n\tnotExported1 interface{}\n\tnotExported2 Nested\n}\n\ntype S2 struct {\n\tfoo interface{}\n}\n\ntype S3 struct {\n\tExported1 *Nested\n\tExported2 *Nested\n}\n\ntype S4 struct {\n\tExported1 []*Nested\n}\n\ntype S5 struct {\n\tExported Nested\n}\n\ntype S6 struct {\n\tExported   string\n\tunexported string\n}\n\nfunc TestObjectsExportedFieldsAreEqual(t *testing.T) {\n\tt.Parallel()\n\n\tintValue := 1\n\n\tcases := []struct {\n\t\texpected interface{}\n\t\tactual   interface{}\n\t\tresult   bool\n\t}{\n\t\t{S{1, Nested{2, 3}, 4, Nested{5, 6}}, S{1, Nested{2, 3}, 4, Nested{5, 6}}, true},\n\t\t{S{1, Nested{2, 3}, 4, Nested{5, 6}}, S{1, Nested{2, 3}, "a", Nested{5, 6}}, true},\n\t\t{S{1, Nested{2, 3}, 4, Nested{5, 6}}, S{1, Nested{2, 3}, 4, Nested{5, "a"}}, true},\n\t\t{S{1, Nested{2, 3}, 4, Nested{5, 6}}, S{1, Nested{2, 3}, 4, Nested{"a", "a"}}, true},\n\t\t{S{1, Nested{2, 3}, 4, Nested{5, 6}}, S{1, Nested{2, "a"}, 4, Nested{5, 6}}, true},\n\t\t{S{1, Nested{2, 3}, 4, Nested{5, 6}}, S{"a", Nested{2, 3}, 4, Nested{5, 6}}, false},\n\t\t{S{1, Nested{2, 3}, 4, Nested{5, 6}}, S{1, Nested{"a", 3}, 4, Nested{5, 6}}, false},\n\t\t{S{1, Nested{2, 3}, 4, Nested{5, 6}}, S2{1}, false},\n\t\t{1, S{1, Nested{2, 3}, 4, Nested{5, 6}}, false},\n\n\t\t{S3{&Nested{1, 2}, &Nested{3, 4}}, S3{&Nested{1, 2}, &Nested{3, 4}}, true},\n\t\t{S3{nil, &Nested{3, 4}}, S3{nil, &Nested{3, 4}}, true},\n\t\t{S3{&Nested{1, 2}, &Nested{3, 4}}, S3{&Nested{1, 2}, &Nested{3, "b"}}, true},\n\t\t{S3{&Nested{1, 2}, &Nested{3, 4}}, S3{&Nested{1, "a"}, &Nested{3, "b"}}, true},\n\t\t{S3{&Nested{1, 2}, &Nested{3, 4}}, S3{&Nested{"a", 2}, &Nested{3, 4}}, false},\n\t\t{S3{&Nested{1, 2}, &Nested{3, 4}}, S3{}, false},\n\t\t{S3{}, S3{}, true},\n\n\t\t{S4{[]*Nested{{1, 2}}}, S4{[]*Nested{{1, 2}}}, true},\n\t\t{S4{[]*Nested{{1, 2}}}, S4{[]*Nested{{1, 3}}}, true},\n\t\t{S4{[]*Nested{{1, 2}, {3, 4}}}, S4{[]*Nested{{1, "a"}, {3, "b"}}}, true},\n\t\t{S4{[]*Nested{{1, 2}, {3, 4}}}, S4{[]*Nested{{1, "a"}, {2, "b"}}}, false},\n\n\t\t{Nested{&intValue, 2}, Nested{&intValue, 2}, true},\n\t\t{Nested{&Nested{1, 2}, 3}, Nested{&Nested{1, "b"}, 3}, true},\n\t\t{Nested{&Nested{1, 2}, 3}, Nested{nil, 3}, false},\n\n\t\t{\n\t\t\tNested{map[interface{}]*Nested{nil: nil}, 2},\n\t\t\tNested{map[interface{}]*Nested{nil: nil}, 2},\n\t\t\ttrue,\n\t\t},\n\t\t{\n\t\t\tNested{map[interface{}]*Nested{"a": nil}, 2},\n\t\t\tNested{map[interface{}]*Nested{"a": nil}, 2},\n\t\t\ttrue,\n\t\t},\n\t\t{\n\t\t\tNested{map[interface{}]*Nested{"a": nil}, 2},\n\t\t\tNested{map[interface{}]*Nested{"a": {1, 2}}, 2},\n\t\t\tfalse,\n\t\t},\n\t\t{\n\t\t\tNested{map[interface{}]Nested{"a": {1, 2}, "b": {3, 4}}, 2},\n\t\t\tNested{map[interface{}]Nested{"a": {1, 5}, "b": {3, 7}}, 2},\n\t\t\ttrue,\n\t\t},\n\t\t{\n\t\t\tNested{map[interface{}]Nested{"a": {1, 2}, "b": {3, 4}}, 2},\n\t\t\tNested{map[interface{}]Nested{"a": {2, 2}, "b": {3, 4}}, 2},\n\t\t\tfalse,\n\t\t},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run(fmt.Sprintf("ObjectsExportedFieldsAreEqual(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tres := ObjectsExportedFieldsAreEqual(c.expected, c.actual)\n\n\t\t\tif res != c.result {\n\t\t\t\tt.Errorf("ObjectsExportedFieldsAreEqual(%#v, %#v) should return %#v", c.expected, c.actual, c.result)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestCopyExportedFields(t *testing.T) {\n\tt.Parallel()\n\n\tintValue := 1\n\n\tcases := []struct {\n\t\tinput    interface{}\n\t\texpected interface{}\n\t}{\n\t\t{\n\t\t\tinput:    Nested{"a", "b"},\n\t\t\texpected: Nested{"a", nil},\n\t\t},\n\t\t{\n\t\t\tinput:    Nested{&intValue, 2},\n\t\t\texpected: Nested{&intValue, nil},\n\t\t},\n\t\t{\n\t\t\tinput:    Nested{nil, 3},\n\t\t\texpected: Nested{nil, nil},\n\t\t},\n\t\t{\n\t\t\tinput:    S{1, Nested{2, 3}, 4, Nested{5, 6}},\n\t\t\texpected: S{1, Nested{2, nil}, nil, Nested{}},\n\t\t},\n\t\t{\n\t\t\tinput:    S3{},\n\t\t\texpected: S3{},\n\t\t},\n\t\t{\n\t\t\tinput:    S3{&Nested{1, 2}, &Nested{3, 4}},\n\t\t\texpected: S3{&Nested{1, nil}, &Nested{3, nil}},\n\t\t},\n\t\t{\n\t\t\tinput:    S3{Exported1: &Nested{"a", "b"}},\n\t\t\texpected: S3{Exported1: &Nested{"a", nil}},\n\t\t},\n\t\t{\n\t\t\tinput: S4{[]*Nested{\n\t\t\t\tnil,\n\t\t\t\t{1, 2},\n\t\t\t}},\n\t\t\texpected: S4{[]*Nested{\n\t\t\t\tnil,\n\t\t\t\t{1, nil},\n\t\t\t}},\n\t\t},\n\t\t{\n\t\t\tinput: S4{\n\t\t\t\t[]*Nested{\n\t\t\t\t\t{1, 2},\n\t\t\t\t},\n\t\t\t},\n\t\t\texpected: S4{\n\t\t\t\t[]*Nested{\n\t\t\t\t\t{1, nil},\n\t\t\t\t},\n\t\t\t},\n\t\t},\n\t\t{\n\t\t\tinput: S4{[]*Nested{\n\t\t\t\t{1, 2},\n\t\t\t\t{3, 4},\n\t\t\t}},\n\t\t\texpected: S4{[]*Nested{\n\t\t\t\t{1, nil},\n\t\t\t\t{3, nil},\n\t\t\t}},\n\t\t},\n\t\t{\n\t\t\tinput:    S5{Exported: Nested{"a", "b"}},\n\t\t\texpected: S5{Exported: Nested{"a", nil}},\n\t\t},\n\t\t{\n\t\t\tinput:    S6{"a", "b"},\n\t\t\texpected: S6{"a", ""},\n\t\t},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run("", func(t *testing.T) {\n\t\t\toutput := copyExportedFields(c.input)\n\t\t\tif !ObjectsAreEqualValues(c.expected, output) {\n\t\t\t\tt.Errorf("%#v, %#v should be equal", c.expected, output)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestEqualExportedValues(t *testing.T) {\n\tt.Parallel()\n\n\tcases := []struct {\n\t\tvalue1        interface{}\n\t\tvalue2        interface{}\n\t\texpectedEqual bool\n\t\texpectedFail  string\n\t}{\n\t\t{\n\t\t\tvalue1:        S{1, Nested{2, 3}, 4, Nested{5, 6}},\n\t\t\tvalue2:        S{1, Nested{2, nil}, nil, Nested{}},\n\t\t\texpectedEqual: true,\n\t\t},\n\t\t{\n\t\t\tvalue1:        S{1, Nested{2, 3}, 4, Nested{5, 6}},\n\t\t\tvalue2:        S{1, Nested{1, nil}, nil, Nested{}},\n\t\t\texpectedEqual: false,\n\t\t\texpectedFail: `\n\t            \tDiff:\n\t            \t--- Expected\n\t            \t+++ Actual\n\t            \t@@ -3,3 +3,3 @@\n\t            \t  Exported2: (assert.Nested) {\n\t            \t-  Exported: (int) 2,\n\t            \t+  Exported: (int) 1,\n\t            \t   notExported: (interface {}) <nil>`,\n\t\t},\n\t\t{\n\t\t\tvalue1:        S3{&Nested{1, 2}, &Nested{3, 4}},\n\t\t\tvalue2:        S3{&Nested{"a", 2}, &Nested{3, 4}},\n\t\t\texpectedEqual: false,\n\t\t\texpectedFail: `\n\t            \tDiff:\n\t            \t--- Expected\n\t            \t+++ Actual\n\t            \t@@ -2,3 +2,3 @@\n\t            \t  Exported1: (*assert.Nested)({\n\t            \t-  Exported: (int) 1,\n\t            \t+  Exported: (string) (len=1) "a",\n\t            \t   notExported: (interface {}) <nil>`,\n\t\t},\n\t\t{\n\t\t\tvalue1: S4{[]*Nested{\n\t\t\t\t{1, 2},\n\t\t\t\t{3, 4},\n\t\t\t}},\n\t\t\tvalue2: S4{[]*Nested{\n\t\t\t\t{1, "a"},\n\t\t\t\t{2, "b"},\n\t\t\t}},\n\t\t\texpectedEqual: false,\n\t\t\texpectedFail: `\n\t            \tDiff:\n\t            \t--- Expected\n\t            \t+++ Actual\n\t            \t@@ -7,3 +7,3 @@\n\t            \t   (*assert.Nested)({\n\t            \t-   Exported: (int) 3,\n\t            \t+   Exported: (int) 2,\n\t            \t    notExported: (interface {}) <nil>`,\n\t\t},\n\t\t{\n\t\t\tvalue1:        S{[2]int{1, 2}, Nested{2, 3}, 4, Nested{5, 6}},\n\t\t\tvalue2:        S{[2]int{1, 2}, Nested{2, nil}, nil, Nested{}},\n\t\t\texpectedEqual: true,\n\t\t},\n\t\t{\n\t\t\tvalue1:        &S{1, Nested{2, 3}, 4, Nested{5, 6}},\n\t\t\tvalue2:        &S{1, Nested{2, nil}, nil, Nested{}},\n\t\t\texpectedEqual: true,\n\t\t},\n\t\t{\n\t\t\tvalue1:        &S{1, Nested{2, 3}, 4, Nested{5, 6}},\n\t\t\tvalue2:        &S{1, Nested{1, nil}, nil, Nested{}},\n\t\t\texpectedEqual: false,\n\t\t\texpectedFail: `\n\t            \tDiff:\n\t            \t--- Expected\n\t            \t+++ Actual\n\t            \t@@ -3,3 +3,3 @@\n\t            \t  Exported2: (assert.Nested) {\n\t            \t-  Exported: (int) 2,\n\t            \t+  Exported: (int) 1,\n\t            \t   notExported: (interface {}) <nil>`,\n\t\t},\n\t\t{\n\t\t\tvalue1:        []int{1, 2},\n\t\t\tvalue2:        []int{1, 2},\n\t\t\texpectedEqual: true,\n\t\t},\n\t\t{\n\t\t\tvalue1:        []int{1, 2},\n\t\t\tvalue2:        []int{1, 3},\n\t\t\texpectedEqual: false,\n\t\t\texpectedFail: `\n\t            \tDiff:\n\t            \t--- Expected\n\t            \t+++ Actual\n\t            \t@@ -2,3 +2,3 @@\n\t            \t  (int) 1,\n\t            \t- (int) 2\n\t            \t+ (int) 3\n\t            \t }`,\n\t\t},\n\t\t{\n\t\t\tvalue1: []*Nested{\n\t\t\t\t{1, 2},\n\t\t\t\t{3, 4},\n\t\t\t},\n\t\t\tvalue2: []*Nested{\n\t\t\t\t{1, "a"},\n\t\t\t\t{3, "b"},\n\t\t\t},\n\t\t\texpectedEqual: true,\n\t\t},\n\t\t{\n\t\t\tvalue1: []*Nested{\n\t\t\t\t{1, 2},\n\t\t\t\t{3, 4},\n\t\t\t},\n\t\t\tvalue2: []*Nested{\n\t\t\t\t{1, "a"},\n\t\t\t\t{2, "b"},\n\t\t\t},\n\t\t\texpectedEqual: false,\n\t\t\texpectedFail: `\n\t            \tDiff:\n\t            \t--- Expected\n\t            \t+++ Actual\n\t            \t@@ -6,3 +6,3 @@\n\t            \t  (*assert.Nested)({\n\t            \t-  Exported: (int) 3,\n\t            \t+  Exported: (int) 2,\n\t            \t   notExported: (interface {}) <nil>`,\n\t\t},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run("", func(t *testing.T) {\n\t\t\tmockT := new(mockTestingT)\n\n\t\t\tactual := EqualExportedValues(mockT, c.value1, c.value2)\n\t\t\tif actual != c.expectedEqual {\n\t\t\t\tt.Errorf("Expected EqualExportedValues to be %t, but was %t", c.expectedEqual, actual)\n\t\t\t}\n\n\t\t\tactualFail := mockT.errorString()\n\t\t\tif !strings.Contains(actualFail, c.expectedFail) {\n\t\t\t\tt.Errorf("Contains failure should include %q but was %q", c.expectedFail, actualFail)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestImplements(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !Implements(mockT, (*AssertionTesterInterface)(nil), new(AssertionTesterConformingObject)) {\n\t\tt.Error("Implements method should return true: AssertionTesterConformingObject implements AssertionTesterInterface")\n\t}\n\tif Implements(mockT, (*AssertionTesterInterface)(nil), new(AssertionTesterNonConformingObject)) {\n\t\tt.Error("Implements method should return false: AssertionTesterNonConformingObject does not implements AssertionTesterInterface")\n\t}\n\tif Implements(mockT, (*AssertionTesterInterface)(nil), nil) {\n\t\tt.Error("Implements method should return false: nil does not implement AssertionTesterInterface")\n\t}\n}\n\nfunc TestNotImplements(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !NotImplements(mockT, (*AssertionTesterInterface)(nil), new(AssertionTesterNonConformingObject)) {\n\t\tt.Error("NotImplements method should return true: AssertionTesterNonConformingObject does not implement AssertionTesterInterface")\n\t}\n\tif NotImplements(mockT, (*AssertionTesterInterface)(nil), new(AssertionTesterConformingObject)) {\n\t\tt.Error("NotImplements method should return false: AssertionTesterConformingObject implements AssertionTesterInterface")\n\t}\n\tif NotImplements(mockT, (*AssertionTesterInterface)(nil), nil) {\n\t\tt.Error("NotImplements method should return false: nil can\'t be checked to be implementing AssertionTesterInterface or not")\n\t}\n}\n\nfunc TestIsType(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !IsType(mockT, new(AssertionTesterConformingObject), new(AssertionTesterConformingObject)) {\n\t\tt.Error("IsType should return true: AssertionTesterConformingObject is the same type as AssertionTesterConformingObject")\n\t}\n\tif IsType(mockT, new(AssertionTesterConformingObject), new(AssertionTesterNonConformingObject)) {\n\t\tt.Error("IsType should return false: AssertionTesterConformingObject is not the same type as AssertionTesterNonConformingObject")\n\t}\n}\n\nfunc TestNotIsType(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !IsNotType(mockT, new(AssertionTesterConformingObject), new(AssertionTesterNonConformingObject)) {\n\t\tt.Error("NotIsType should return true: AssertionTesterConformingObject is not the same type as AssertionTesterNonConformingObject")\n\t}\n\tif IsNotType(mockT, new(AssertionTesterConformingObject), new(AssertionTesterConformingObject)) {\n\t\tt.Error("NotIsType should return false: AssertionTesterConformingObject is the same type as AssertionTesterConformingObject")\n\t}\n}\n\nfunc TestEqual(t *testing.T) {\n\tt.Parallel()\n\n\ttype myType string\n\n\tmockT := new(testing.T)\n\tvar m map[string]interface{}\n\n\tcases := []struct {\n\t\texpected interface{}\n\t\tactual   interface{}\n\t\tresult   bool\n\t\tremark   string\n\t}{\n\t\t{"Hello World", "Hello World", true, ""},\n\t\t{123, 123, true, ""},\n\t\t{123.5, 123.5, true, ""},\n\t\t{[]byte("Hello World"), []byte("Hello World"), true, ""},\n\t\t{nil, nil, true, ""},\n\t\t{int32(123), int32(123), true, ""},\n\t\t{uint64(123), uint64(123), true, ""},\n\t\t{myType("1"), myType("1"), true, ""},\n\t\t{&struct{}{}, &struct{}{}, true, "pointer equality is based on equality of underlying value"},\n\n\t\t// Not expected to be equal\n\t\t{m["bar"], "something", false, ""},\n\t\t{myType("1"), myType("2"), false, ""},\n\n\t\t// A case that might be confusing, especially with numeric literals\n\t\t{10, uint(10), false, ""},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run(fmt.Sprintf("Equal(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tres := Equal(mockT, c.expected, c.actual)\n\n\t\t\tif res != c.result {\n\t\t\t\tt.Errorf("Equal(%#v, %#v) should return %#v: %s", c.expected, c.actual, c.result, c.remark)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc ptr(i int) *int {\n\treturn &i\n}\n\nfunc TestSame(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif Same(mockT, ptr(1), ptr(1)) {\n\t\tt.Error("Same should return false")\n\t}\n\tif Same(mockT, 1, 1) {\n\t\tt.Error("Same should return false")\n\t}\n\tp := ptr(2)\n\tif Same(mockT, p, *p) {\n\t\tt.Error("Same should return false")\n\t}\n\tif !Same(mockT, p, p) {\n\t\tt.Error("Same should return true")\n\t}\n}\n\nfunc TestNotSame(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !NotSame(mockT, ptr(1), ptr(1)) {\n\t\tt.Error("NotSame should return true; different pointers")\n\t}\n\tif !NotSame(mockT, 1, 1) {\n\t\tt.Error("NotSame should return true; constant inputs")\n\t}\n\tp := ptr(2)\n\tif !NotSame(mockT, p, *p) {\n\t\tt.Error("NotSame should return true; mixed-type inputs")\n\t}\n\tif NotSame(mockT, p, p) {\n\t\tt.Error("NotSame should return false")\n\t}\n}\n\nfunc Test_samePointers(t *testing.T) {\n\tt.Parallel()\n\n\tp := ptr(2)\n\n\ttype args struct {\n\t\tfirst  interface{}\n\t\tsecond interface{}\n\t}\n\ttests := []struct {\n\t\tname string\n\t\targs args\n\t\tsame BoolAssertionFunc\n\t\tok   BoolAssertionFunc\n\t}{\n\t\t{\n\t\t\tname: "1 != 2",\n\t\t\targs: args{first: 1, second: 2},\n\t\t\tsame: False,\n\t\t\tok:   False,\n\t\t},\n\t\t{\n\t\t\tname: "1 != 1 (not same ptr)",\n\t\t\targs: args{first: 1, second: 1},\n\t\t\tsame: False,\n\t\t\tok:   False,\n\t\t},\n\t\t{\n\t\t\tname: "ptr(1) == ptr(1)",\n\t\t\targs: args{first: p, second: p},\n\t\t\tsame: True,\n\t\t\tok:   True,\n\t\t},\n\t\t{\n\t\t\tname: "int(1) != float32(1)",\n\t\t\targs: args{first: int(1), second: float32(1)},\n\t\t\tsame: False,\n\t\t\tok:   False,\n\t\t},\n\t\t{\n\t\t\tname: "array != slice",\n\t\t\targs: args{first: [2]int{1, 2}, second: []int{1, 2}},\n\t\t\tsame: False,\n\t\t\tok:   False,\n\t\t},\n\t\t{\n\t\t\tname: "non-pointer vs pointer (1 != ptr(2))",\n\t\t\targs: args{first: 1, second: p},\n\t\t\tsame: False,\n\t\t\tok:   False,\n\t\t},\n\t\t{\n\t\t\tname: "pointer vs non-pointer (ptr(2) != 1)",\n\t\t\targs: args{first: p, second: 1},\n\t\t\tsame: False,\n\t\t\tok:   False,\n\t\t},\n\t}\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\tsame, ok := samePointers(tt.args.first, tt.args.second)\n\t\t\ttt.same(t, same)\n\t\t\ttt.ok(t, ok)\n\t\t})\n\t}\n}\n\n// bufferT implements TestingT. Its implementation of Errorf writes the output that would be produced by\n// testing.T.Errorf to an internal bytes.Buffer.\ntype bufferT struct {\n\tbuf bytes.Buffer\n}\n\n// Helper is like [testing.T.Helper] but does nothing.\nfunc (bufferT) Helper() {}\n\nfunc (t *bufferT) Errorf(format string, args ...interface{}) {\n\t// implementation of decorate is copied from testing.T\n\tdecorate := func(s string) string {\n\t\t_, file, line, ok := runtime.Caller(3) // decorate + log + public function.\n\t\tif ok {\n\t\t\t// Truncate file name at last file name separator.\n\t\t\tif index := strings.LastIndex(file, "/"); index >= 0 {\n\t\t\t\tfile = file[index+1:]\n\t\t\t} else if index = strings.LastIndex(file, "\\\\"); index >= 0 {\n\t\t\t\tfile = file[index+1:]\n\t\t\t}\n\t\t} else {\n\t\t\tfile = "???"\n\t\t\tline = 1\n\t\t}\n\t\tbuf := new(bytes.Buffer)\n\t\t// Every line is indented at least one tab.\n\t\tbuf.WriteByte(\'\\t\')\n\t\tfmt.Fprintf(buf, "%s:%d: ", file, line)\n\t\tlines := strings.Split(s, "\\n")\n\t\tif l := len(lines); l > 1 && lines[l-1] == "" {\n\t\t\tlines = lines[:l-1]\n\t\t}\n\t\tfor i, line := range lines {\n\t\t\tif i > 0 {\n\t\t\t\t// Second and subsequent lines are indented an extra tab.\n\t\t\t\tbuf.WriteString("\\n\\t\\t")\n\t\t\t}\n\t\t\tbuf.WriteString(line)\n\t\t}\n\t\tbuf.WriteByte(\'\\n\')\n\t\treturn buf.String()\n\t}\n\tt.buf.WriteString(decorate(fmt.Sprintf(format, args...)))\n}\n\nfunc TestStringEqual(t *testing.T) {\n\tt.Parallel()\n\n\tfor i, currCase := range []struct {\n\t\tequalWant  string\n\t\tequalGot   string\n\t\tmsgAndArgs []interface{}\n\t\twant       string\n\t}{\n\t\t{equalWant: "hi, \\nmy name is", equalGot: "what,\\nmy name is", want: "\\tassertions.go:\\\\d+: \\n\\t+Error Trace:\\t\\n\\t+Error:\\\\s+Not equal:\\\\s+\\n\\\\s+expected: \\"hi, \\\\\\\\nmy name is\\"\\n\\\\s+actual\\\\s+: \\"what,\\\\\\\\nmy name is\\"\\n\\\\s+Diff:\\n\\\\s+-+ Expected\\n\\\\s+\\\\++ Actual\\n\\\\s+@@ -1,2 \\\\+1,2 @@\\n\\\\s+-hi, \\n\\\\s+\\\\+what,\\n\\\\s+my name is"},\n\t} {\n\t\tmockT := &bufferT{}\n\t\tEqual(mockT, currCase.equalWant, currCase.equalGot, currCase.msgAndArgs...)\n\t\tRegexp(t, regexp.MustCompile(currCase.want), mockT.buf.String(), "Case %d", i)\n\t}\n}\n\nfunc TestEqualFormatting(t *testing.T) {\n\tt.Parallel()\n\n\tfor i, currCase := range []struct {\n\t\tequalWant  string\n\t\tequalGot   string\n\t\tmsgAndArgs []interface{}\n\t\twant       string\n\t}{\n\t\t{equalWant: "want", equalGot: "got", want: "\\tassertions.go:\\\\d+: \\n\\t+Error Trace:\\t\\n\\t+Error:\\\\s+Not equal:\\\\s+\\n\\\\s+expected: \\"want\\"\\n\\\\s+actual\\\\s+: \\"got\\"\\n\\\\s+Diff:\\n\\\\s+-+ Expected\\n\\\\s+\\\\++ Actual\\n\\\\s+@@ -1 \\\\+1 @@\\n\\\\s+-want\\n\\\\s+\\\\+got\\n"},\n\t\t{equalWant: "want", equalGot: "got", msgAndArgs: []interface{}{"hello, %v!", "world"}, want: "\\tassertions.go:[0-9]+: \\n\\t+Error Trace:\\t\\n\\t+Error:\\\\s+Not equal:\\\\s+\\n\\\\s+expected: \\"want\\"\\n\\\\s+actual\\\\s+: \\"got\\"\\n\\\\s+Diff:\\n\\\\s+-+ Expected\\n\\\\s+\\\\++ Actual\\n\\\\s+@@ -1 \\\\+1 @@\\n\\\\s+-want\\n\\\\s+\\\\+got\\n\\\\s+Messages:\\\\s+hello, world!\\n"},\n\t\t{equalWant: "want", equalGot: "got", msgAndArgs: []interface{}{123}, want: "\\tassertions.go:[0-9]+: \\n\\t+Error Trace:\\t\\n\\t+Error:\\\\s+Not equal:\\\\s+\\n\\\\s+expected: \\"want\\"\\n\\\\s+actual\\\\s+: \\"got\\"\\n\\\\s+Diff:\\n\\\\s+-+ Expected\\n\\\\s+\\\\++ Actual\\n\\\\s+@@ -1 \\\\+1 @@\\n\\\\s+-want\\n\\\\s+\\\\+got\\n\\\\s+Messages:\\\\s+123\\n"},\n\t\t{equalWant: "want", equalGot: "got", msgAndArgs: []interface{}{struct{ a string }{"hello"}}, want: "\\tassertions.go:[0-9]+: \\n\\t+Error Trace:\\t\\n\\t+Error:\\\\s+Not equal:\\\\s+\\n\\\\s+expected: \\"want\\"\\n\\\\s+actual\\\\s+: \\"got\\"\\n\\\\s+Diff:\\n\\\\s+-+ Expected\\n\\\\s+\\\\++ Actual\\n\\\\s+@@ -1 \\\\+1 @@\\n\\\\s+-want\\n\\\\s+\\\\+got\\n\\\\s+Messages:\\\\s+{a:hello}\\n"},\n\t} {\n\t\tmockT := &bufferT{}\n\t\tEqual(mockT, currCase.equalWant, currCase.equalGot, currCase.msgAndArgs...)\n\t\tRegexp(t, regexp.MustCompile(currCase.want), mockT.buf.String(), "Case %d", i)\n\t}\n}\n\nfunc TestFormatUnequalValues(t *testing.T) {\n\tt.Parallel()\n\n\texpected, actual := formatUnequalValues("foo", "bar")\n\tEqual(t, `"foo"`, expected, "value should not include type")\n\tEqual(t, `"bar"`, actual, "value should not include type")\n\n\texpected, actual = formatUnequalValues(123, 123)\n\tEqual(t, `123`, expected, "value should not include type")\n\tEqual(t, `123`, actual, "value should not include type")\n\n\texpected, actual = formatUnequalValues(int64(123), int32(123))\n\tEqual(t, `int64(123)`, expected, "value should include type")\n\tEqual(t, `int32(123)`, actual, "value should include type")\n\n\texpected, actual = formatUnequalValues(int64(123), nil)\n\tEqual(t, `int64(123)`, expected, "value should include type")\n\tEqual(t, `<nil>(<nil>)`, actual, "value should include type")\n\n\ttype testStructType struct {\n\t\tVal string\n\t}\n\n\texpected, actual = formatUnequalValues(&testStructType{Val: "test"}, &testStructType{Val: "test"})\n\tEqual(t, `&assert.testStructType{Val:"test"}`, expected, "value should not include type annotation")\n\tEqual(t, `&assert.testStructType{Val:"test"}`, actual, "value should not include type annotation")\n}\n\nfunc TestNotNil(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !NotNil(mockT, new(AssertionTesterConformingObject)) {\n\t\tt.Error("NotNil should return true: object is not nil")\n\t}\n\tif NotNil(mockT, nil) {\n\t\tt.Error("NotNil should return false: object is nil")\n\t}\n\tif NotNil(mockT, (*struct{})(nil)) {\n\t\tt.Error("NotNil should return false: object is (*struct{})(nil)")\n\t}\n}\n\nfunc TestNil(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !Nil(mockT, nil) {\n\t\tt.Error("Nil should return true: object is nil")\n\t}\n\tif !Nil(mockT, (*struct{})(nil)) {\n\t\tt.Error("Nil should return true: object is (*struct{})(nil)")\n\t}\n\tif Nil(mockT, new(AssertionTesterConformingObject)) {\n\t\tt.Error("Nil should return false: object is not nil")\n\t}\n}\n\nfunc TestTrue(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !True(mockT, true) {\n\t\tt.Error("True should return true")\n\t}\n\tif True(mockT, false) {\n\t\tt.Error("True should return false")\n\t}\n}\n\nfunc TestFalse(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !False(mockT, false) {\n\t\tt.Error("False should return true")\n\t}\n\tif False(mockT, true) {\n\t\tt.Error("False should return false")\n\t}\n}\n\nfunc TestExactly(t *testing.T) {\n\tt.Parallel()\n\tmockT := new(testing.T)\n\n\ta := float32(1)\n\tb := float64(1)\n\tc := float32(1)\n\td := float32(2)\n\tcases := []struct {\n\t\texpected interface{}\n\t\tactual   interface{}\n\t\tresult   bool\n\t}{\n\t\t{a, b, false},\n\t\t{a, d, false},\n\t\t{a, c, true},\n\t\t{nil, a, false},\n\t\t{a, nil, false},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run(fmt.Sprintf("Exactly(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tres := Exactly(mockT, c.expected, c.actual)\n\n\t\t\tif res != c.result {\n\t\t\t\tt.Errorf("Exactly(%#v, %#v) should return %#v", c.expected, c.actual, c.result)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestNotEqual(t *testing.T) {\n\tt.Parallel()\n\tmockT := new(testing.T)\n\n\tcases := []struct {\n\t\texpected interface{}\n\t\tactual   interface{}\n\t\tresult   bool\n\t}{\n\t\t// cases that are expected not to match\n\t\t{"Hello World", "Hello World!", true},\n\t\t{123, 1234, true},\n\t\t{123.5, 123.55, true},\n\t\t{[]byte("Hello World"), []byte("Hello World!"), true},\n\t\t{nil, new(AssertionTesterConformingObject), true},\n\n\t\t// cases that are expected to match\n\t\t{nil, nil, false},\n\t\t{"Hello World", "Hello World", false},\n\t\t{123, 123, false},\n\t\t{123.5, 123.5, false},\n\t\t{[]byte("Hello World"), []byte("Hello World"), false},\n\t\t{new(AssertionTesterConformingObject), new(AssertionTesterConformingObject), false},\n\t\t{&struct{}{}, &struct{}{}, false},\n\t\t{func() int { return 23 }, func() int { return 24 }, false},\n\t\t// A case that might be confusing, especially with numeric literals\n\t\t{int(10), uint(10), true},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run(fmt.Sprintf("NotEqual(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tres := NotEqual(mockT, c.expected, c.actual)\n\n\t\t\tif res != c.result {\n\t\t\t\tt.Errorf("NotEqual(%#v, %#v) should return %#v", c.expected, c.actual, c.result)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestEqualValuesAndNotEqualValues(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tcases := []struct {\n\t\texpected       interface{}\n\t\tactual         interface{}\n\t\tnotEqualResult bool // result for NotEqualValues\n\t}{\n\t\t// cases that are expected not to match\n\t\t{"Hello World", "Hello World!", true},\n\t\t{123, 1234, true},\n\t\t{123.5, 123.55, true},\n\t\t{[]byte("Hello World"), []byte("Hello World!"), true},\n\t\t{nil, new(AssertionTesterConformingObject), true},\n\n\t\t// cases that are expected to match\n\t\t{nil, nil, false},\n\t\t{"Hello World", "Hello World", false},\n\t\t{123, 123, false},\n\t\t{123.5, 123.5, false},\n\t\t{[]byte("Hello World"), []byte("Hello World"), false},\n\t\t{new(AssertionTesterConformingObject), new(AssertionTesterConformingObject), false},\n\t\t{&struct{}{}, &struct{}{}, false},\n\n\t\t// Different behavior from NotEqual()\n\t\t{func() int { return 23 }, func() int { return 24 }, true},\n\t\t{int(10), int(11), true},\n\t\t{int(10), uint(10), false},\n\n\t\t{struct{}{}, struct{}{}, false},\n\t}\n\n\tfor _, c := range cases {\n\t\t// Test NotEqualValues\n\t\tt.Run(fmt.Sprintf("NotEqualValues(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tres := NotEqualValues(mockT, c.expected, c.actual)\n\n\t\t\tif res != c.notEqualResult {\n\t\t\t\tt.Errorf("NotEqualValues(%#v, %#v) should return %#v", c.expected, c.actual, c.notEqualResult)\n\t\t\t}\n\t\t})\n\n\t\t// Test EqualValues (inverse of NotEqualValues)\n\t\tt.Run(fmt.Sprintf("EqualValues(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\texpectedEqualResult := !c.notEqualResult // EqualValues should return opposite of NotEqualValues\n\t\t\tres := EqualValues(mockT, c.expected, c.actual)\n\n\t\t\tif res != expectedEqualResult {\n\t\t\t\tt.Errorf("EqualValues(%#v, %#v) should return %#v", c.expected, c.actual, expectedEqualResult)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestContainsNotContains(t *testing.T) {\n\tt.Parallel()\n\n\ttype A struct {\n\t\tName, Value string\n\t}\n\tlist := []string{"Foo", "Bar"}\n\n\tcomplexList := []*A{\n\t\t{"b", "c"},\n\t\t{"d", "e"},\n\t\t{"g", "h"},\n\t\t{"j", "k"},\n\t}\n\tsimpleMap := map[interface{}]interface{}{"Foo": "Bar"}\n\tvar zeroMap map[interface{}]interface{}\n\n\tcases := []struct {\n\t\texpected interface{}\n\t\tactual   interface{}\n\t\tresult   bool\n\t}{\n\t\t{"Hello World", "Hello", true},\n\t\t{"Hello World", "Salut", false},\n\t\t{list, "Bar", true},\n\t\t{list, "Salut", false},\n\t\t{complexList, &A{"g", "h"}, true},\n\t\t{complexList, &A{"g", "e"}, false},\n\t\t{simpleMap, "Foo", true},\n\t\t{simpleMap, "Bar", false},\n\t\t{zeroMap, "Bar", false},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run(fmt.Sprintf("Contains(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tmockT := new(testing.T)\n\t\t\tres := Contains(mockT, c.expected, c.actual)\n\n\t\t\tif res != c.result {\n\t\t\t\tif res {\n\t\t\t\t\tt.Errorf("Contains(%#v, %#v) should return true:\\n\\t%#v contains %#v", c.expected, c.actual, c.expected, c.actual)\n\t\t\t\t} else {\n\t\t\t\t\tt.Errorf("Contains(%#v, %#v) should return false:\\n\\t%#v does not contain %#v", c.expected, c.actual, c.expected, c.actual)\n\t\t\t\t}\n\t\t\t}\n\t\t})\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run(fmt.Sprintf("NotContains(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tmockT := new(testing.T)\n\t\t\tres := NotContains(mockT, c.expected, c.actual)\n\n\t\t\t// NotContains should be inverse of Contains. If it\'s not, something is wrong\n\t\t\tif res == Contains(mockT, c.expected, c.actual) {\n\t\t\t\tif res {\n\t\t\t\t\tt.Errorf("NotContains(%#v, %#v) should return true:\\n\\t%#v does not contains %#v", c.expected, c.actual, c.expected, c.actual)\n\t\t\t\t} else {\n\t\t\t\t\tt.Errorf("NotContains(%#v, %#v) should return false:\\n\\t%#v contains %#v", c.expected, c.actual, c.expected, c.actual)\n\t\t\t\t}\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestContainsNotContainsFailMessage(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(mockTestingT)\n\n\ttype nonContainer struct {\n\t\tValue string\n\t}\n\n\tcases := []struct {\n\t\tassertion func(t TestingT, s, contains interface{}, msgAndArgs ...interface{}) bool\n\t\tcontainer interface{}\n\t\tinstance  interface{}\n\t\texpected  string\n\t}{\n\t\t{\n\t\t\tassertion: Contains,\n\t\t\tcontainer: "Hello World",\n\t\t\tinstance:  errors.New("Hello"),\n\t\t\texpected:  "\\"Hello World\\" does not contain &errors.errorString{s:\\"Hello\\"}",\n\t\t},\n\t\t{\n\t\t\tassertion: Contains,\n\t\t\tcontainer: map[string]int{"one": 1},\n\t\t\tinstance:  "two",\n\t\t\texpected:  "map[string]int{\\"one\\":1} does not contain \\"two\\"\\n",\n\t\t},\n\t\t{\n\t\t\tassertion: NotContains,\n\t\t\tcontainer: map[string]int{"one": 1},\n\t\t\tinstance:  "one",\n\t\t\texpected:  "map[string]int{\\"one\\":1} should not contain \\"one\\"",\n\t\t},\n\t\t{\n\t\t\tassertion: Contains,\n\t\t\tcontainer: nonContainer{Value: "Hello"},\n\t\t\tinstance:  "Hello",\n\t\t\texpected:  "assert.nonContainer{Value:\\"Hello\\"} could not be applied builtin len()\\n",\n\t\t},\n\t\t{\n\t\t\tassertion: NotContains,\n\t\t\tcontainer: nonContainer{Value: "Hello"},\n\t\t\tinstance:  "Hello",\n\t\t\texpected:  "assert.nonContainer{Value:\\"Hello\\"} could not be applied builtin len()\\n",\n\t\t},\n\t}\n\tfor _, c := range cases {\n\t\tname := filepath.Base(runtime.FuncForPC(reflect.ValueOf(c.assertion).Pointer()).Name())\n\t\tt.Run(fmt.Sprintf("%v(%T, %T)", name, c.container, c.instance), func(t *testing.T) {\n\t\t\tc.assertion(mockT, c.container, c.instance)\n\t\t\tactualFail := mockT.errorString()\n\t\t\tif !strings.Contains(actualFail, c.expected) {\n\t\t\t\tt.Errorf("Contains failure should include %q but was %q", c.expected, actualFail)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestContainsNotContainsOnNilValue(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(mockTestingT)\n\n\tContains(mockT, nil, "key")\n\texpectedFail := "<nil> could not be applied builtin len()"\n\tactualFail := mockT.errorString()\n\tif !strings.Contains(actualFail, expectedFail) {\n\t\tt.Errorf("Contains failure should include %q but was %q", expectedFail, actualFail)\n\t}\n\n\tNotContains(mockT, nil, "key")\n\tif !strings.Contains(actualFail, expectedFail) {\n\t\tt.Errorf("Contains failure should include %q but was %q", expectedFail, actualFail)\n\t}\n}\n\nfunc TestSubsetNotSubset(t *testing.T) {\n\tt.Parallel()\n\n\tcases := []struct {\n\t\tlist    interface{}\n\t\tsubset  interface{}\n\t\tresult  bool\n\t\tmessage string\n\t}{\n\t\t// cases that are expected to contain\n\t\t{[]int{1, 2, 3}, nil, true, `nil is the empty set which is a subset of every set`},\n\t\t{[]int{1, 2, 3}, []int{}, true, `[] is a subset of [\'\\x01\' \'\\x02\' \'\\x03\']`},\n\t\t{[]int{1, 2, 3}, []int{1, 2}, true, `[\'\\x01\' \'\\x02\'] is a subset of [\'\\x01\' \'\\x02\' \'\\x03\']`},\n\t\t{[]int{1, 2, 3}, []int{1, 2, 3}, true, `[\'\\x01\' \'\\x02\' \'\\x03\'] is a subset of [\'\\x01\' \'\\x02\' \'\\x03\']`},\n\t\t{[]string{"hello", "world"}, []string{"hello"}, true, `["hello"] is a subset of ["hello" "world"]`},\n\t\t{map[string]string{\n\t\t\t"a": "x",\n\t\t\t"c": "z",\n\t\t\t"b": "y",\n\t\t}, map[string]string{\n\t\t\t"a": "x",\n\t\t\t"b": "y",\n\t\t}, true, `map["a":"x" "b":"y"] is a subset of map["a":"x" "b":"y" "c":"z"]`},\n\t\t{[]string{"a", "b", "c"}, map[string]int{"a": 1, "c": 3}, true, `map["a":\'\\x01\' "c":\'\\x03\'] is a subset of ["a" "b" "c"]`},\n\n\t\t// cases that are expected not to contain\n\t\t{[]string{"hello", "world"}, []string{"hello", "testify"}, false, `[]string{"hello", "world"} does not contain "testify"`},\n\t\t{[]int{1, 2, 3}, []int{4, 5}, false, `[]int{1, 2, 3} does not contain 4`},\n\t\t{[]int{1, 2, 3}, []int{1, 5}, false, `[]int{1, 2, 3} does not contain 5`},\n\t\t{map[string]string{\n\t\t\t"a": "x",\n\t\t\t"c": "z",\n\t\t\t"b": "y",\n\t\t}, map[string]string{\n\t\t\t"a": "x",\n\t\t\t"b": "z",\n\t\t}, false, `map[string]string{"a":"x", "b":"y", "c":"z"} does not contain map[string]string{"a":"x", "b":"z"}`},\n\t\t{map[string]string{\n\t\t\t"a": "x",\n\t\t\t"b": "y",\n\t\t}, map[string]string{\n\t\t\t"a": "x",\n\t\t\t"b": "y",\n\t\t\t"c": "z",\n\t\t}, false, `map[string]string{"a":"x", "b":"y"} does not contain map[string]string{"a":"x", "b":"y", "c":"z"}`},\n\t\t{[]string{"a", "b", "c"}, map[string]int{"c": 3, "d": 4}, false, `[]string{"a", "b", "c"} does not contain "d"`},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run("SubSet: "+c.message, func(t *testing.T) {\n\t\t\tmockT := new(mockTestingT)\n\t\t\tres := Subset(mockT, c.list, c.subset)\n\n\t\t\tif res != c.result {\n\t\t\t\tt.Errorf("Subset should return %t: %s", c.result, c.message)\n\t\t\t}\n\t\t\tif !c.result {\n\t\t\t\texpectedFail := c.message\n\t\t\t\tactualFail := mockT.errorString()\n\t\t\t\tif !strings.Contains(actualFail, expectedFail) {\n\t\t\t\t\tt.Log(actualFail)\n\t\t\t\t\tt.Errorf("Subset failure should contain %q but was %q", expectedFail, actualFail)\n\t\t\t\t}\n\t\t\t}\n\t\t})\n\t}\n\tfor _, c := range cases {\n\t\tt.Run("NotSubSet: "+c.message, func(t *testing.T) {\n\t\t\tmockT := new(mockTestingT)\n\t\t\tres := NotSubset(mockT, c.list, c.subset)\n\n\t\t\t// NotSubset should match the inverse of Subset. If it doesn\'t, something is wrong\n\t\t\tif res == Subset(mockT, c.list, c.subset) {\n\t\t\t\tt.Errorf("NotSubset should return %t: %s", !c.result, c.message)\n\t\t\t}\n\t\t\tif c.result {\n\t\t\t\texpectedFail := c.message\n\t\t\t\tactualFail := mockT.errorString()\n\t\t\t\tif !strings.Contains(actualFail, expectedFail) {\n\t\t\t\t\tt.Log(actualFail)\n\t\t\t\t\tt.Errorf("NotSubset failure should contain %q but was %q", expectedFail, actualFail)\n\t\t\t\t}\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestNotSubsetNil(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tNotSubset(mockT, []string{"foo"}, nil)\n\tif !mockT.Failed() {\n\t\tt.Error("NotSubset on nil set should have failed the test")\n\t}\n}\n\nfunc Test_containsElement(t *testing.T) {\n\tt.Parallel()\n\n\tlist1 := []string{"Foo", "Bar"}\n\tlist2 := []int{1, 2}\n\tsimpleMap := map[interface{}]interface{}{"Foo": "Bar"}\n\n\tok, found := containsElement("Hello World", "World")\n\tTrue(t, ok)\n\tTrue(t, found)\n\n\tok, found = containsElement(list1, "Foo")\n\tTrue(t, ok)\n\tTrue(t, found)\n\n\tok, found = containsElement(list1, "Bar")\n\tTrue(t, ok)\n\tTrue(t, found)\n\n\tok, found = containsElement(list2, 1)\n\tTrue(t, ok)\n\tTrue(t, found)\n\n\tok, found = containsElement(list2, 2)\n\tTrue(t, ok)\n\tTrue(t, found)\n\n\tok, found = containsElement(list1, "Foo!")\n\tTrue(t, ok)\n\tFalse(t, found)\n\n\tok, found = containsElement(list2, 3)\n\tTrue(t, ok)\n\tFalse(t, found)\n\n\tok, found = containsElement(list2, "1")\n\tTrue(t, ok)\n\tFalse(t, found)\n\n\tok, found = containsElement(simpleMap, "Foo")\n\tTrue(t, ok)\n\tTrue(t, found)\n\n\tok, found = containsElement(simpleMap, "Bar")\n\tTrue(t, ok)\n\tFalse(t, found)\n\n\tok, found = containsElement(1433, "1")\n\tFalse(t, ok)\n\tFalse(t, found)\n}\n\nfunc TestElementsMatch(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tcases := []struct {\n\t\texpected interface{}\n\t\tactual   interface{}\n\t\tresult   bool\n\t}{\n\t\t// matching\n\t\t{nil, nil, true},\n\n\t\t{nil, nil, true},\n\t\t{[]int{}, []int{}, true},\n\t\t{[]int{1}, []int{1}, true},\n\t\t{[]int{1, 1}, []int{1, 1}, true},\n\t\t{[]int{1, 2}, []int{1, 2}, true},\n\t\t{[]int{1, 2}, []int{2, 1}, true},\n\t\t{[2]int{1, 2}, [2]int{2, 1}, true},\n\t\t{[]string{"hello", "world"}, []string{"world", "hello"}, true},\n\t\t{[]string{"hello", "hello"}, []string{"hello", "hello"}, true},\n\t\t{[]string{"hello", "hello", "world"}, []string{"hello", "world", "hello"}, true},\n\t\t{[3]string{"hello", "hello", "world"}, [3]string{"hello", "world", "hello"}, true},\n\t\t{[]int{}, nil, true},\n\n\t\t// not matching\n\t\t{[]int{1}, []int{1, 1}, false},\n\t\t{[]int{1, 2}, []int{2, 2}, false},\n\t\t{[]string{"hello", "hello"}, []string{"hello"}, false},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run(fmt.Sprintf("ElementsMatch(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tres := ElementsMatch(mockT, c.actual, c.expected)\n\n\t\t\tif res != c.result {\n\t\t\t\tt.Errorf("ElementsMatch(%#v, %#v) should return %v", c.actual, c.expected, c.result)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestDiffLists(t *testing.T) {\n\tt.Parallel()\n\n\ttests := []struct {\n\t\tname   string\n\t\tlistA  interface{}\n\t\tlistB  interface{}\n\t\textraA []interface{}\n\t\textraB []interface{}\n\t}{\n\t\t{\n\t\t\tname:   "equal empty",\n\t\t\tlistA:  []string{},\n\t\t\tlistB:  []string{},\n\t\t\textraA: nil,\n\t\t\textraB: nil,\n\t\t},\n\t\t{\n\t\t\tname:   "equal same order",\n\t\t\tlistA:  []string{"hello", "world"},\n\t\t\tlistB:  []string{"hello", "world"},\n\t\t\textraA: nil,\n\t\t\textraB: nil,\n\t\t},\n\t\t{\n\t\t\tname:   "equal different order",\n\t\t\tlistA:  []string{"hello", "world"},\n\t\t\tlistB:  []string{"world", "hello"},\n\t\t\textraA: nil,\n\t\t\textraB: nil,\n\t\t},\n\t\t{\n\t\t\tname:   "extra A",\n\t\t\tlistA:  []string{"hello", "hello", "world"},\n\t\t\tlistB:  []string{"hello", "world"},\n\t\t\textraA: []interface{}{"hello"},\n\t\t\textraB: nil,\n\t\t},\n\t\t{\n\t\t\tname:   "extra A twice",\n\t\t\tlistA:  []string{"hello", "hello", "hello", "world"},\n\t\t\tlistB:  []string{"hello", "world"},\n\t\t\textraA: []interface{}{"hello", "hello"},\n\t\t\textraB: nil,\n\t\t},\n\t\t{\n\t\t\tname:   "extra B",\n\t\t\tlistA:  []string{"hello", "world"},\n\t\t\tlistB:  []string{"hello", "hello", "world"},\n\t\t\textraA: nil,\n\t\t\textraB: []interface{}{"hello"},\n\t\t},\n\t\t{\n\t\t\tname:   "extra B twice",\n\t\t\tlistA:  []string{"hello", "world"},\n\t\t\tlistB:  []string{"hello", "hello", "world", "hello"},\n\t\t\textraA: nil,\n\t\t\textraB: []interface{}{"hello", "hello"},\n\t\t},\n\t\t{\n\t\t\tname:   "integers 1",\n\t\t\tlistA:  []int{1, 2, 3, 4, 5},\n\t\t\tlistB:  []int{5, 4, 3, 2, 1},\n\t\t\textraA: nil,\n\t\t\textraB: nil,\n\t\t},\n\t\t{\n\t\t\tname:   "integers 2",\n\t\t\tlistA:  []int{1, 2, 1, 2, 1},\n\t\t\tlistB:  []int{2, 1, 2, 1, 2},\n\t\t\textraA: []interface{}{1},\n\t\t\textraB: []interface{}{2},\n\t\t},\n\t}\n\tfor _, test := range tests {\n\t\ttest := test\n\t\tt.Run(test.name, func(t *testing.T) {\n\t\t\tactualExtraA, actualExtraB := diffLists(test.listA, test.listB)\n\t\t\tEqual(t, test.extraA, actualExtraA, "extra A does not match for listA=%v listB=%v",\n\t\t\t\ttest.listA, test.listB)\n\t\t\tEqual(t, test.extraB, actualExtraB, "extra B does not match for listA=%v listB=%v",\n\t\t\t\ttest.listA, test.listB)\n\t\t})\n\t}\n}\n\nfunc TestNotElementsMatch(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tcases := []struct {\n\t\texpected interface{}\n\t\tactual   interface{}\n\t\tresult   bool\n\t}{\n\t\t// not matching\n\t\t{[]int{1}, []int{}, true},\n\t\t{[]int{}, []int{2}, true},\n\t\t{[]int{1}, []int{2}, true},\n\t\t{[]int{1}, []int{1, 1}, true},\n\t\t{[]int{1, 2}, []int{3, 4}, true},\n\t\t{[]int{3, 4}, []int{1, 2}, true},\n\t\t{[]int{1, 1, 2, 3}, []int{1, 2, 3}, true},\n\t\t{[]string{"hello"}, []string{"world"}, true},\n\t\t{[]string{"hello", "hello"}, []string{"world", "world"}, true},\n\t\t{[3]string{"hello", "hello", "hello"}, [3]string{"world", "world", "world"}, true},\n\n\t\t// matching\n\t\t{nil, nil, false},\n\t\t{[]int{}, nil, false},\n\t\t{[]int{}, []int{}, false},\n\t\t{[]int{1}, []int{1}, false},\n\t\t{[]int{1, 1}, []int{1, 1}, false},\n\t\t{[]int{1, 2}, []int{2, 1}, false},\n\t\t{[2]int{1, 2}, [2]int{2, 1}, false},\n\t\t{[]int{1, 1, 2}, []int{1, 2, 1}, false},\n\t\t{[]string{"hello", "world"}, []string{"world", "hello"}, false},\n\t\t{[]string{"hello", "hello"}, []string{"hello", "hello"}, false},\n\t\t{[]string{"hello", "hello", "world"}, []string{"hello", "world", "hello"}, false},\n\t\t{[3]string{"hello", "hello", "world"}, [3]string{"hello", "world", "hello"}, false},\n\t}\n\n\tfor _, c := range cases {\n\t\tt.Run(fmt.Sprintf("NotElementsMatch(%#v, %#v)", c.expected, c.actual), func(t *testing.T) {\n\t\t\tres := NotElementsMatch(mockT, c.actual, c.expected)\n\n\t\t\tif res != c.result {\n\t\t\t\tt.Errorf("NotElementsMatch(%#v, %#v) should return %v", c.actual, c.expected, c.result)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestCondition(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !Condition(mockT, func() bool { return true }, "Truth") {\n\t\tt.Error("Condition should return true")\n\t}\n\n\tif Condition(mockT, func() bool { return false }, "Lie") {\n\t\tt.Error("Condition should return false")\n\t}\n}\n\nfunc TestDidPanic(t *testing.T) {\n\tt.Parallel()\n\n\tconst panicMsg = "Panic!"\n\n\tif funcDidPanic, msg, _ := didPanic(func() {\n\t\tpanic(panicMsg)\n\t}); !funcDidPanic || msg != panicMsg {\n\t\tt.Error("didPanic should return true, panicMsg")\n\t}\n\n\tif funcDidPanic, msg, _ := didPanic(func() {\n\t\tpanic(nil)\n\t}); !funcDidPanic || msg != nil {\n\t\tt.Error("didPanic should return true, nil")\n\t}\n\n\tif funcDidPanic, _, _ := didPanic(func() {\n\t}); funcDidPanic {\n\t\tt.Error("didPanic should return false")\n\t}\n}\n\nfunc TestPanics(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !Panics(mockT, func() {\n\t\tpanic("Panic!")\n\t}) {\n\t\tt.Error("Panics should return true")\n\t}\n\n\tif Panics(mockT, func() {\n\t}) {\n\t\tt.Error("Panics should return false")\n\t}\n}\n\nfunc TestPanicsWithValue(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !PanicsWithValue(mockT, "Panic!", func() {\n\t\tpanic("Panic!")\n\t}) {\n\t\tt.Error("PanicsWithValue should return true")\n\t}\n\n\tif !PanicsWithValue(mockT, nil, func() {\n\t\tpanic(nil)\n\t}) {\n\t\tt.Error("PanicsWithValue should return true")\n\t}\n\n\tif PanicsWithValue(mockT, "Panic!", func() {\n\t}) {\n\t\tt.Error("PanicsWithValue should return false")\n\t}\n\n\tif PanicsWithValue(mockT, "at the disco", func() {\n\t\tpanic("Panic!")\n\t}) {\n\t\tt.Error("PanicsWithValue should return false")\n\t}\n}\n\nfunc TestPanicsWithError(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(captureTestingT)\n\tsucceeded := PanicsWithError(mockT, "panic", func() {\n\t\tpanic(errors.New("panic"))\n\t})\n\tmockT.checkResultAndErrMsg(t, true, succeeded, "")\n\n\tsucceeded = PanicsWithError(mockT, "Panic!", func() {})\n\tEqual(t, false, succeeded, "PanicsWithError should return false")\n\tContains(t, mockT.msg, "Panic value:\\t<nil>")\n\n\tsucceeded = PanicsWithError(mockT, "expected panic err msg", func() {\n\t\tpanic(errors.New("actual panic err msg"))\n\t})\n\tEqual(t, false, succeeded, "PanicsWithError should return false")\n\tContains(t, mockT.msg, `Error message:\t"actual panic err msg"`)\n\n\tsucceeded = PanicsWithError(mockT, "expected panic err msg", func() {\n\t\tpanic(&PanicsWithErrorWrapper{"wrapped", errors.New("actual panic err msg")})\n\t})\n\tEqual(t, false, succeeded, "PanicsWithError should return false")\n\tContains(t, mockT.msg, `Error message:\t"wrapped: actual panic err msg"`)\n\n\tsucceeded = PanicsWithError(mockT, "expected panic msg", func() {\n\t\tpanic("actual panic msg")\n\t})\n\tEqual(t, false, succeeded, "PanicsWithError should return false")\n\tContains(t, mockT.msg, `Panic value:\t"actual panic msg"`)\n\tNotContains(t, mockT.msg, "Error message:", "PanicsWithError should not report error message if not due an error")\n}\n\ntype PanicsWithErrorWrapper struct {\n\tPrefix string\n\tErr    error\n}\n\nfunc (e PanicsWithErrorWrapper) Error() string {\n\treturn e.Prefix + ": " + e.Err.Error()\n}\n\nfunc TestNotPanics(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tif !NotPanics(mockT, func() {\n\t}) {\n\t\tt.Error("NotPanics should return true")\n\t}\n\n\tif NotPanics(mockT, func() {\n\t\tpanic("Panic!")\n\t}) {\n\t\tt.Error("NotPanics should return false")\n\t}\n}\n\nfunc TestNoError(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\t// start with a nil error\n\tvar err error\n\n\tTrue(t, NoError(mockT, err), "NoError should return True for nil arg")\n\n\t// now set an error\n\terr = errors.New("some error")\n\n\tFalse(t, NoError(mockT, err), "NoError with error should return False")\n\n\t// returning an empty error interface\n\terr = func() error {\n\t\tvar err *customError\n\t\treturn err\n\t}()\n\n\tif err == nil { // err is not nil here!\n\t\tt.Errorf("Error should be nil due to empty interface: %s", err)\n\t}\n\n\tFalse(t, NoError(mockT, err), "NoError should fail with empty error interface")\n}\n\ntype customError struct{}\n\nfunc (*customError) Error() string { return "fail" }\n\nfunc TestError(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\t// start with a nil error\n\tvar err error\n\n\tFalse(t, Error(mockT, err), "Error should return False for nil arg")\n\n\t// now set an error\n\terr = errors.New("some error")\n\n\tTrue(t, Error(mockT, err), "Error with error should return True")\n\n\t// go vet check\n\tTrue(t, Errorf(mockT, err, "example with %s", "formatted message"), "Errorf with error should return True")\n\n\t// returning an empty error interface\n\terr = func() error {\n\t\tvar err *customError\n\t\treturn err\n\t}()\n\n\tif err == nil { // err is not nil here!\n\t\tt.Errorf("Error should be nil due to empty interface: %s", err)\n\t}\n\n\tTrue(t, Error(mockT, err), "Error should pass with empty error interface")\n}\n\nfunc TestEqualError(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\t// start with a nil error\n\tvar err error\n\tFalse(t, EqualError(mockT, err, ""),\n\t\t"EqualError should return false for nil arg")\n\n\t// now set an error\n\terr = errors.New("some error")\n\tFalse(t, EqualError(mockT, err, "Not some error"),\n\t\t"EqualError should return false for different error string")\n\tTrue(t, EqualError(mockT, err, "some error"),\n\t\t"EqualError should return true")\n}\n\nfunc TestErrorContains(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\t// start with a nil error\n\tvar err error\n\tFalse(t, ErrorContains(mockT, err, ""),\n\t\t"ErrorContains should return false for nil arg")\n\n\t// now set an error\n\terr = errors.New("some error: another error")\n\tFalse(t, ErrorContains(mockT, err, "bad error"),\n\t\t"ErrorContains should return false for different error string")\n\tTrue(t, ErrorContains(mockT, err, "some error"),\n\t\t"ErrorContains should return true")\n\tTrue(t, ErrorContains(mockT, err, "another error"),\n\t\t"ErrorContains should return true")\n}\n\nfunc Test_isEmpty(t *testing.T) {\n\tt.Parallel()\n\n\tchWithValue := make(chan struct{}, 1)\n\tchWithValue <- struct{}{}\n\n\tTrue(t, isEmpty(""))\n\tTrue(t, isEmpty(nil))\n\tTrue(t, isEmpty(error(nil)))\n\tTrue(t, isEmpty((*int)(nil)))\n\tTrue(t, isEmpty((*string)(nil)))\n\tTrue(t, isEmpty(new(string)))\n\tTrue(t, isEmpty([]string{}))\n\tTrue(t, isEmpty([]string(nil)))\n\tTrue(t, isEmpty([]byte(nil)))\n\tTrue(t, isEmpty([]byte{}))\n\tTrue(t, isEmpty([]byte("")))\n\tTrue(t, isEmpty([]bool(nil)))\n\tTrue(t, isEmpty([]bool{}))\n\tTrue(t, isEmpty([]interface{}(nil)))\n\tTrue(t, isEmpty([]interface{}{}))\n\tTrue(t, isEmpty(struct{}{}))\n\tTrue(t, isEmpty(&struct{}{}))\n\tTrue(t, isEmpty(struct{ A int }{A: 0}))\n\tTrue(t, isEmpty(struct{ a int }{a: 0}))\n\tTrue(t, isEmpty(struct {\n\t\ta int\n\t\tB int\n\t}{a: 0, B: 0}))\n\tTrue(t, isEmpty(0))\n\tTrue(t, isEmpty(int(0)))\n\tTrue(t, isEmpty(int8(0)))\n\tTrue(t, isEmpty(int16(0)))\n\tTrue(t, isEmpty(uint16(0)))\n\tTrue(t, isEmpty(int32(0)))\n\tTrue(t, isEmpty(uint32(0)))\n\tTrue(t, isEmpty(int64(0)))\n\tTrue(t, isEmpty(uint64(0)))\n\tTrue(t, isEmpty(\'\\u0000\')) // rune => int32\n\tTrue(t, isEmpty(float32(0)))\n\tTrue(t, isEmpty(float64(0)))\n\tTrue(t, isEmpty(0i))   // complex\n\tTrue(t, isEmpty(0.0i)) // complex\n\tTrue(t, isEmpty(false))\n\tTrue(t, isEmpty(new(bool)))\n\tTrue(t, isEmpty(map[string]string{}))\n\tTrue(t, isEmpty(map[string]string(nil)))\n\tTrue(t, isEmpty(new(time.Time)))\n\tTrue(t, isEmpty(time.Time{}))\n\tTrue(t, isEmpty(make(chan struct{})))\n\tTrue(t, isEmpty(chan struct{}(nil)))\n\tTrue(t, isEmpty(chan<- struct{}(nil)))\n\tTrue(t, isEmpty(make(chan struct{})))\n\tTrue(t, isEmpty(make(chan<- struct{})))\n\tTrue(t, isEmpty(make(chan struct{}, 1)))\n\tTrue(t, isEmpty(make(chan<- struct{}, 1)))\n\tTrue(t, isEmpty([1]int{0}))\n\tTrue(t, isEmpty([2]int{0, 0}))\n\tTrue(t, isEmpty([8]int{}))\n\tTrue(t, isEmpty([...]int{7: 0}))\n\tTrue(t, isEmpty([...]bool{false, false}))\n\tTrue(t, isEmpty(errors.New(""))) // BEWARE\n\tTrue(t, isEmpty([]error{}))\n\tTrue(t, isEmpty([]error(nil)))\n\tTrue(t, isEmpty(&[1]int{0}))\n\tTrue(t, isEmpty(&[2]int{0, 0}))\n\tFalse(t, isEmpty("something"))\n\tFalse(t, isEmpty(errors.New("something")))\n\tFalse(t, isEmpty([]string{"something"}))\n\tFalse(t, isEmpty(1))\n\tFalse(t, isEmpty(int(1)))\n\tFalse(t, isEmpty(uint(1)))\n\tFalse(t, isEmpty(byte(1)))\n\tFalse(t, isEmpty(int8(1)))\n\tFalse(t, isEmpty(uint8(1)))\n\tFalse(t, isEmpty(int16(1)))\n\tFalse(t, isEmpty(uint16(1)))\n\tFalse(t, isEmpty(int32(1)))\n\tFalse(t, isEmpty(uint32(1)))\n\tFalse(t, isEmpty(int64(1)))\n\tFalse(t, isEmpty(uint64(1)))\n\tFalse(t, isEmpty(\'A\')) // rune => int32\n\tFalse(t, isEmpty(true))\n\tFalse(t, isEmpty(1.0))\n\tFalse(t, isEmpty(1i))            // complex\n\tFalse(t, isEmpty([]byte{0}))     // elements values are ignored for slices\n\tFalse(t, isEmpty([]byte{0, 0}))  // elements values are ignored for slices\n\tFalse(t, isEmpty([]string{""}))  // elements values are ignored for slices\n\tFalse(t, isEmpty([]string{"a"})) // elements values are ignored for slices\n\tFalse(t, isEmpty([]bool{false})) // elements values are ignored for slices\n\tFalse(t, isEmpty([]bool{true}))  // elements values are ignored for slices\n\tFalse(t, isEmpty([]error{errors.New("xxx")}))\n\tFalse(t, isEmpty([]error{nil}))            // BEWARE\n\tFalse(t, isEmpty([]error{errors.New("")})) // BEWARE\n\tFalse(t, isEmpty(map[string]string{"Hello": "World"}))\n\tFalse(t, isEmpty(map[string]string{"": ""}))\n\tFalse(t, isEmpty(map[string]string{"foo": ""}))\n\tFalse(t, isEmpty(map[string]string{"": "foo"}))\n\tFalse(t, isEmpty(chWithValue))\n\tFalse(t, isEmpty([1]bool{true}))\n\tFalse(t, isEmpty([2]bool{false, true}))\n\tFalse(t, isEmpty([...]bool{10: true}))\n\tFalse(t, isEmpty([]int{0}))\n\tFalse(t, isEmpty([]int{42}))\n\tFalse(t, isEmpty([1]int{42}))\n\tFalse(t, isEmpty([2]int{0, 42}))\n\tFalse(t, isEmpty(&[1]int{42}))\n\tFalse(t, isEmpty(&[2]int{0, 42}))\n\tFalse(t, isEmpty([1]*int{new(int)})) // array elements must be the zero value, not any Empty value\n\tFalse(t, isEmpty(struct{ A int }{A: 42}))\n\tFalse(t, isEmpty(struct{ a int }{a: 42}))\n\tFalse(t, isEmpty(struct{ a *int }{a: new(int)})) // fields must be the zero value, not any Empty value\n\tFalse(t, isEmpty(struct{ a []int }{a: []int{}})) // fields must be the zero value, not any Empty value\n\tFalse(t, isEmpty(struct {\n\t\ta int\n\t\tB int\n\t}{a: 0, B: 42}))\n\tFalse(t, isEmpty(struct {\n\t\ta int\n\t\tB int\n\t}{a: 42, B: 0}))\n}\n\nfunc Benchmark_isEmpty(b *testing.B) {\n\tb.ReportAllocs()\n\n\tv := new(int)\n\tb.ResetTimer()\n\n\tfor i := 0; i < b.N; i++ {\n\t\tisEmpty("")\n\t\tisEmpty(42)\n\t\tisEmpty(v)\n\t}\n}\n\nfunc TestEmpty(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tchWithValue := make(chan struct{}, 1)\n\tchWithValue <- struct{}{}\n\tvar tiP *time.Time\n\tvar tiNP time.Time\n\tvar s *string\n\tvar f *os.File\n\tsP := &s\n\tx := 1\n\txP := &x\n\n\ttype TString string\n\ttype TStruct struct {\n\t\tx int\n\t}\n\n\tTrue(t, Empty(mockT, ""), "Empty string is empty")\n\tTrue(t, Empty(mockT, nil), "Nil is empty")\n\tTrue(t, Empty(mockT, []string{}), "Empty string array is empty")\n\tTrue(t, Empty(mockT, 0), "Zero int value is empty")\n\tTrue(t, Empty(mockT, false), "False value is empty")\n\tTrue(t, Empty(mockT, make(chan struct{})), "Channel without values is empty")\n\tTrue(t, Empty(mockT, s), "Nil string pointer is empty")\n\tTrue(t, Empty(mockT, f), "Nil os.File pointer is empty")\n\tTrue(t, Empty(mockT, tiP), "Nil time.Time pointer is empty")\n\tTrue(t, Empty(mockT, tiNP), "time.Time is empty")\n\tTrue(t, Empty(mockT, TStruct{}), "struct with zero values is empty")\n\tTrue(t, Empty(mockT, TString("")), "empty aliased string is empty")\n\tTrue(t, Empty(mockT, sP), "ptr to nil value is empty")\n\tTrue(t, Empty(mockT, [1]int{}), "array is state")\n\n\tFalse(t, Empty(mockT, "something"), "Non Empty string is not empty")\n\tFalse(t, Empty(mockT, errors.New("something")), "Non nil object is not empty")\n\tFalse(t, Empty(mockT, []string{"something"}), "Non empty string array is not empty")\n\tFalse(t, Empty(mockT, 1), "Non-zero int value is not empty")\n\tFalse(t, Empty(mockT, true), "True value is not empty")\n\tFalse(t, Empty(mockT, chWithValue), "Channel with values is not empty")\n\tFalse(t, Empty(mockT, TStruct{x: 1}), "struct with initialized values is empty")\n\tFalse(t, Empty(mockT, TString("abc")), "non-empty aliased string is empty")\n\tFalse(t, Empty(mockT, xP), "ptr to non-nil value is not empty")\n\tFalse(t, Empty(mockT, [1]int{42}), "array is not state")\n\n\t// error messages validation\n\ttests := []struct {\n\t\tname           string\n\t\tvalue          interface{}\n\t\texpectedResult bool\n\t\texpectedErrMsg string\n\t}{\n\t\t{\n\t\t\tname:           "Non Empty string is not empty",\n\t\t\tvalue:          "something",\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should be empty, but was something\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "Non nil object is not empty",\n\t\t\tvalue:          errors.New("something"),\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should be empty, but was something\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "Non empty string array is not empty",\n\t\t\tvalue:          []string{"something"},\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should be empty, but was [something]\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "Non-zero int value is not empty",\n\t\t\tvalue:          1,\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should be empty, but was 1\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "True value is not empty",\n\t\t\tvalue:          true,\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should be empty, but was true\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "Channel with values is not empty",\n\t\t\tvalue:          chWithValue,\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: fmt.Sprintf("Should be empty, but was %v\\n", chWithValue),\n\t\t},\n\t\t{\n\t\t\tname:           "struct with initialized values is empty",\n\t\t\tvalue:          TStruct{x: 1},\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should be empty, but was {1}\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "non-empty aliased string is empty",\n\t\t\tvalue:          TString("abc"),\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should be empty, but was abc\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "ptr to non-nil value is not empty",\n\t\t\tvalue:          xP,\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: fmt.Sprintf("Should be empty, but was %p\\n", xP),\n\t\t},\n\t\t{\n\t\t\tname:           "array is not state",\n\t\t\tvalue:          [1]int{42},\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should be empty, but was [42]\\n",\n\t\t},\n\n\t\t// Here are some edge cases\n\t\t{\n\t\t\tname:           "string with only spaces is not empty",\n\t\t\tvalue:          "   ",\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should be empty, but was    \\n", // TODO FIX THIS strange error message\n\t\t},\n\t\t{\n\t\t\tname:           "string with a line feed is not empty",\n\t\t\tvalue:          "\\n",\n\t\t\texpectedResult: false,\n\t\t\t// TODO This is the exact same error message as for an empty string\n\t\t\texpectedErrMsg: "Should be empty, but was \\n", // TODO FIX THIS strange error message\n\t\t},\n\t\t{\n\t\t\tname:           "string with only tabulation and lines feed is not empty",\n\t\t\tvalue:          "\\n\\t\\n",\n\t\t\texpectedResult: false,\n\t\t\t// TODO The line feeds and tab are not helping to spot what is expected\n\t\t\texpectedErrMsg: "" + // this syntax is used to show how errors are reported.\n\t\t\t\t"Should be empty, but was \\n" +\n\t\t\t\t"\\t\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "string with trailing lines feed is not empty",\n\t\t\tvalue:          "foo\\n\\n",\n\t\t\texpectedResult: false,\n\t\t\t// TODO it\'s not clear if one or two lines feed are expected\n\t\t\texpectedErrMsg: "Should be empty, but was foo\\n\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "string with leading and trailing tabulation and lines feed is not empty",\n\t\t\tvalue:          "\\n\\nfoo\\t\\n\\t\\n",\n\t\t\texpectedResult: false,\n\t\t\t// TODO The line feeds and tab are not helping to figure what is expected\n\t\t\texpectedErrMsg: "" +\n\t\t\t\t"Should be empty, but was \\n" +\n\t\t\t\t"\\n" +\n\t\t\t\t"foo\\t\\n" +\n\t\t\t\t"\\t\\n",\n\t\t},\n\n\t\t{\n\t\t\tname:           "non-printable character is not empty",\n\t\t\tvalue:          "\\u00a0", // NO-BREAK SPACE UNICODE CHARACTER\n\t\t\texpectedResult: false,\n\t\t\t// TODO here you cannot figure out what is expected\n\t\t\texpectedErrMsg: "Should be empty, but was \\u00a0\\n",\n\t\t},\n\n\t\t// Here we are testing there is no error message on success\n\t\t{\n\t\t\tname:           "Empty string is empty",\n\t\t\tvalue:          "",\n\t\t\texpectedResult: true,\n\t\t\texpectedErrMsg: "",\n\t\t},\n\t}\n\n\tfor _, tt := range tests {\n\t\ttt := tt\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\tmockCT := new(captureTestingT)\n\t\t\tres := Empty(mockCT, tt.value)\n\t\t\tmockCT.checkResultAndErrMsg(t, res, tt.expectedResult, tt.expectedErrMsg)\n\t\t})\n\t}\n}\n\nfunc TestNotEmpty(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tchWithValue := make(chan struct{}, 1)\n\tchWithValue <- struct{}{}\n\n\tFalse(t, NotEmpty(mockT, ""), "Empty string is empty")\n\tFalse(t, NotEmpty(mockT, nil), "Nil is empty")\n\tFalse(t, NotEmpty(mockT, []string{}), "Empty string array is empty")\n\tFalse(t, NotEmpty(mockT, 0), "Zero int value is empty")\n\tFalse(t, NotEmpty(mockT, false), "False value is empty")\n\tFalse(t, NotEmpty(mockT, make(chan struct{})), "Channel without values is empty")\n\tFalse(t, NotEmpty(mockT, [1]int{}), "array is state")\n\n\tTrue(t, NotEmpty(mockT, "something"), "Non Empty string is not empty")\n\tTrue(t, NotEmpty(mockT, errors.New("something")), "Non nil object is not empty")\n\tTrue(t, NotEmpty(mockT, []string{"something"}), "Non empty string array is not empty")\n\tTrue(t, NotEmpty(mockT, 1), "Non-zero int value is not empty")\n\tTrue(t, NotEmpty(mockT, true), "True value is not empty")\n\tTrue(t, NotEmpty(mockT, chWithValue), "Channel with values is not empty")\n\tTrue(t, NotEmpty(mockT, [1]int{42}), "array is not state")\n\n\t// error messages validation\n\ttests := []struct {\n\t\tname           string\n\t\tvalue          interface{}\n\t\texpectedResult bool\n\t\texpectedErrMsg string\n\t}{\n\t\t{\n\t\t\tname:           "Empty string is empty",\n\t\t\tvalue:          "",\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: `Should NOT be empty, but was ` + "\\n", // TODO FIX THIS strange error message\n\t\t},\n\t\t{\n\t\t\tname:           "Nil is empty",\n\t\t\tvalue:          nil,\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should NOT be empty, but was <nil>\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "Empty string array is empty",\n\t\t\tvalue:          []string{},\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should NOT be empty, but was []\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "Zero int value is empty",\n\t\t\tvalue:          0,\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should NOT be empty, but was 0\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "False value is empty",\n\t\t\tvalue:          false,\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should NOT be empty, but was false\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "array is state",\n\t\t\tvalue:          [1]int{},\n\t\t\texpectedResult: false,\n\t\t\texpectedErrMsg: "Should NOT be empty, but was [0]\\n",\n\t\t},\n\n\t\t// Here we are testing there is no error message on success\n\t\t{\n\t\t\tname:           "Non Empty string is not empty",\n\t\t\tvalue:          "something",\n\t\t\texpectedResult: true,\n\t\t\texpectedErrMsg: "",\n\t\t},\n\t}\n\n\tfor _, tt := range tests {\n\t\ttt := tt\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\tmockCT := new(captureTestingT)\n\t\t\tres := NotEmpty(mockCT, tt.value)\n\t\t\tmockCT.checkResultAndErrMsg(t, tt.expectedResult, res, tt.expectedErrMsg)\n\t\t})\n\t}\n}\n\nfunc Test_getLen(t *testing.T) {\n\tt.Parallel()\n\n\tfalseCases := []interface{}{\n\t\tnil,\n\t\t0,\n\t\ttrue,\n\t\tfalse,\n\t\t\'A\',\n\t\tstruct{}{},\n\t}\n\tfor _, v := range falseCases {\n\t\tl, ok := getLen(v)\n\t\tFalse(t, ok, "Expected getLen fail to get length of %#v", v)\n\t\tEqual(t, 0, l, "getLen should return 0 for %#v", v)\n\t}\n\n\tch := make(chan int, 5)\n\tch <- 1\n\tch <- 2\n\tch <- 3\n\ttrueCases := []struct {\n\t\tv interface{}\n\t\tl int\n\t}{\n\t\t{[]int{1, 2, 3}, 3},\n\t\t{[...]int{1, 2, 3}, 3},\n\t\t{"ABC", 3},\n\t\t{map[int]int{1: 2, 2: 4, 3: 6}, 3},\n\t\t{ch, 3},\n\n\t\t{[]int{}, 0},\n\t\t{map[int]int{}, 0},\n\t\t{make(chan int), 0},\n\n\t\t{[]int(nil), 0},\n\t\t{map[int]int(nil), 0},\n\t\t{(chan int)(nil), 0},\n\t}\n\n\tfor _, c := range trueCases {\n\t\tl, ok := getLen(c.v)\n\t\tTrue(t, ok, "Expected getLen success to get length of %#v", c.v)\n\t\tEqual(t, c.l, l)\n\t}\n}\n\nfunc TestLen(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tFalse(t, Len(mockT, nil, 0), "nil does not have length")\n\tFalse(t, Len(mockT, 0, 0), "int does not have length")\n\tFalse(t, Len(mockT, true, 0), "true does not have length")\n\tFalse(t, Len(mockT, false, 0), "false does not have length")\n\tFalse(t, Len(mockT, \'A\', 0), "Rune does not have length")\n\tFalse(t, Len(mockT, struct{}{}, 0), "Struct does not have length")\n\n\tch := make(chan int, 5)\n\tch <- 1\n\tch <- 2\n\tch <- 3\n\n\tcases := []struct {\n\t\tv               interface{}\n\t\tl               int\n\t\texpected1234567 string // message when expecting 1234567 items\n\t}{\n\t\t{[]int{1, 2, 3}, 3, `"[1 2 3]" should have 1234567 item(s), but has 3`},\n\t\t{[...]int{1, 2, 3}, 3, `"[1 2 3]" should have 1234567 item(s), but has 3`},\n\t\t{"ABC", 3, `"ABC" should have 1234567 item(s), but has 3`},\n\t\t{map[int]int{1: 2, 2: 4, 3: 6}, 3, `"map[1:2 2:4 3:6]" should have 1234567 item(s), but has 3`},\n\t\t{ch, 3, ""},\n\n\t\t{[]int{}, 0, `"[]" should have 1234567 item(s), but has 0`},\n\t\t{map[int]int{}, 0, `"map[]" should have 1234567 item(s), but has 0`},\n\t\t{make(chan int), 0, ""},\n\n\t\t{[]int(nil), 0, `"[]" should have 1234567 item(s), but has 0`},\n\t\t{map[int]int(nil), 0, `"map[]" should have 1234567 item(s), but has 0`},\n\t\t{(chan int)(nil), 0, `"<nil>" should have 1234567 item(s), but has 0`},\n\t}\n\n\tfor _, c := range cases {\n\t\tTrue(t, Len(mockT, c.v, c.l), "%#v have %d items", c.v, c.l)\n\t\tFalse(t, Len(mockT, c.v, c.l+1), "%#v have %d items", c.v, c.l)\n\t\tif c.expected1234567 != "" {\n\t\t\tmsgMock := new(mockTestingT)\n\t\t\tLen(msgMock, c.v, 1234567)\n\t\t\tContains(t, msgMock.errorString(), c.expected1234567)\n\t\t}\n\t}\n}\n\nfunc TestWithinDuration(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\ta := time.Now()\n\tb := a.Add(10 * time.Second)\n\n\tTrue(t, WithinDuration(mockT, a, b, 10*time.Second), "A 10s difference is within a 10s time difference")\n\tTrue(t, WithinDuration(mockT, b, a, 10*time.Second), "A 10s difference is within a 10s time difference")\n\n\tFalse(t, WithinDuration(mockT, a, b, 9*time.Second), "A 10s difference is not within a 9s time difference")\n\tFalse(t, WithinDuration(mockT, b, a, 9*time.Second), "A 10s difference is not within a 9s time difference")\n\n\tFalse(t, WithinDuration(mockT, a, b, -9*time.Second), "A 10s difference is not within a 9s time difference")\n\tFalse(t, WithinDuration(mockT, b, a, -9*time.Second), "A 10s difference is not within a 9s time difference")\n\n\tFalse(t, WithinDuration(mockT, a, b, -11*time.Second), "A 10s difference is not within a 9s time difference")\n\tFalse(t, WithinDuration(mockT, b, a, -11*time.Second), "A 10s difference is not within a 9s time difference")\n}\n\nfunc TestWithinRange(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tn := time.Now()\n\ts := n.Add(-time.Second)\n\te := n.Add(time.Second)\n\n\tTrue(t, WithinRange(mockT, n, n, n), "Exact same actual, start, and end values return true")\n\n\tTrue(t, WithinRange(mockT, n, s, e), "Time in range is within the time range")\n\tTrue(t, WithinRange(mockT, s, s, e), "The start time is within the time range")\n\tTrue(t, WithinRange(mockT, e, s, e), "The end time is within the time range")\n\n\tFalse(t, WithinRange(mockT, s.Add(-time.Nanosecond), s, e, "Just before the start time is not within the time range"))\n\tFalse(t, WithinRange(mockT, e.Add(time.Nanosecond), s, e, "Just after the end time is not within the time range"))\n\n\tFalse(t, WithinRange(mockT, n, e, s, "Just after the end time is not within the time range"))\n}\n\nfunc TestInDelta(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tTrue(t, InDelta(mockT, 1.001, 1, 0.01), "|1.001 - 1| <= 0.01")\n\tTrue(t, InDelta(mockT, 1, 1.001, 0.01), "|1 - 1.001| <= 0.01")\n\tTrue(t, InDelta(mockT, 1, 2, 1), "|1 - 2| <= 1")\n\tFalse(t, InDelta(mockT, 1, 2, 0.5), "Expected |1 - 2| <= 0.5 to fail")\n\tFalse(t, InDelta(mockT, 2, 1, 0.5), "Expected |2 - 1| <= 0.5 to fail")\n\tFalse(t, InDelta(mockT, "", nil, 1), "Expected non numerals to fail")\n\tFalse(t, InDelta(mockT, 42, math.NaN(), 0.01), "Expected NaN for actual to fail")\n\tFalse(t, InDelta(mockT, math.NaN(), 42, 0.01), "Expected NaN for expected to fail")\n\tTrue(t, InDelta(mockT, math.NaN(), math.NaN(), 0.01), "Expected NaN for both to pass")\n\n\tcases := []struct {\n\t\ta, b  interface{}\n\t\tdelta float64\n\t}{\n\t\t{uint(2), uint(1), 1},\n\t\t{uint8(2), uint8(1), 1},\n\t\t{uint16(2), uint16(1), 1},\n\t\t{uint32(2), uint32(1), 1},\n\t\t{uint64(2), uint64(1), 1},\n\n\t\t{int(2), int(1), 1},\n\t\t{int8(2), int8(1), 1},\n\t\t{int16(2), int16(1), 1},\n\t\t{int32(2), int32(1), 1},\n\t\t{int64(2), int64(1), 1},\n\n\t\t{float32(2), float32(1), 1},\n\t\t{float64(2), float64(1), 1},\n\t}\n\n\tfor _, tc := range cases {\n\t\tTrue(t, InDelta(mockT, tc.a, tc.b, tc.delta), "Expected |%V - %V| <= %v", tc.a, tc.b, tc.delta)\n\t}\n}\n\nfunc TestInDeltaSlice(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tTrue(t, InDeltaSlice(mockT,\n\t\t[]float64{1.001, math.NaN(), 0.999},\n\t\t[]float64{1, math.NaN(), 1},\n\t\t0.1), "{1.001, NaN, 0.009} is element-wise close to {1, NaN, 1} in delta=0.1")\n\n\tTrue(t, InDeltaSlice(mockT,\n\t\t[]float64{1, math.NaN(), 2},\n\t\t[]float64{0, math.NaN(), 3},\n\t\t1), "{1, NaN, 2} is element-wise close to {0, NaN, 3} in delta=1")\n\n\tFalse(t, InDeltaSlice(mockT,\n\t\t[]float64{1, math.NaN(), 2},\n\t\t[]float64{0, math.NaN(), 3},\n\t\t0.1), "{1, NaN, 2} is not element-wise close to {0, NaN, 3} in delta=0.1")\n\n\tFalse(t, InDeltaSlice(mockT, "", nil, 1), "Expected non numeral slices to fail")\n}\n\nfunc TestInDeltaMapValues(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tfor _, tc := range []struct {\n\t\ttitle  string\n\t\texpect interface{}\n\t\tactual interface{}\n\t\tf      func(TestingT, bool, ...interface{}) bool\n\t\tdelta  float64\n\t}{\n\t\t{\n\t\t\ttitle: "Within delta",\n\t\t\texpect: map[string]float64{\n\t\t\t\t"foo": 1.0,\n\t\t\t\t"bar": 2.0,\n\t\t\t\t"baz": math.NaN(),\n\t\t\t},\n\t\t\tactual: map[string]float64{\n\t\t\t\t"foo": 1.01,\n\t\t\t\t"bar": 1.99,\n\t\t\t\t"baz": math.NaN(),\n\t\t\t},\n\t\t\tdelta: 0.1,\n\t\t\tf:     True,\n\t\t},\n\t\t{\n\t\t\ttitle: "Within delta",\n\t\t\texpect: map[int]float64{\n\t\t\t\t1: 1.0,\n\t\t\t\t2: 2.0,\n\t\t\t},\n\t\t\tactual: map[int]float64{\n\t\t\t\t1: 1.0,\n\t\t\t\t2: 1.99,\n\t\t\t},\n\t\t\tdelta: 0.1,\n\t\t\tf:     True,\n\t\t},\n\t\t{\n\t\t\ttitle: "Different number of keys",\n\t\t\texpect: map[int]float64{\n\t\t\t\t1: 1.0,\n\t\t\t\t2: 2.0,\n\t\t\t},\n\t\t\tactual: map[int]float64{\n\t\t\t\t1: 1.0,\n\t\t\t},\n\t\t\tdelta: 0.1,\n\t\t\tf:     False,\n\t\t},\n\t\t{\n\t\t\ttitle: "Within delta with zero value",\n\t\t\texpect: map[string]float64{\n\t\t\t\t"zero": 0,\n\t\t\t},\n\t\t\tactual: map[string]float64{\n\t\t\t\t"zero": 0,\n\t\t\t},\n\t\t\tdelta: 0.1,\n\t\t\tf:     True,\n\t\t},\n\t\t{\n\t\t\ttitle: "With missing key with zero value",\n\t\t\texpect: map[string]float64{\n\t\t\t\t"zero": 0,\n\t\t\t\t"foo":  0,\n\t\t\t},\n\t\t\tactual: map[string]float64{\n\t\t\t\t"zero": 0,\n\t\t\t\t"bar":  0,\n\t\t\t},\n\t\t\tf: False,\n\t\t},\n\t} {\n\t\ttc.f(t, InDeltaMapValues(mockT, tc.expect, tc.actual, tc.delta), tc.title+"\\n"+diff(tc.expect, tc.actual))\n\t}\n}\n\nfunc TestInEpsilon(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tcases := []struct {\n\t\ta, b    interface{}\n\t\tepsilon float64\n\t}{\n\t\t{uint8(2), uint16(2), .001},\n\t\t{2.1, 2.2, 0.1},\n\t\t{2.2, 2.1, 0.1},\n\t\t{-2.1, -2.2, 0.1},\n\t\t{-2.2, -2.1, 0.1},\n\t\t{uint64(100), uint8(101), 0.01},\n\t\t{0.1, -0.1, 2},\n\t\t{0.1, 0, 2},\n\t\t{math.NaN(), math.NaN(), 1},\n\t\t{time.Second, time.Second + time.Millisecond, 0.002},\n\t}\n\n\tfor _, tc := range cases {\n\t\tTrue(t, InEpsilon(t, tc.a, tc.b, tc.epsilon, "Expected %V and %V to have a relative difference of %v", tc.a, tc.b, tc.epsilon), "test: %q", tc)\n\t}\n\n\tcases = []struct {\n\t\ta, b    interface{}\n\t\tepsilon float64\n\t}{\n\t\t{uint8(2), int16(-2), .001},\n\t\t{uint64(100), uint8(102), 0.01},\n\t\t{2.1, 2.2, 0.001},\n\t\t{2.2, 2.1, 0.001},\n\t\t{2.1, -2.2, 1},\n\t\t{2.1, "bla-bla", 0},\n\t\t{0.1, -0.1, 1.99},\n\t\t{0, 0.1, 2}, // expected must be different to zero\n\t\t{time.Second, time.Second + 10*time.Millisecond, 0.002},\n\t\t{math.NaN(), 0, 1},\n\t\t{0, math.NaN(), 1},\n\t\t{0, 0, math.NaN()},\n\t\t{math.Inf(1), 1, 1},\n\t\t{math.Inf(-1), 1, 1},\n\t\t{1, math.Inf(1), 1},\n\t\t{1, math.Inf(-1), 1},\n\t\t{math.Inf(1), math.Inf(1), 1},\n\t\t{math.Inf(1), math.Inf(-1), 1},\n\t\t{math.Inf(-1), math.Inf(1), 1},\n\t\t{math.Inf(-1), math.Inf(-1), 1},\n\t}\n\n\tfor _, tc := range cases {\n\t\tFalse(t, InEpsilon(mockT, tc.a, tc.b, tc.epsilon, "Expected %V and %V to have a relative difference of %v", tc.a, tc.b, tc.epsilon))\n\t}\n}\n\nfunc TestInEpsilonSlice(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tTrue(t, InEpsilonSlice(mockT,\n\t\t[]float64{2.2, math.NaN(), 2.0},\n\t\t[]float64{2.1, math.NaN(), 2.1},\n\t\t0.06), "{2.2, NaN, 2.0} is element-wise close to {2.1, NaN, 2.1} in epsilon=0.06")\n\n\tFalse(t, InEpsilonSlice(mockT,\n\t\t[]float64{2.2, 2.0},\n\t\t[]float64{2.1, 2.1},\n\t\t0.04), "{2.2, 2.0} is not element-wise close to {2.1, 2.1} in epsilon=0.04")\n\n\tFalse(t, InEpsilonSlice(mockT, "", nil, 1), "Expected non numeral slices to fail")\n}\n\nfunc TestRegexp(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tcases := []struct {\n\t\trx, str string\n\t}{\n\t\t{"^start", "start of the line"},\n\t\t{"end$", "in the end"},\n\t\t{"end$", "in the end"},\n\t\t{"[0-9]{3}[.-]?[0-9]{2}[.-]?[0-9]{2}", "My phone number is 650.12.34"},\n\t}\n\n\tfor _, tc := range cases {\n\t\tTrue(t, Regexp(mockT, tc.rx, tc.str))\n\t\tTrue(t, Regexp(mockT, regexp.MustCompile(tc.rx), tc.str))\n\t\tTrue(t, Regexp(mockT, regexp.MustCompile(tc.rx), []byte(tc.str)))\n\t\tFalse(t, NotRegexp(mockT, tc.rx, tc.str))\n\t\tFalse(t, NotRegexp(mockT, tc.rx, []byte(tc.str)))\n\t\tFalse(t, NotRegexp(mockT, regexp.MustCompile(tc.rx), tc.str))\n\t}\n\n\tcases = []struct {\n\t\trx, str string\n\t}{\n\t\t{"^asdfastart", "Not the start of the line"},\n\t\t{"end$", "in the end."},\n\t\t{"[0-9]{3}[.-]?[0-9]{2}[.-]?[0-9]{2}", "My phone number is 650.12a.34"},\n\t}\n\n\tfor _, tc := range cases {\n\t\tFalse(t, Regexp(mockT, tc.rx, tc.str), "Expected %q to not match %q", tc.rx, tc.str)\n\t\tFalse(t, Regexp(mockT, regexp.MustCompile(tc.rx), tc.str))\n\t\tFalse(t, Regexp(mockT, regexp.MustCompile(tc.rx), []byte(tc.str)))\n\t\tTrue(t, NotRegexp(mockT, tc.rx, tc.str))\n\t\tTrue(t, NotRegexp(mockT, tc.rx, []byte(tc.str)))\n\t\tTrue(t, NotRegexp(mockT, regexp.MustCompile(tc.rx), tc.str))\n\t}\n}\n\nfunc testAutogeneratedFunction() {\n\tdefer func() {\n\t\tif err := recover(); err == nil {\n\t\t\tpanic("did not panic")\n\t\t}\n\t\tCallerInfo()\n\t}()\n\tt := struct {\n\t\tio.Closer\n\t}{}\n\tc := t\n\tc.Close()\n}\n\nfunc TestCallerInfoWithAutogeneratedFunctions(t *testing.T) {\n\tt.Parallel()\n\n\tNotPanics(t, func() {\n\t\ttestAutogeneratedFunction()\n\t})\n}\n\nfunc TestZero(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tfor _, test := range zeros {\n\t\tTrue(t, Zero(mockT, test, "%#v is not the %T zero value", test, test))\n\t}\n\n\tfor _, test := range nonZeros {\n\t\tFalse(t, Zero(mockT, test, "%#v is not the %T zero value", test, test))\n\t}\n}\n\nfunc TestNotZero(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tfor _, test := range zeros {\n\t\tFalse(t, NotZero(mockT, test, "%#v is not the %T zero value", test, test))\n\t}\n\n\tfor _, test := range nonZeros {\n\t\tTrue(t, NotZero(mockT, test, "%#v is not the %T zero value", test, test))\n\t}\n}\n\nfunc TestFileExists(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tTrue(t, FileExists(mockT, "assertions.go"))\n\n\tmockT = new(testing.T)\n\tFalse(t, FileExists(mockT, "random_file"))\n\n\tmockT = new(testing.T)\n\tFalse(t, FileExists(mockT, "../_codegen"))\n\n\tlink := getTempSymlinkPath(t, "assertions.go")\n\tmockT = new(testing.T)\n\tTrue(t, FileExists(mockT, link))\n\n\tlink = getTempSymlinkPath(t, "non_existent_file")\n\tmockT = new(testing.T)\n\tTrue(t, FileExists(mockT, link))\n}\n\nfunc TestNoFileExists(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, NoFileExists(mockT, "assertions.go"))\n\n\tmockT = new(testing.T)\n\tTrue(t, NoFileExists(mockT, "non_existent_file"))\n\n\tmockT = new(testing.T)\n\tTrue(t, NoFileExists(mockT, "../_codegen"))\n\n\tlink := getTempSymlinkPath(t, "assertions.go")\n\tmockT = new(testing.T)\n\tFalse(t, NoFileExists(mockT, link))\n\n\tlink = getTempSymlinkPath(t, "non_existent_file")\n\tmockT = new(testing.T)\n\tFalse(t, NoFileExists(mockT, link))\n}\n\nfunc getTempSymlinkPath(t *testing.T, file string) string {\n\tt.Helper()\n\n\ttempDir := t.TempDir()\n\tlink := filepath.Join(tempDir, file+"_symlink")\n\tif err := os.Symlink(file, link); err != nil {\n\t\tt.Fatalf("could not create temp symlink %q pointing to %q: %v", link, file, err)\n\t}\n\treturn link\n}\n\nfunc TestDirExists(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, DirExists(mockT, "assertions.go"))\n\n\tmockT = new(testing.T)\n\tFalse(t, DirExists(mockT, "non_existent_dir"))\n\n\tmockT = new(testing.T)\n\tTrue(t, DirExists(mockT, "../_codegen"))\n\n\tlink := getTempSymlinkPath(t, "assertions.go")\n\tmockT = new(testing.T)\n\tFalse(t, DirExists(mockT, link))\n\n\tlink = getTempSymlinkPath(t, "non_existent_dir")\n\tmockT = new(testing.T)\n\tFalse(t, DirExists(mockT, link))\n}\n\nfunc TestNoDirExists(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tTrue(t, NoDirExists(mockT, "assertions.go"))\n\n\tmockT = new(testing.T)\n\tTrue(t, NoDirExists(mockT, "non_existent_dir"))\n\n\tmockT = new(testing.T)\n\tFalse(t, NoDirExists(mockT, "../_codegen"))\n\n\tlink := getTempSymlinkPath(t, "assertions.go")\n\tmockT = new(testing.T)\n\tTrue(t, NoDirExists(mockT, link))\n\n\tlink = getTempSymlinkPath(t, "non_existent_dir")\n\tmockT = new(testing.T)\n\tTrue(t, NoDirExists(mockT, link))\n}\n\nfunc TestJSONEq_EqualSONString(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tTrue(t, JSONEq(mockT, `{"hello": "world", "foo": "bar"}`, `{"hello": "world", "foo": "bar"}`))\n}\n\nfunc TestJSONEq_EquivalentButNotEqual(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tTrue(t, JSONEq(mockT, `{"hello": "world", "foo": "bar"}`, `{"foo": "bar", "hello": "world"}`))\n}\n\nfunc TestJSONEq_HashOfArraysAndHashes(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tTrue(t, JSONEq(mockT, "{\\r\\n\\t\\"numeric\\": 1.5,\\r\\n\\t\\"array\\": [{\\"foo\\": \\"bar\\"}, 1, \\"string\\", [\\"nested\\", \\"array\\", 5.5]],\\r\\n\\t\\"hash\\": {\\"nested\\": \\"hash\\", \\"nested_slice\\": [\\"this\\", \\"is\\", \\"nested\\"]},\\r\\n\\t\\"string\\": \\"foo\\"\\r\\n}",\n\t\t"{\\r\\n\\t\\"numeric\\": 1.5,\\r\\n\\t\\"hash\\": {\\"nested\\": \\"hash\\", \\"nested_slice\\": [\\"this\\", \\"is\\", \\"nested\\"]},\\r\\n\\t\\"string\\": \\"foo\\",\\r\\n\\t\\"array\\": [{\\"foo\\": \\"bar\\"}, 1, \\"string\\", [\\"nested\\", \\"array\\", 5.5]]\\r\\n}"))\n}\n\nfunc TestJSONEq_Array(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tTrue(t, JSONEq(mockT, `["foo", {"hello": "world", "nested": "hash"}]`, `["foo", {"nested": "hash", "hello": "world"}]`))\n}\n\nfunc TestJSONEq_HashAndArrayNotEquivalent(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, JSONEq(mockT, `["foo", {"hello": "world", "nested": "hash"}]`, `{"foo": "bar", {"nested": "hash", "hello": "world"}}`))\n}\n\nfunc TestJSONEq_HashesNotEquivalent(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, JSONEq(mockT, `{"foo": "bar"}`, `{"foo": "bar", "hello": "world"}`))\n}\n\nfunc TestJSONEq_ActualIsNotJSON(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, JSONEq(mockT, `{"foo": "bar"}`, "Not JSON"))\n}\n\nfunc TestJSONEq_ExpectedIsNotJSON(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, JSONEq(mockT, "Not JSON", `{"foo": "bar", "hello": "world"}`))\n}\n\nfunc TestJSONEq_ExpectedAndActualNotJSON(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, JSONEq(mockT, "Not JSON", "Not JSON"))\n}\n\nfunc TestJSONEq_ArraysOfDifferentOrder(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, JSONEq(mockT, `["foo", {"hello": "world", "nested": "hash"}]`, `[{ "hello": "world", "nested": "hash"}, "foo"]`))\n}\n\nfunc TestYAMLEq_EqualYAMLString(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tTrue(t, YAMLEq(mockT, `{"hello": "world", "foo": "bar"}`, `{"hello": "world", "foo": "bar"}`))\n}\n\nfunc TestYAMLEq_EquivalentButNotEqual(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tTrue(t, YAMLEq(mockT, `{"hello": "world", "foo": "bar"}`, `{"foo": "bar", "hello": "world"}`))\n}\n\nfunc TestYAMLEq_HashOfArraysAndHashes(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\texpected := `\nnumeric: 1.5\narray:\n  - foo: bar\n  - 1\n  - "string"\n  - ["nested", "array", 5.5]\nhash:\n  nested: hash\n  nested_slice: [this, is, nested]\nstring: "foo"\n`\n\n\tactual := `\nnumeric: 1.5\nhash:\n  nested: hash\n  nested_slice: [this, is, nested]\nstring: "foo"\narray:\n  - foo: bar\n  - 1\n  - "string"\n  - ["nested", "array", 5.5]\n`\n\tTrue(t, YAMLEq(mockT, expected, actual))\n}\n\nfunc TestYAMLEq_Array(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tTrue(t, YAMLEq(mockT, `["foo", {"hello": "world", "nested": "hash"}]`, `["foo", {"nested": "hash", "hello": "world"}]`))\n}\n\nfunc TestYAMLEq_HashAndArrayNotEquivalent(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, YAMLEq(mockT, `["foo", {"hello": "world", "nested": "hash"}]`, `{"foo": "bar", {"nested": "hash", "hello": "world"}}`))\n}\n\nfunc TestYAMLEq_HashesNotEquivalent(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, YAMLEq(mockT, `{"foo": "bar"}`, `{"foo": "bar", "hello": "world"}`))\n}\n\nfunc TestYAMLEq_ActualIsSimpleString(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, YAMLEq(mockT, `{"foo": "bar"}`, "Simple String"))\n}\n\nfunc TestYAMLEq_ExpectedIsSimpleString(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, YAMLEq(mockT, "Simple String", `{"foo": "bar", "hello": "world"}`))\n}\n\nfunc TestYAMLEq_ExpectedAndActualSimpleString(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tTrue(t, YAMLEq(mockT, "Simple String", "Simple String"))\n}\n\nfunc TestYAMLEq_ArraysOfDifferentOrder(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\tFalse(t, YAMLEq(mockT, `["foo", {"hello": "world", "nested": "hash"}]`, `[{ "hello": "world", "nested": "hash"}, "foo"]`))\n}\n\ntype diffTestingStruct struct {\n\tA string\n\tB int\n}\n\nfunc (d *diffTestingStruct) String() string {\n\treturn d.A\n}\n\nfunc TestDiff(t *testing.T) {\n\tt.Parallel()\n\n\texpected := `\n\nDiff:\n--- Expected\n+++ Actual\n@@ -1,3 +1,3 @@\n (struct { foo string }) {\n- foo: (string) (len=5) "hello"\n+ foo: (string) (len=3) "bar"\n }\n`\n\tactual := diff(\n\t\tstruct{ foo string }{"hello"},\n\t\tstruct{ foo string }{"bar"},\n\t)\n\tEqual(t, expected, actual)\n\n\texpected = `\n\nDiff:\n--- Expected\n+++ Actual\n@@ -2,5 +2,5 @@\n  (int) 1,\n- (int) 2,\n  (int) 3,\n- (int) 4\n+ (int) 5,\n+ (int) 7\n }\n`\n\tactual = diff(\n\t\t[]int{1, 2, 3, 4},\n\t\t[]int{1, 3, 5, 7},\n\t)\n\tEqual(t, expected, actual)\n\n\texpected = `\n\nDiff:\n--- Expected\n+++ Actual\n@@ -2,4 +2,4 @@\n  (int) 1,\n- (int) 2,\n- (int) 3\n+ (int) 3,\n+ (int) 5\n }\n`\n\tactual = diff(\n\t\t[]int{1, 2, 3, 4}[0:3],\n\t\t[]int{1, 3, 5, 7}[0:3],\n\t)\n\tEqual(t, expected, actual)\n\n\texpected = `\n\nDiff:\n--- Expected\n+++ Actual\n@@ -1,6 +1,6 @@\n (map[string]int) (len=4) {\n- (string) (len=4) "four": (int) 4,\n+ (string) (len=4) "five": (int) 5,\n  (string) (len=3) "one": (int) 1,\n- (string) (len=5) "three": (int) 3,\n- (string) (len=3) "two": (int) 2\n+ (string) (len=5) "seven": (int) 7,\n+ (string) (len=5) "three": (int) 3\n }\n`\n\n\tactual = diff(\n\t\tmap[string]int{"one": 1, "two": 2, "three": 3, "four": 4},\n\t\tmap[string]int{"one": 1, "three": 3, "five": 5, "seven": 7},\n\t)\n\tEqual(t, expected, actual)\n\n\texpected = `\n\nDiff:\n--- Expected\n+++ Actual\n@@ -1,3 +1,3 @@\n (*errors.errorString)({\n- s: (string) (len=19) "some expected error"\n+ s: (string) (len=12) "actual error"\n })\n`\n\n\tactual = diff(\n\t\terrors.New("some expected error"),\n\t\terrors.New("actual error"),\n\t)\n\tEqual(t, expected, actual)\n\n\texpected = `\n\nDiff:\n--- Expected\n+++ Actual\n@@ -2,3 +2,3 @@\n  A: (string) (len=11) "some string",\n- B: (int) 10\n+ B: (int) 15\n }\n`\n\n\tactual = diff(\n\t\tdiffTestingStruct{A: "some string", B: 10},\n\t\tdiffTestingStruct{A: "some string", B: 15},\n\t)\n\tEqual(t, expected, actual)\n\n\texpected = `\n\nDiff:\n--- Expected\n+++ Actual\n@@ -1,2 +1,2 @@\n-(time.Time) 2020-09-24 00:00:00 +0000 UTC\n+(time.Time) 2020-09-25 00:00:00 +0000 UTC\n \n`\n\n\tactual = diff(\n\t\ttime.Date(2020, 9, 24, 0, 0, 0, 0, time.UTC),\n\t\ttime.Date(2020, 9, 25, 0, 0, 0, 0, time.UTC),\n\t)\n\tEqual(t, expected, actual)\n}\n\nfunc TestTimeEqualityErrorFormatting(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(mockTestingT)\n\n\tEqual(mockT, time.Second*2, time.Millisecond)\n\n\texpectedErr := "\\\\s+Error Trace:\\\\s+Error:\\\\s+Not equal:\\\\s+\\n\\\\s+expected: 2s\\n\\\\s+actual\\\\s+: 1ms\\n"\n\tRegexp(t, regexp.MustCompile(expectedErr), mockT.errorString())\n}\n\nfunc TestDiffEmptyCases(t *testing.T) {\n\tt.Parallel()\n\n\tEqual(t, "", diff(nil, nil))\n\tEqual(t, "", diff(struct{ foo string }{}, nil))\n\tEqual(t, "", diff(nil, struct{ foo string }{}))\n\tEqual(t, "", diff(1, 2))\n\tEqual(t, "", diff(1, 2))\n\tEqual(t, "", diff([]int{1}, []bool{true}))\n}\n\n// Ensure there are no data races\nfunc TestDiffRace(t *testing.T) {\n\tt.Parallel()\n\n\texpected := map[string]string{\n\t\t"a": "A",\n\t\t"b": "B",\n\t\t"c": "C",\n\t}\n\n\tactual := map[string]string{\n\t\t"d": "D",\n\t\t"e": "E",\n\t\t"f": "F",\n\t}\n\n\t// run diffs in parallel simulating tests with t.Parallel()\n\tnumRoutines := 10\n\trChans := make([]chan string, numRoutines)\n\tfor idx := range rChans {\n\t\trChans[idx] = make(chan string)\n\t\tgo func(ch chan string) {\n\t\t\tdefer close(ch)\n\t\t\tch <- diff(expected, actual)\n\t\t}(rChans[idx])\n\t}\n\n\tfor _, ch := range rChans {\n\t\tfor msg := range ch {\n\t\t\tNotZero(t, msg) // dummy assert\n\t\t}\n\t}\n}\n\ntype mockTestingT struct {\n\terrorFmt string\n\targs     []interface{}\n}\n\n// Helper is like [testing.T.Helper] but does nothing.\nfunc (mockTestingT) Helper() {}\n\nfunc (m *mockTestingT) errorString() string {\n\treturn fmt.Sprintf(m.errorFmt, m.args...)\n}\n\nfunc (m *mockTestingT) Errorf(format string, args ...interface{}) {\n\tm.errorFmt = format\n\tm.args = args\n}\n\nfunc (m *mockTestingT) Failed() bool {\n\treturn m.errorFmt != ""\n}\n\nfunc TestFailNowWithPlainTestingT(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := &mockTestingT{}\n\n\tPanics(t, func() {\n\t\tFailNow(mockT, "failed")\n\t}, "should panic since mockT is missing FailNow()")\n}\n\ntype mockFailNowTestingT struct{}\n\n// Helper is like [testing.T.Helper] but does nothing.\nfunc (mockFailNowTestingT) Helper() {}\n\nfunc (m *mockFailNowTestingT) Errorf(format string, args ...interface{}) {}\n\nfunc (m *mockFailNowTestingT) FailNow() {}\n\nfunc TestFailNowWithFullTestingT(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := &mockFailNowTestingT{}\n\n\tNotPanics(t, func() {\n\t\tFailNow(mockT, "failed")\n\t}, "should call mockT.FailNow() rather than panicking")\n}\n\nfunc TestBytesEqual(t *testing.T) {\n\tt.Parallel()\n\n\tcases := []struct {\n\t\ta, b []byte\n\t}{\n\t\t{make([]byte, 2), make([]byte, 2)},\n\t\t{make([]byte, 2), make([]byte, 2, 3)},\n\t\t{nil, make([]byte, 0)},\n\t}\n\tfor i, c := range cases {\n\t\tEqual(t, reflect.DeepEqual(c.a, c.b), ObjectsAreEqual(c.a, c.b), "case %d failed", i+1)\n\t}\n}\n\nfunc BenchmarkBytesEqual(b *testing.B) {\n\tconst size = 1024 * 8\n\ts := make([]byte, size)\n\tfor i := range s {\n\t\ts[i] = byte(i % 255)\n\t}\n\ts2 := make([]byte, size)\n\tcopy(s2, s)\n\n\tmockT := &mockFailNowTestingT{}\n\tb.ResetTimer()\n\tfor i := 0; i < b.N; i++ {\n\t\tEqual(mockT, s, s2)\n\t}\n}\n\nfunc BenchmarkNotNil(b *testing.B) {\n\tfor i := 0; i < b.N; i++ {\n\t\tNotNil(b, b)\n\t}\n}\n\nfunc ExampleComparisonAssertionFunc() {\n\tt := &testing.T{} // provided by test\n\n\tadder := func(x, y int) int {\n\t\treturn x + y\n\t}\n\n\ttype args struct {\n\t\tx int\n\t\ty int\n\t}\n\n\ttests := []struct {\n\t\tname      string\n\t\targs      args\n\t\texpect    int\n\t\tassertion ComparisonAssertionFunc\n\t}{\n\t\t{"2+2=4", args{2, 2}, 4, Equal},\n\t\t{"2+2!=5", args{2, 2}, 5, NotEqual},\n\t\t{"2+3==5", args{2, 3}, 5, Exactly},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\ttt.assertion(t, tt.expect, adder(tt.args.x, tt.args.y))\n\t\t})\n\t}\n}\n\nfunc TestComparisonAssertionFunc(t *testing.T) {\n\tt.Parallel()\n\n\ttype iface interface {\n\t\tName() string\n\t}\n\n\ttests := []struct {\n\t\tname      string\n\t\texpect    interface{}\n\t\tgot       interface{}\n\t\tassertion ComparisonAssertionFunc\n\t}{\n\t\t{"implements", (*iface)(nil), t, Implements},\n\t\t{"isType", (*testing.T)(nil), t, IsType},\n\t\t{"equal", t, t, Equal},\n\t\t{"equalValues", t, t, EqualValues},\n\t\t{"notEqualValues", t, nil, NotEqualValues},\n\t\t{"exactly", t, t, Exactly},\n\t\t{"notEqual", t, nil, NotEqual},\n\t\t{"notContains", []int{1, 2, 3}, 4, NotContains},\n\t\t{"subset", []int{1, 2, 3, 4}, []int{2, 3}, Subset},\n\t\t{"notSubset", []int{1, 2, 3, 4}, []int{0, 3}, NotSubset},\n\t\t{"elementsMatch", []byte("abc"), []byte("bac"), ElementsMatch},\n\t\t{"regexp", "^t.*y$", "testify", Regexp},\n\t\t{"notRegexp", "^t.*y$", "Testify", NotRegexp},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\ttt.assertion(t, tt.expect, tt.got)\n\t\t})\n\t}\n}\n\nfunc ExampleValueAssertionFunc() {\n\tt := &testing.T{} // provided by test\n\n\tdumbParse := func(input string) interface{} {\n\t\tvar x interface{}\n\t\t_ = json.Unmarshal([]byte(input), &x)\n\t\treturn x\n\t}\n\n\ttests := []struct {\n\t\tname      string\n\t\targ       string\n\t\tassertion ValueAssertionFunc\n\t}{\n\t\t{"true is not nil", "true", NotNil},\n\t\t{"empty string is nil", "", Nil},\n\t\t{"zero is not nil", "0", NotNil},\n\t\t{"zero is zero", "0", Zero},\n\t\t{"false is zero", "false", Zero},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\ttt.assertion(t, dumbParse(tt.arg))\n\t\t})\n\t}\n}\n\nfunc TestValueAssertionFunc(t *testing.T) {\n\tt.Parallel()\n\n\ttests := []struct {\n\t\tname      string\n\t\tvalue     interface{}\n\t\tassertion ValueAssertionFunc\n\t}{\n\t\t{"notNil", true, NotNil},\n\t\t{"nil", nil, Nil},\n\t\t{"empty", []int{}, Empty},\n\t\t{"notEmpty", []int{1}, NotEmpty},\n\t\t{"zero", false, Zero},\n\t\t{"notZero", 42, NotZero},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\ttt.assertion(t, tt.value)\n\t\t})\n\t}\n}\n\nfunc ExampleBoolAssertionFunc() {\n\tt := &testing.T{} // provided by test\n\n\tisOkay := func(x int) bool {\n\t\treturn x >= 42\n\t}\n\n\ttests := []struct {\n\t\tname      string\n\t\targ       int\n\t\tassertion BoolAssertionFunc\n\t}{\n\t\t{"-1 is bad", -1, False},\n\t\t{"42 is good", 42, True},\n\t\t{"41 is bad", 41, False},\n\t\t{"45 is cool", 45, True},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\ttt.assertion(t, isOkay(tt.arg))\n\t\t})\n\t}\n}\n\nfunc TestBoolAssertionFunc(t *testing.T) {\n\tt.Parallel()\n\n\ttests := []struct {\n\t\tname      string\n\t\tvalue     bool\n\t\tassertion BoolAssertionFunc\n\t}{\n\t\t{"true", true, True},\n\t\t{"false", false, False},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\ttt.assertion(t, tt.value)\n\t\t})\n\t}\n}\n\nfunc ExampleErrorAssertionFunc() {\n\tt := &testing.T{} // provided by test\n\n\tdumbParseNum := func(input string, v interface{}) error {\n\t\treturn json.Unmarshal([]byte(input), v)\n\t}\n\n\ttests := []struct {\n\t\tname      string\n\t\targ       string\n\t\tassertion ErrorAssertionFunc\n\t}{\n\t\t{"1.2 is number", "1.2", NoError},\n\t\t{"1.2.3 not number", "1.2.3", Error},\n\t\t{"true is not number", "true", Error},\n\t\t{"3 is number", "3", NoError},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\tvar x float64\n\t\t\ttt.assertion(t, dumbParseNum(tt.arg, &x))\n\t\t})\n\t}\n}\n\nfunc TestErrorAssertionFunc(t *testing.T) {\n\tt.Parallel()\n\n\ttests := []struct {\n\t\tname      string\n\t\terr       error\n\t\tassertion ErrorAssertionFunc\n\t}{\n\t\t{"noError", nil, NoError},\n\t\t{"error", errors.New("whoops"), Error},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\ttt.assertion(t, tt.err)\n\t\t})\n\t}\n}\n\nfunc ExamplePanicAssertionFunc() {\n\tt := &testing.T{} // provided by test\n\n\ttests := []struct {\n\t\tname      string\n\t\tpanicFn   PanicTestFunc\n\t\tassertion PanicAssertionFunc\n\t}{\n\t\t{"with panic", func() { panic(nil) }, Panics},\n\t\t{"without panic", func() {}, NotPanics},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\ttt.assertion(t, tt.panicFn)\n\t\t})\n\t}\n}\n\nfunc TestPanicAssertionFunc(t *testing.T) {\n\tt.Parallel()\n\n\ttests := []struct {\n\t\tname      string\n\t\tpanicFn   PanicTestFunc\n\t\tassertion PanicAssertionFunc\n\t}{\n\t\t{"not panic", func() {}, NotPanics},\n\t\t{"panic", func() { panic(nil) }, Panics},\n\t}\n\n\tfor _, tt := range tests {\n\t\tt.Run(tt.name, func(t *testing.T) {\n\t\t\ttt.assertion(t, tt.panicFn)\n\t\t})\n\t}\n}\n\nfunc TestEventuallyFalse(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tcondition := func() bool {\n\t\treturn false\n\t}\n\n\tFalse(t, Eventually(mockT, condition, 100*time.Millisecond, 20*time.Millisecond))\n}\n\nfunc TestEventuallyTrue(t *testing.T) {\n\tt.Parallel()\n\n\tstate := 0\n\tcondition := func() bool {\n\t\tdefer func() {\n\t\t\tstate += 1\n\t\t}()\n\t\treturn state == 2\n\t}\n\n\tTrue(t, Eventually(t, condition, 100*time.Millisecond, 20*time.Millisecond))\n}\n\n// errorsCapturingT is a mock implementation of TestingT that captures errors reported with Errorf.\ntype errorsCapturingT struct {\n\terrors []error\n}\n\n// Helper is like [testing.T.Helper] but does nothing.\nfunc (errorsCapturingT) Helper() {}\n\nfunc (t *errorsCapturingT) Errorf(format string, args ...interface{}) {\n\tt.errors = append(t.errors, fmt.Errorf(format, args...))\n}\n\nfunc TestEventuallyWithTFalse(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(errorsCapturingT)\n\n\tcondition := func(collect *CollectT) {\n\t\tFail(collect, "condition fixed failure")\n\t}\n\n\tFalse(t, EventuallyWithT(mockT, condition, 100*time.Millisecond, 20*time.Millisecond))\n\tLen(t, mockT.errors, 2)\n}\n\nfunc TestEventuallyWithTTrue(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(errorsCapturingT)\n\n\tcounter := 0\n\tcondition := func(collect *CollectT) {\n\t\tcounter += 1\n\t\tTrue(collect, counter == 2)\n\t}\n\n\tTrue(t, EventuallyWithT(mockT, condition, 100*time.Millisecond, 20*time.Millisecond))\n\tLen(t, mockT.errors, 0)\n\tEqual(t, 2, counter, "Condition is expected to be called 2 times")\n}\n\nfunc TestEventuallyWithT_ConcurrencySafe(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(errorsCapturingT)\n\n\tcondition := func(collect *CollectT) {\n\t\tFail(collect, "condition fixed failure")\n\t}\n\n\t// To trigger race conditions, we run EventuallyWithT with a nanosecond tick.\n\tFalse(t, EventuallyWithT(mockT, condition, 100*time.Millisecond, time.Nanosecond))\n\tLen(t, mockT.errors, 2)\n}\n\nfunc TestEventuallyWithT_ReturnsTheLatestFinishedConditionErrors(t *testing.T) {\n\tt.Parallel()\n\n\t// We\'ll use a channel to control whether a condition should sleep or not.\n\tmustSleep := make(chan bool, 2)\n\tmustSleep <- false\n\tmustSleep <- true\n\tclose(mustSleep)\n\n\tcondition := func(collect *CollectT) {\n\t\tif <-mustSleep {\n\t\t\t// Sleep to ensure that the second condition runs longer than timeout.\n\t\t\ttime.Sleep(time.Second)\n\t\t\treturn\n\t\t}\n\n\t\t// The first condition will fail. We expect to get this error as a result.\n\t\tFail(collect, "condition fixed failure")\n\t}\n\n\tmockT := new(errorsCapturingT)\n\tFalse(t, EventuallyWithT(mockT, condition, 100*time.Millisecond, 20*time.Millisecond))\n\tLen(t, mockT.errors, 2)\n}\n\nfunc TestEventuallyWithTFailNow(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(CollectT)\n\n\tcondition := func(collect *CollectT) {\n\t\tcollect.FailNow()\n\t}\n\n\tFalse(t, EventuallyWithT(mockT, condition, 100*time.Millisecond, 20*time.Millisecond))\n\tLen(t, mockT.errors, 1)\n}\n\n// Check that a long running condition doesn\'t block Eventually.\n// See issue 805 (and its long tail of following issues)\nfunc TestEventuallyTimeout(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tNotPanics(t, func() {\n\t\tdone, done2 := make(chan struct{}), make(chan struct{})\n\n\t\t// A condition function that returns after the Eventually timeout\n\t\tcondition := func() bool {\n\t\t\t// Wait until Eventually times out and terminates\n\t\t\t<-done\n\t\t\tclose(done2)\n\t\t\treturn true\n\t\t}\n\n\t\tFalse(t, Eventually(mockT, condition, time.Millisecond, time.Microsecond))\n\n\t\tclose(done)\n\t\t<-done2\n\t})\n}\n\nfunc TestEventuallySucceedQuickly(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tcondition := func() bool { return true }\n\n\t// By making the tick longer than the total duration, we expect that this test would fail if\n\t// we didn\'t check the condition before the first tick elapses.\n\tTrue(t, Eventually(mockT, condition, 100*time.Millisecond, time.Second))\n}\n\nfunc TestEventuallyWithTSucceedQuickly(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\tcondition := func(t *CollectT) {}\n\n\t// By making the tick longer than the total duration, we expect that this test would fail if\n\t// we didn\'t check the condition before the first tick elapses.\n\tTrue(t, EventuallyWithT(mockT, condition, 100*time.Millisecond, time.Second))\n}\n\nfunc TestNeverFalse(t *testing.T) {\n\tt.Parallel()\n\n\tcondition := func() bool {\n\t\treturn false\n\t}\n\n\tTrue(t, Never(t, condition, 100*time.Millisecond, 20*time.Millisecond))\n}\n\n// TestNeverTrue checks Never with a condition that returns true on second call.\nfunc TestNeverTrue(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\t// A list of values returned by condition.\n\t// Channel protects against concurrent access.\n\treturns := make(chan bool, 2)\n\treturns <- false\n\treturns <- true\n\tdefer close(returns)\n\n\t// Will return true on second call.\n\tcondition := func() bool {\n\t\treturn <-returns\n\t}\n\n\tFalse(t, Never(mockT, condition, 100*time.Millisecond, 20*time.Millisecond))\n}\n\nfunc TestNeverFailQuickly(t *testing.T) {\n\tt.Parallel()\n\n\tmockT := new(testing.T)\n\n\t// By making the tick longer than the total duration, we expect that this test would fail if\n\t// we didn\'t check the condition before the first tick elapses.\n\tcondition := func() bool { return true }\n\tFalse(t, Never(mockT, condition, 100*time.Millisecond, time.Second))\n}\n\nfunc Test_validateEqualArgs(t *testing.T) {\n\tt.Parallel()\n\n\tif validateEqualArgs(func() {}, func() {}) == nil {\n\t\tt.Error("non-nil functions should error")\n\t}\n\n\tif validateEqualArgs(func() {}, func() {}) == nil {\n\t\tt.Error("non-nil functions should error")\n\t}\n\n\tif validateEqualArgs(nil, nil) != nil {\n\t\tt.Error("nil functions are equal")\n\t}\n}\n\nfunc Test_truncatingFormat(t *testing.T) {\n\tt.Parallel()\n\n\toriginal := strings.Repeat("a", bufio.MaxScanTokenSize-102)\n\tresult := truncatingFormat(original)\n\tEqual(t, fmt.Sprintf("%#v", original), result, "string should not be truncated")\n\n\toriginal = original + "x"\n\tresult = truncatingFormat(original)\n\tNotEqual(t, fmt.Sprintf("%#v", original), result, "string should have been truncated.")\n\n\tif !strings.HasSuffix(result, "<... truncated>") {\n\t\tt.Error("truncated string should have <... truncated> suffix")\n\t}\n}\n\n// parseLabeledOutput does the inverse of labeledOutput - it takes a formatted\n// output string and turns it back into a slice of labeledContent.\nfunc parseLabeledOutput(output string) []labeledContent {\n\tlabelPattern := regexp.MustCompile(`^\\t([^\\t]*): *\\t(.*)$`)\n\tcontentPattern := regexp.MustCompile(`^\\t *\\t(.*)$`)\n\tvar contents []labeledContent\n\tlines := strings.Split(output, "\\n")\n\ti := -1\n\tfor _, line := range lines {\n\t\tif line == "" {\n\t\t\t// skip blank lines\n\t\t\tcontinue\n\t\t}\n\t\tmatches := labelPattern.FindStringSubmatch(line)\n\t\tif len(matches) == 3 {\n\t\t\t// a label\n\t\t\tcontents = append(contents, labeledContent{\n\t\t\t\tlabel:   matches[1],\n\t\t\t\tcontent: matches[2] + "\\n",\n\t\t\t})\n\t\t\ti++\n\t\t\tcontinue\n\t\t}\n\t\tmatches = contentPattern.FindStringSubmatch(line)\n\t\tif len(matches) == 2 {\n\t\t\t// just content\n\t\t\tif i >= 0 {\n\t\t\t\tcontents[i].content += matches[1] + "\\n"\n\t\t\t\tcontinue\n\t\t\t}\n\t\t}\n\t\t// Couldn\'t parse output\n\t\treturn nil\n\t}\n\treturn contents\n}\n\ntype captureTestingT struct {\n\tfailed bool\n\tmsg    string\n}\n\n// Helper is like [testing.T.Helper] but does nothing.\nfunc (captureTestingT) Helper() {}\n\nfunc (ctt *captureTestingT) Errorf(format string, args ...interface{}) {\n\tctt.msg = fmt.Sprintf(format, args...)\n\tctt.failed = true\n}\n\nfunc (ctt *captureTestingT) checkResultAndErrMsg(t *testing.T, expectedRes, res bool, expectedErrMsg string) {\n\tt.Helper()\n\tif res != expectedRes {\n\t\tt.Errorf("Should return %t", expectedRes)\n\t\treturn\n\t}\n\tif res == ctt.failed {\n\t\tt.Errorf("The test result (%t) should be reflected in the testing.T type (%t)", res, !ctt.failed)\n\t\treturn\n\t}\n\tcontents := parseLabeledOutput(ctt.msg)\n\tif res == true {\n\t\tif contents != nil {\n\t\t\tt.Errorf("Should not log an error. Log output: %q", ctt.msg)\n\t\t}\n\t\treturn\n\t}\n\tif contents == nil {\n\t\tt.Errorf("Should log an error. Log output: %q", ctt.msg)\n\t\treturn\n\t}\n\tfor _, content := range contents {\n\t\tif content.label == "Error" {\n\t\t\tif expectedErrMsg == content.content {\n\t\t\t\treturn\n\t\t\t}\n\t\t\tt.Errorf("Recorded Error: %q", content.content)\n\t\t}\n\t}\n\tt.Errorf("Expected Error: %q", expectedErrMsg)\n}\n\nfunc TestErrorIs(t *testing.T) {\n\tt.Parallel()\n\n\ttests := []struct {\n\t\terr          error\n\t\ttarget       error\n\t\tresult       bool\n\t\tresultErrMsg string\n\t}{\n\t\t{\n\t\t\terr:    io.EOF,\n\t\t\ttarget: io.EOF,\n\t\t\tresult: true,\n\t\t},\n\t\t{\n\t\t\terr:    fmt.Errorf("wrap: %w", io.EOF),\n\t\t\ttarget: io.EOF,\n\t\t\tresult: true,\n\t\t},\n\t\t{\n\t\t\terr:    io.EOF,\n\t\t\ttarget: io.ErrClosedPipe,\n\t\t\tresult: false,\n\t\t\tresultErrMsg: "" +\n\t\t\t\t"Target error should be in err chain:\\n" +\n\t\t\t\t"expected: \\"io: read/write on closed pipe\\"\\n" +\n\t\t\t\t"in chain: \\"EOF\\"\\n",\n\t\t},\n\t\t{\n\t\t\terr:          nil,\n\t\t\ttarget:       io.EOF,\n\t\t\tresult:       false,\n\t\t\tresultErrMsg: "Expected error with \\"EOF\\" in chain but got nil.\\n",\n\t\t},\n\t\t{\n\t\t\terr:    io.EOF,\n\t\t\ttarget: nil,\n\t\t\tresult: false,\n\t\t\tresultErrMsg: "" +\n\t\t\t\t"Target error should be in err chain:\\n" +\n\t\t\t\t"expected: \\"\\"\\n" +\n\t\t\t\t"in chain: \\"EOF\\"\\n",\n\t\t},\n\t\t{\n\t\t\terr:    nil,\n\t\t\ttarget: nil,\n\t\t\tresult: true,\n\t\t},\n\t\t{\n\t\t\terr:    fmt.Errorf("abc: %w", errors.New("def")),\n\t\t\ttarget: io.EOF,\n\t\t\tresult: false,\n\t\t\tresultErrMsg: "" +\n\t\t\t\t"Target error should be in err chain:\\n" +\n\t\t\t\t"expected: \\"EOF\\"\\n" +\n\t\t\t\t"in chain: \\"abc: def\\"\\n" +\n\t\t\t\t"\\t\\"def\\"\\n",\n\t\t},\n\t}\n\tfor _, tt := range tests {\n\t\ttt := tt\n\t\tt.Run(fmt.Sprintf("ErrorIs(%#v,%#v)", tt.err, tt.target), func(t *testing.T) {\n\t\t\tmockT := new(captureTestingT)\n\t\t\tres := ErrorIs(mockT, tt.err, tt.target)\n\t\t\tmockT.checkResultAndErrMsg(t, tt.result, res, tt.resultErrMsg)\n\t\t})\n\t}\n}\n\nfunc TestNotErrorIs(t *testing.T) {\n\tt.Parallel()\n\n\ttests := []struct {\n\t\terr          error\n\t\ttarget       error\n\t\tresult       bool\n\t\tresultErrMsg string\n\t}{\n\t\t{\n\t\t\terr:    io.EOF,\n\t\t\ttarget: io.EOF,\n\t\t\tresult: false,\n\t\t\tresultErrMsg: "" +\n\t\t\t\t"Target error should not be in err chain:\\n" +\n\t\t\t\t"found: \\"EOF\\"\\n" +\n\t\t\t\t"in chain: \\"EOF\\"\\n",\n\t\t},\n\t\t{\n\t\t\terr:    fmt.Errorf("wrap: %w", io.EOF),\n\t\t\ttarget: io.EOF,\n\t\t\tresult: false,\n\t\t\tresultErrMsg: "" +\n\t\t\t\t"Target error should not be in err chain:\\n" +\n\t\t\t\t"found: \\"EOF\\"\\n" +\n\t\t\t\t"in chain: \\"wrap: EOF\\"\\n" +\n\t\t\t\t"\\t\\"EOF\\"\\n",\n\t\t},\n\t\t{\n\t\t\terr:    io.EOF,\n\t\t\ttarget: io.ErrClosedPipe,\n\t\t\tresult: true,\n\t\t},\n\t\t{\n\t\t\terr:    nil,\n\t\t\ttarget: io.EOF,\n\t\t\tresult: true,\n\t\t},\n\t\t{\n\t\t\terr:    io.EOF,\n\t\t\ttarget: nil,\n\t\t\tresult: true,\n\t\t},\n\t\t{\n\t\t\terr:    nil,\n\t\t\ttarget: nil,\n\t\t\tresult: false,\n\t\t\tresultErrMsg: "" +\n\t\t\t\t"Target error should not be in err chain:\\n" +\n\t\t\t\t"found: \\"\\"\\n" +\n\t\t\t\t"in chain: \\n",\n\t\t},\n\t\t{\n\t\t\terr:    fmt.Errorf("abc: %w", errors.New("def")),\n\t\t\ttarget: io.EOF,\n\t\t\tresult: true,\n\t\t},\n\t}\n\tfor _, tt := range tests {\n\t\ttt := tt\n\t\tt.Run(fmt.Sprintf("NotErrorIs(%#v,%#v)", tt.err, tt.target), func(t *testing.T) {\n\t\t\tmockT := new(captureTestingT)\n\t\t\tres := NotErrorIs(mockT, tt.err, tt.target)\n\t\t\tmockT.checkResultAndErrMsg(t, tt.result, res, tt.resultErrMsg)\n\t\t})\n\t}\n}\n\nfunc TestErrorAs(t *testing.T) {\n\tt.Parallel()\n\n\ttests := []struct {\n\t\terr          error\n\t\tresult       bool\n\t\tresultErrMsg string\n\t}{\n\t\t{\n\t\t\terr:    fmt.Errorf("wrap: %w", &customError{}),\n\t\t\tresult: true,\n\t\t},\n\t\t{\n\t\t\terr:    io.EOF,\n\t\t\tresult: false,\n\t\t\tresultErrMsg: "" +\n\t\t\t\t"Should be in error chain:\\n" +\n\t\t\t\t"expected: *assert.customError\\n" +\n\t\t\t\t"in chain: \\"EOF\\" (*errors.errorString)\\n",\n\t\t},\n\t\t{\n\t\t\terr:    nil,\n\t\t\tresult: false,\n\t\t\tresultErrMsg: "" +\n\t\t\t\t"An error is expected but got nil.\\n" +\n\t\t\t\t`expected: *assert.customError` + "\\n",\n\t\t},\n\t\t{\n\t\t\terr:    fmt.Errorf("abc: %w", errors.New("def")),\n\t\t\tresult: false,\n\t\t\tresultErrMsg: "" +\n\t\t\t\t"Should be in error chain:\\n" +\n\t\t\t\t"expected: *assert.customError\\n" +\n\t\t\t\t"in chain: \\"abc: def\\" (*fmt.wrapError)\\n" +\n\t\t\t\t"\\t\\"def\\" (*errors.errorString)\\n",\n\t\t},\n\t}\n\tfor _, tt := range tests {\n\t\ttt := tt\n\t\tvar target *customError\n\t\tt.Run(fmt.Sprintf("ErrorAs(%#v,%#v)", tt.err, target), func(t *testing.T) {\n\t\t\tmockT := new(captureTestingT)\n\t\t\tres := ErrorAs(mockT, tt.err, &target)\n\t\t\tmockT.checkResultAndErrMsg(t, tt.result, res, tt.resultErrMsg)\n\t\t})\n\t}\n}\n\nfunc TestNotErrorAs(t *testing.T) {\n\tt.Parallel()\n\n\ttests := []struct {\n\t\terr          error\n\t\tresult       bool\n\t\tresultErrMsg string\n\t}{\n\t\t{\n\t\t\terr:    fmt.Errorf("wrap: %w", &customError{}),\n\t\t\tresult: false,\n\t\t\tresultErrMsg: "" +\n\t\t\t\t"Target error should not be in err chain:\\n" +\n\t\t\t\t"found: *assert.customError\\n" +\n\t\t\t\t"in chain: \\"wrap: fail\\" (*fmt.wrapError)\\n" +\n\t\t\t\t"\\t\\"fail\\" (*assert.customError)\\n",\n\t\t},\n\t\t{\n\t\t\terr:    io.EOF,\n\t\t\tresult: true,\n\t\t},\n\t\t{\n\t\t\terr:    nil,\n\t\t\tresult: true,\n\t\t},\n\t}\n\tfor _, tt := range tests {\n\t\ttt := tt\n\t\tvar target *customError\n\t\tt.Run(fmt.Sprintf("NotErrorAs(%#v,%#v)", tt.err, target), func(t *testing.T) {\n\t\t\tmockT := new(captureTestingT)\n\t\t\tres := NotErrorAs(mockT, tt.err, &target)\n\t\t\tmockT.checkResultAndErrMsg(t, tt.result, res, tt.resultErrMsg)\n\t\t})\n\t}\n}\n',
        }
